          const visible = el => !!el && !el.disabled && el.type !== 'hidden' && (el.offsetParent !== null || getComputedStyle(el).position === 'fixed');
          const passwordInputs = Array.from(document.querySelectorAll('input[type="password"]')).filter(visible);
