          const form = pwd.form || document;
          const fields = Array.from(form.querySelectorAll('input')).filter(visible);
          const user = fields.find(i => /email|user|login|identifier|account|name/i.test(i.name || i.id || i.placeholder || '') && (i.value || '').trim())
