    setStorageKey(store, key) { const cfg = this.getStorageConfig(); cfg[store] = key; localStorage.setItem('ex_storage_cfg', JSON.stringify(cfg)); showToast('💾 Storage key for "' + store + '" set to "' + key + '"'); }
