function parseStoredSettingValue(value) {
    if (typeof value !== 'string') return value;
    const trimmed = value.trim();
    if (!trimmed) return '';
    if (trimmed === 'true') return true;
    if (trimmed === 'false') return false;
    if (trimmed === 'null') return null;
    if (/^-?\d+(?:\.\d+)?$/.test(trimmed)) {
        const numeric = Number(trimmed);
        if (Number.isFinite(numeric)) return numeric;
    }
    if ((trimmed.startsWith('{') && trimmed.endsWith('}')) || (trimmed.startsWith('[') && trimmed.endsWith(']'))) {
        try { return JSON.parse(trimmed); } catch (_) { }
    }
    return value;
}

let _settingsHydratedFromSqlite = false;
async function hydrateSettingsFromSqlite() {
    if (_settingsHydratedFromSqlite) return;
    _settingsHydratedFromSqlite = true;
    if (!window.etherx?.settings?.get) return;
    try {
        const legacyLocal = getPublicSettingsSnapshot();
        const { publicSettings: legacyPublic, secretSettings: legacySecrets } = splitSensitiveSettingsObject(legacyLocal);
        if (Object.keys(legacySecrets).length) {
            SECURE_SETTINGS_CACHE = { ...SECURE_SETTINGS_CACHE, ...legacySecrets };
            writePublicSettingsSnapshot(legacyPublic);
            await persistSensitiveSettings({ ...legacyPublic, ...legacySecrets });
        }

        const sqliteRaw = await window.etherx.settings.get();
        if (!sqliteRaw || typeof sqliteRaw !== 'object') return;

        const sqliteParsed = {};
        Object.entries(sqliteRaw).forEach(([key, value]) => {
            sqliteParsed[key] = parseStoredSettingValue(value);
        });

        const local = DB.getSettings() || {};
        // Keep current in-memory/local values if present, fill missing from SQLite backup.
        const merged = { ...sqliteParsed, ...local };
        const { publicSettings, secretSettings } = splitSensitiveSettingsObject(merged);
        SECURE_SETTINGS_CACHE = { ...secretSettings };
        writePublicSettingsSnapshot(publicSettings);
        PENDING_SETTINGS = { ...merged };

        if (typeof _refreshSettingsToggles === 'function') _refreshSettingsToggles();
        if (typeof window.syncTkaiModelSelectorsFromGlobal === 'function') {
            try { window.syncTkaiModelSelectorsFromGlobal(); } catch (_) { }
        }
    } catch (err) {
        console.warn('Settings hydration from SQLite failed:', err);
    }
}

// ── Sync all localStorage data to Electron SQLite backend ──────────────
function syncLocalToSqlite() {
    if (!window.etherx) { showToast('⚠️ SQLite sync not available (no Electron backend)'); return; }
    let count = 0;
    try {
        if (window.etherx.settings?.save) { window.etherx.settings.save(DB.getSettings()).catch(() => { }); count++; }
        if (window.etherx.userProfile?.save) { window.etherx.userProfile.save(DB.getUser()).catch(() => { }); count++; }
        if (window.etherx.bookmarks?.sync) { window.etherx.bookmarks.sync(DB.getBookmarks()).catch(() => { }); count++; }
        if (window.etherx.history?.sync) { window.etherx.history.sync(DB.getHistory()).catch(() => { }); count++; }
        if (window.etherx.sessions?.sync) { window.etherx.sessions.sync(DB.getSessions()).catch(() => { }); count++; }
        if (window.etherx.notes?.sync) { window.etherx.notes.sync(DB.getNotes()).catch(() => { }); count++; }
        if (window.etherx.downloads?.sync) { window.etherx.downloads.sync(DB.getDownloads()).catch(() => { }); count++; }
        showToast('🔄 Synced ' + count + ' tables to SQLite');
    } catch (e) {
        showToast('❌ Sync error: ' + e.message);
    }
}

// ── Settings panel: init toggles from saved settings ──
let PENDING_SETTINGS = {};

// Normalise a stored setting value to the canonical option value used in <select> elements.
// Handles old translated text stored before value="" attributes were added to <option> elements.
function normalizeSelectSettingValue(key, rawValue) {
    const v = String(rawValue || '').trim().toLowerCase();
    if (!v) return rawValue;
    if (key === 'opensWith') {
        if (v === 'last-session' || v === 'all windows from last session' || v === 'svim prozorima iz zadnje sesije' || v === 'svi prozori iz zadnje sesije') return 'last-session';
        if (v === 'new-window' || v === 'a new window' || v === 'novim prozorom' || v === 'novi prozor') return 'new-window';
        if (v === 'new-private-window' || v === 'a new private window' || v === 'novim privatnim prozorom' || v === 'novi privatni prozor') return 'new-private-window';
    }
    if (key === 'newWindowWith' || key === 'newTabWith') {
        if (v === 'start-page' || v === 'start page' || v === 'početnom stranicom' || v === 'početna stranica (etherx)') return 'start-page';
        if (v === 'homepage' || v === 'početnom stranicom (adresa)' || v === 'početna stranica') return 'homepage';
        if (v === 'empty-page' || v === 'empty page' || v === 'praznom stranicom' || v === 'prazna stranica') return 'empty-page';
        if (v === 'same-page' || v === 'same page' || v === 'istom stranicom') return 'same-page';
    }
    return rawValue;
}

// Osvježi vizualno stanje svih togglea iz baze (poziva se pri svakom otvaranju panela)
function _refreshSettingsToggles() {
    const s = DB.getSettings();
    PENDING_SETTINGS = { ...s };
    document.querySelectorAll('[data-setting]').forEach(el => {
        const k = el.dataset.setting;
        if (el.classList.contains('toggle')) {
            if (el.dataset.icon || el.dataset.titlebar) return;
            const saved = s[k];
            if (saved === true) el.classList.add('on');
            else if (saved === false) el.classList.remove('on');
        } else if (el.tagName === 'SELECT') {
            if (s[k] !== undefined) el.value = normalizeSelectSettingValue(k, s[k]);
        } else if (el.tagName === 'INPUT') {
            if (el.type === 'checkbox') {
                if (s[k] !== undefined) el.checked = s[k];
            } else {
                if (s[k] !== undefined) el.value = s[k];
            }
        }
    });
}

function initSettingsPanel() {
    const s = DB.getSettings();
    PENDING_SETTINGS = { ...s };
    document.querySelectorAll('[data-setting]').forEach(el => {
        const k = el.dataset.setting;
        if (el.classList.contains('toggle')) {
            // Skip Appearance toggles that already have dedicated handlers
            // (initIconVisibility & initTitleBarVisibility manage data-icon / data-titlebar)
            if (el.dataset.icon || el.dataset.titlebar) return;
            const saved = PENDING_SETTINGS[k];
            if (saved === false) el.classList.remove('on');
            else if (saved === true) el.classList.add('on');
            el.addEventListener('click', () => {
                // togglePageDarkMode ima poseban handler koji poziva applyPageDarkMode
                // On sam radi add/remove 'on' i DB.saveSetting — ne radimo duplo ovdje
                if (el.id === 'togglePageDarkMode') return;
                el.classList.toggle('on');
                const isOn = el.classList.contains('on');
                PENDING_SETTINGS[k] = isOn;
                DB.saveSetting(k, isOn); // auto-save immediately
                showSettingsAutoSaveIndicator();
            });
        } else if (el.tagName === 'SELECT') {
            if (PENDING_SETTINGS[k] !== undefined) {
                const norm = normalizeSelectSettingValue(k, PENDING_SETTINGS[k]);
                el.value = norm;
                // If the normalized value was different from raw, persist the canonical value
                if (norm !== PENDING_SETTINGS[k]) {
                    PENDING_SETTINGS[k] = norm;
                    DB.saveSetting(k, norm);
                }
            }
            el.addEventListener('change', () => {
                PENDING_SETTINGS[k] = el.value;
                DB.saveSetting(k, el.value); // auto-save immediately
                showSettingsAutoSaveIndicator();
            });
        } else if (el.tagName === 'INPUT') {
            if (el.type === 'checkbox') {
                if (PENDING_SETTINGS[k] !== undefined) el.checked = PENDING_SETTINGS[k];
                el.addEventListener('change', () => {
                    PENDING_SETTINGS[k] = el.checked;
                    DB.saveSetting(k, el.checked); // auto-save immediately
                    showSettingsAutoSaveIndicator();
                });
            } else {
                if (PENDING_SETTINGS[k] !== undefined) el.value = PENDING_SETTINGS[k];
                el.addEventListener('input', () => {
                    PENDING_SETTINGS[k] = el.value;
                    DB.saveSetting(k, el.value); // auto-save immediately
                    showSettingsAutoSaveIndicator();
                });
            }
        }
    });
}

function showSettingsAutoSaveIndicator() {
    const btn = document.getElementById('btnSaveSettings');
    if (!btn) return;
    btn.textContent = '✓ Saved';
    btn.style.background = 'rgba(39,174,96,.25)';
    btn.style.borderColor = 'rgba(39,174,96,.5)';
    clearTimeout(btn._saveTimer);
    btn._saveTimer = setTimeout(() => {
        btn.textContent = 'Done';
        btn.style.background = '';
        btn.style.borderColor = '';
    }, 1500);
}

document.getElementById('btnSaveSettings')?.addEventListener('click', () => {
    Object.keys(PENDING_SETTINGS).forEach(k => DB.saveSetting(k, PENDING_SETTINGS[k]));
    showToast('✓ Settings saved');
    document.getElementById('settingsPanel').classList.remove('open');
});

initSettingsPanel();
setTimeout(() => { hydrateSettingsFromSqlite().catch(() => { }); }, 0);

