// Fullscreen: sakrij title-bar i menu-bar, prikaži na hover gore
(function initFullscreenBars() {
    const titleBar = document.querySelector('.title-bar');
    const menuBar = document.getElementById('menuBar');
    const tabBar = document.querySelector('.tab-bar');
    let _fsHoverTimer = null;
    // Hover zona na vrhu ekrana koja prikazuje barove u fullscreenu
    const hoverZone = document.createElement('div');
    hoverZone.id = 'fsHoverZone';
    hoverZone.style.cssText = 'position:fixed;top:0;left:0;right:0;height:6px;z-index:99998;display:none';
    document.body.appendChild(hoverZone);

    function showBarsFS() {
        clearTimeout(_fsHoverTimer);
        if (!document.fullscreenElement) return;
        if (titleBar) { titleBar.style.transition = 'transform .2s'; titleBar.style.transform = 'translateY(0)'; }
        if (menuBar && menuBar.style.display !== 'none') { menuBar.style.transition = 'transform .2s'; menuBar.style.transform = 'translateY(0)'; }
        if (tabBar) { tabBar.style.transition = 'transform .2s'; tabBar.style.transform = 'translateY(0)'; }
        _fsHoverTimer = setTimeout(hideBarsFS, 2500);
    }
    function hideBarsFS() {
        if (!document.fullscreenElement) return;
        const titleH = titleBar ? titleBar.offsetHeight : 0;
        const menuH = (menuBar && menuBar.style.display !== 'none') ? menuBar.offsetHeight : 0;
        const tabH = tabBar ? tabBar.offsetHeight : 0;
        if (titleBar) titleBar.style.transform = 'translateY(-' + titleH + 'px)';
        if (menuBar && menuBar.style.display !== 'none') menuBar.style.transform = 'translateY(-' + (titleH + menuH) + 'px)';
        if (tabBar) tabBar.style.transform = 'translateY(-' + (titleH + menuH + tabH) + 'px)';
    }
    hoverZone.addEventListener('mouseenter', showBarsFS);
    hoverZone.addEventListener('mousemove', showBarsFS);

    document.addEventListener('fullscreenchange', () => {
        if (document.fullscreenElement) {
            // Ušli u fullscreen — sakrij barove i prikaži hover zonu
            hoverZone.style.display = 'block';
            if (titleBar) { titleBar.style.overflow = 'visible'; titleBar.style.position = 'fixed'; titleBar.style.top = '0'; titleBar.style.left = '0'; titleBar.style.right = '0'; titleBar.style.zIndex = '99999'; }
            if (menuBar) { menuBar.style.position = 'fixed'; menuBar.style.top = (titleBar ? titleBar.offsetHeight : 0) + 'px'; menuBar.style.left = '0'; menuBar.style.right = '0'; menuBar.style.zIndex = '99998'; }
            if (tabBar) { tabBar.style.position = 'fixed'; tabBar.style.top = ((titleBar ? titleBar.offsetHeight : 0) + (menuBar && menuBar.style.display !== 'none' ? menuBar.offsetHeight : 0)) + 'px'; tabBar.style.left = '0'; tabBar.style.right = '0'; tabBar.style.zIndex = '99997'; }
            setTimeout(hideBarsFS, 1500);
            showToast('⛶ Full Screen — pomakni miš gore za menije | F11 za izlaz');
        } else {
            // Izašli iz fullscreen — vrati sve u normalu
            hoverZone.style.display = 'none';
            clearTimeout(_fsHoverTimer);
            [titleBar, menuBar, tabBar].forEach(el => {
                if (!el) return;
                el.style.position = ''; el.style.top = ''; el.style.left = ''; el.style.right = '';
                el.style.zIndex = ''; el.style.transform = ''; el.style.transition = '';
            });
            showToast('⊡ Exited Full Screen');
        }
    });
})();
