// ── AI Page Summarizer (multi-provider) ────────────────────────────────
const GEMINI_DEFAULT_MODEL = 'gemini-2.5-flash';
const LOCAL_AI_DEFAULT_BASE_URL = 'http://127.0.0.1:11434/v1';
const OLLAMA_REMOTE_DEFAULT_BASE_URL = 'https://your-ollama-server.example.com/v1';
function getSelectedAiModel() {
    const sel = document.getElementById('settingsAiModel');
    if (sel && sel.value) return sel.value;
    const saved = DB.getSettings().aiModel;
    return saved || GEMINI_DEFAULT_MODEL;
}
function inferAiProviderFromModel(model) {
    const value = String(model || '').toLowerCase();
    if (value.startsWith('gpt')) return 'openai';
    if (value.startsWith('claude') && !value.includes('/')) return 'anthropic';
    if (value.startsWith('gemini') && !value.includes('/')) return 'gemini';
    if (['grok-2', 'grok-beta', 'local-guardian'].includes(value)) return 'guardian';
    // OpenRouter models always contain a slash (e.g. "meta-llama/llama-3.3")
    if (value.includes('/')) return 'openrouter';
    // Groq-specific models (no slash, served by Groq API)
    const groqModels = ['llama-', 'mixtral-', 'gemma2-', 'qwen-qwq', 'whisper-'];
    if (groqModels.some(p => value.startsWith(p))) return 'groq';
    // Ollama models usually have a colon tag (llama3.1:8b) or are plain names
    if (value.includes(':')) return 'ollama';
    return 'local';
}
function getSelectedAiProvider() {
    const sel = document.getElementById('settingsAiProvider');
    if (sel && sel.value) return sel.value;
    const saved = DB.getSettings().aiProvider;
    return saved || inferAiProviderFromModel(getSelectedAiModel());
}
function getProviderApiKey(provider, settings = null) {
    const cfg = settings || DB.getSettings() || {};
    const p = String(provider || '').toLowerCase();
    if (p === 'gemini') return String(cfg.geminiApiKey || cfg.gemini_api_key || '').trim();
    if (p === 'openai') return String(cfg.openaiApiKey || cfg.openai_api_key || '').trim();
    if (p === 'anthropic') return String(cfg.anthropicApiKey || cfg.anthropic_api_key || '').trim();
    if (p === 'openrouter') return String(cfg.openrouterApiKey || cfg.openrouter_api_key || '').trim();
    if (p === 'groq') return String(cfg.groqApiKey || cfg.groq_api_key || '').trim();
    if (p === 'huggingface') return String(cfg.hfApiKey || cfg.hf_api_key || '').trim();
    if (p === 'local') return String(cfg.localAiApiKey || cfg.local_ai_api_key || '').trim();
    if (p === 'guardian') return String(cfg.tkaiGuardianApiKey || '').trim();
    return '';
}
function normalizeLocalAiBaseUrl(baseUrl) {
    let value = String(baseUrl || LOCAL_AI_DEFAULT_BASE_URL).trim();
    if (!value) value = LOCAL_AI_DEFAULT_BASE_URL;
    value = value.replace(/\/$/, '');
    value = value.replace(/\/v1\/chat\/completions$/i, '');
    value = value.replace(/\/chat\/completions$/i, '');
    value = value.replace(/\/v1\/models$/i, '');
    value = value.replace(/\/models$/i, '');
    if (!/^https?:\/\//i.test(value)) value = 'http://' + value;
    if (!/\/v1$/i.test(value)) value += '/v1';
    return value;
}
async function getAiRuntimeSettings() {
    let settings = DB.getSettings();
    if (window.etherx?.settings?.get) settings = await window.etherx.settings.get();
    const provider = getSelectedAiProvider();
    const model = getSelectedAiModel();
    const localBaseUrl = normalizeLocalAiBaseUrl(
        document.getElementById('settingsLocalAiBaseUrl')?.value ||
        settings.localAiBaseUrl ||
        settings.local_ai_base_url ||
        LOCAL_AI_DEFAULT_BASE_URL
    );
    return {
        provider,
        model,
        temperature: Number(document.getElementById('settingsAiTemp')?.value ?? settings.aiTemperature ?? 0.7),
        geminiApiKey: document.getElementById('settingsGeminiKey')?.value?.trim() || settings.geminiApiKey || settings.gemini_api_key || '',
        openaiApiKey: document.getElementById('settingsOpenaiKey')?.value?.trim() || settings.openaiApiKey || settings.openai_api_key || '',
        anthropicApiKey: document.getElementById('settingsAnthropicKey')?.value?.trim() || settings.anthropicApiKey || settings.anthropic_api_key || '',
        localAiApiKey: document.getElementById('settingsLocalAiKey')?.value?.trim() || settings.localAiApiKey || settings.local_ai_api_key || '',
        localAiBaseUrl: localBaseUrl,
        groqApiKey: document.getElementById('settingsGroqKey')?.value?.trim() || settings.groqApiKey || settings.groq_api_key || '',
        openrouterApiKey: document.getElementById('settingsOpenrouterKey')?.value?.trim() || settings.openrouterApiKey || settings.openrouter_api_key || '',
        hfApiKey: document.getElementById('settingsHfToken')?.value?.trim() || settings.hfApiKey || settings.hf_api_key || '',
        ollamaBaseUrl: normalizeLocalAiBaseUrl(document.getElementById('settingsOllamaBaseUrl')?.value || settings.ollamaBaseUrl || OLLAMA_REMOTE_DEFAULT_BASE_URL),
    };
}
function buildGuardianEndpoint(settings = {}) {
    const protocol = String(settings?.tkaiGuardianProtocol || 'http').trim().toLowerCase() === 'https' ? 'https' : 'http';
    const host = String(settings?.tkaiGuardianHost || 'localhost').trim() || 'localhost';
    const rawPort = String(settings?.tkaiGuardianPort ?? '5555').trim();
    const parsedPort = Number.parseInt(rawPort, 10);
    const port = Number.isFinite(parsedPort) && parsedPort > 0 && parsedPort <= 65535 ? String(parsedPort) : '5555';
    const rawPath = String(settings?.tkaiGuardianPath || '/v1/chat/completions').trim() || '/v1/chat/completions';
    const pathPart = rawPath.startsWith('/') ? rawPath : ('/' + rawPath);
    return `${protocol}://${host}:${port}${pathPart}`;
}

async function runGuardianAiRequest(prompt, systemPrompt = '', model = 'grok-2', apiKey = '', settings = null) {
    const cfg = settings || DB.getSettings() || {};
    const endpoint = buildGuardianEndpoint(cfg);
    const headers = { 'Content-Type': 'application/json' };
    if (apiKey) headers['Authorization'] = 'Bearer ' + apiKey;

    if (window.etherx?.ai?.guardianRequest) {
        const proxied = await window.etherx.ai.guardianRequest({
            endpoint,
            model: model || 'grok-2',
            apiKey,
            prompt,
            systemPrompt,
            maxTokens: 300
        });
        if (!proxied?.ok) throw new Error(proxied?.error || 'Guardian AI proxy request failed');
        return String(proxied.content || '').trim();
    }

    const response = await fetch(endpoint, {
        method: 'POST',
        headers,
        body: JSON.stringify({
            model: model || 'grok-2',
            messages: [
                ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
                { role: 'user', content: prompt }
            ],
            temperature: 0.3,
            max_tokens: 300
        })
    });
    if (!response.ok) {
        throw new Error('Guardian AI HTTP ' + response.status);
    }
    const data = await response.json();
    return (data.choices?.[0]?.message?.content || '').trim();
}

async function runAiTextRequest(prompt, opts = {}) {
    const runtime = await getAiRuntimeSettings();
    const provider = opts.provider || runtime.provider;
    const model = opts.model || runtime.model;
    const temperature = opts.temperature ?? runtime.temperature ?? 0.7;
    const maxOutputTokens = opts.maxOutputTokens ?? 400;
    const systemPrompt = opts.systemPrompt || '';

    if (provider === 'guardian') {
        const s = DB.getSettings() || {};
        const gModel = String(opts.model || s.tkaiGuardianModel || 'grok-2').trim();
        const gApiKey = String(opts.apiKey || s.tkaiGuardianApiKey || '').trim();
        return runGuardianAiRequest(prompt, systemPrompt, gModel, gApiKey, s);
    }

    const fetchWith202Retry = async (url, init, label, maxAttempts = 3) => {
        let lastAccepted = null;
        for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
            const response = await fetch(url, init);
            if (response.status !== 202) return response;
            lastAccepted = response;
            if (attempt < maxAttempts) {
                await new Promise((resolve) => setTimeout(resolve, 1200));
            }
        }
        let detail = '';
        try {
            const txt = await lastAccepted.text();
            if (txt) detail = txt.slice(0, 220);
        } catch (_) { }
        throw new Error(label + ' odgovor je i dalje u obradi (HTTP 202). Pokušaj ponovno za nekoliko sekundi.' + (detail ? ' Detalj: ' + detail : ''));
    };

    const providerLabel = (name) => ({
        gemini: 'Gemini',
        openai: 'OpenAI',
        local: 'Local AI',
        guardian: 'Guardian AI',
        groq: 'Groq',
        openrouter: 'OpenRouter',
        huggingface: 'HuggingFace',
        ollama: 'Ollama',
        anthropic: 'Anthropic'
    }[String(name || '').toLowerCase()] || String(name || 'AI provider'));

    const throwApiError = (name, response, data, selectedModel) => {
        const status = Number(response?.status || 0);
        const raw = String(data?.error?.message || data?.message || data?.error || '').trim();
        const label = providerLabel(name);
        if (status === 402) {
            throw new Error(label + ' HTTP 402 - račun nema aktivan billing/kredit za model "' + String(selectedModel || '') + '". Provjeri billing/credits kod providera ili promijeni provider/model.');
        }
        if (status === 429) {
            throw new Error(label + ' HTTP 429 - rate limit. Pričekaj i pokušaj ponovno.' + (raw ? ' Detalj: ' + raw : ''));
        }
        if (!response?.ok || data?.error) {
            throw new Error(raw || ('HTTP ' + status));
        }
    };

    if (provider === 'gemini') {
        const apiKey = opts.apiKey || runtime.geminiApiKey;
        if (!apiKey) throw new Error('Gemini API ključ nije postavljen.');
        const response = await fetchWith202Retry(`https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                contents: [{ parts: [{ text: systemPrompt ? systemPrompt + '\n\n' + prompt : prompt }] }],
                generationConfig: { temperature, maxOutputTokens }
            })
        }, 'Gemini');
        const data = await response.json().catch(() => ({}));
        throwApiError(provider, response, data, model);
        return (data.candidates?.[0]?.content?.parts?.[0]?.text || '').trim();
    }

    if (provider === 'openai' || provider === 'local') {
        const apiKey = opts.apiKey || (provider === 'openai' ? runtime.openaiApiKey : runtime.localAiApiKey);
        const baseUrl = provider === 'openai' ? 'https://api.openai.com/v1' : normalizeLocalAiBaseUrl(opts.baseUrl || runtime.localAiBaseUrl);
        if (provider === 'openai' && !apiKey) throw new Error('OpenAI API ključ nije postavljen.');
        const headers = { 'Content-Type': 'application/json' };
        if (apiKey) headers.Authorization = 'Bearer ' + apiKey;
        const response = await fetchWith202Retry(baseUrl + '/chat/completions', {
            method: 'POST',
            headers,
            body: JSON.stringify({
                model,
                messages: [
                    ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
                    { role: 'user', content: prompt }
                ],
                temperature,
                max_tokens: maxOutputTokens
            })
        }, provider === 'openai' ? 'OpenAI' : 'Local AI');
        const data = await response.json().catch(() => ({}));
        throwApiError(provider, response, data, model);
        return (data.choices?.[0]?.message?.content || '').trim();
    }

    if (provider === 'groq') {
        const apiKey = opts.apiKey || runtime.groqApiKey;
        if (!apiKey) throw new Error('Groq API ključ nije postavljen.');
        const response = await fetchWith202Retry('https://api.groq.com/openai/v1/chat/completions', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey },
            body: JSON.stringify({
                model,
                messages: [
                    ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
                    { role: 'user', content: prompt }
                ],
                temperature,
                max_tokens: maxOutputTokens
            })
        }, 'Groq');
        const data = await response.json().catch(() => ({}));
        throwApiError(provider, response, data, model);
        return (data.choices?.[0]?.message?.content || '').trim();
    }

    if (provider === 'openrouter') {
        const apiKey = opts.apiKey || runtime.openrouterApiKey;
        if (!apiKey) throw new Error('OpenRouter API ključ nije postavljen.');
        const response = await fetchWith202Retry('https://openrouter.ai/api/v1/chat/completions', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': 'Bearer ' + apiKey,
                'HTTP-Referer': 'https://etherx.io',
                'X-Title': 'EtherX Browser'
            },
            body: JSON.stringify({
                model,
                messages: [
                    ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
                    { role: 'user', content: prompt }
                ],
                temperature,
                max_tokens: maxOutputTokens
            })
        }, 'OpenRouter');
        const data = await response.json().catch(() => ({}));
        throwApiError(provider, response, data, model);
        return (data.choices?.[0]?.message?.content || '').trim();
    }

    if (provider === 'huggingface') {
        const apiKey = opts.apiKey || runtime.hfApiKey;
        if (!apiKey) throw new Error('HuggingFace token nije postavljen.');
        const response = await fetchWith202Retry('https://router.huggingface.co/v1/chat/completions', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey },
            body: JSON.stringify({
                model,
                messages: [
                    ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
                    { role: 'user', content: prompt }
                ],
                temperature,
                max_tokens: maxOutputTokens
            })
        }, 'HuggingFace');
        const data = await response.json().catch(() => ({}));
        throwApiError(provider, response, data, model);
        return (data.choices?.[0]?.message?.content || '').trim();
    }

    if (provider === 'ollama') {
        const baseUrl = normalizeLocalAiBaseUrl(opts.baseUrl || runtime.ollamaBaseUrl || OLLAMA_REMOTE_DEFAULT_BASE_URL);
        if (/https?:\/\/(?:localhost|127\.0\.0\.1)(?::\d+)?\/v1/i.test(baseUrl)) {
            throw new Error('Ollama localhost je isključen. Postavi online Ollama endpoint u AI postavkama.');
        }
        const response = await fetchWith202Retry(baseUrl + '/chat/completions', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                model,
                messages: [
                    ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
                    { role: 'user', content: prompt }
                ],
                temperature,
                max_tokens: maxOutputTokens
            })
        }, 'Ollama');
        const data = await response.json().catch(() => ({}));
        throwApiError(provider, response, data, model);
        return (data.choices?.[0]?.message?.content || '').trim();
    }

    if (provider === 'anthropic') {
        const apiKey = opts.apiKey || runtime.anthropicApiKey;
        if (!apiKey) throw new Error('Anthropic API ključ nije postavljen.');
        const response = await fetchWith202Retry('https://api.anthropic.com/v1/messages', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'x-api-key': apiKey,
                'anthropic-version': '2023-06-01'
            },
            body: JSON.stringify({
                model,
                max_tokens: maxOutputTokens,
                temperature,
                system: systemPrompt || undefined,
                messages: [{ role: 'user', content: prompt }]
            })
        }, 'Anthropic');
        const data = await response.json().catch(() => ({}));
        throwApiError(provider, response, data, model);
        return (data.content || []).map(part => part?.text || '').join('').trim();
    }

    throw new Error('Nepodržan AI provider: ' + provider);
}
const GEMINI_MODEL = GEMINI_DEFAULT_MODEL;

const _summaryCache = {};
function _md5Hash(str) {
    let h = 5381;
    for (let i = 0; i < str.length; i++) h = ((h << 5) + h) ^ str.charCodeAt(i);
    return (h >>> 0).toString(16);
}

async function summarizeCurrentPage() {
    const tab = getActiveTab();
    const url = tab?.url || '';
    if (!url || url.startsWith('etherx://') || !url.startsWith('http')) {
        return { ok: false, error: 'Nema aktivne web stranice za analizu.' };
    }

    const selectedModel = getSelectedAiModel();
    const selectedProvider = getSelectedAiProvider();
    const card = document.getElementById('aiSummaryCard');
    const loader = document.getElementById('ascLoader');
    const bulletsEl = document.getElementById('ascBullets');
    const metaEl = document.getElementById('ascMeta');
    const cachedEl = document.getElementById('ascCached');
    const titleEl = document.getElementById('ascTitle');

    card.classList.add('open');
    loader.style.display = 'flex';
    bulletsEl.style.display = 'none';
    cachedEl.textContent = '';
    try { titleEl.textContent = new URL(url).hostname; } catch (e) { }

    const cacheKey = _md5Hash(url + ':' + selectedProvider + ':' + selectedModel);
    if (_summaryCache[cacheKey]) {
        loader.style.display = 'none';
        _renderSummaryBullets(bulletsEl, _summaryCache[cacheKey].bullets);
        bulletsEl.style.display = 'block';
        metaEl.textContent = selectedModel;
        cachedEl.textContent = '✓ iz cache-a';
        return { ok: true, cached: true };
    }

    if (selectedProvider === 'gemini' && window.electronWebview && window.etherx?.ai?.summarizePage) {
        try {
            let html = '';
            const activeWv = document.querySelector('.tab-frame.active webview, webview#browseFrame');
            if (activeWv && typeof activeWv.executeJavaScript === 'function') {
                try {
                    html = await activeWv.executeJavaScript('document.documentElement.outerHTML');
                } catch (_e) {
                    try { html = await activeWv.executeJavaScript('document.body.innerText'); } catch (_e2) { html = ''; }
                }
            }
            const result = await window.etherx.ai.summarizePage(url, html);
            loader.style.display = 'none';
            if (!result.ok) {
                _renderSummaryError(bulletsEl, result.error);
                bulletsEl.style.display = 'block';
                return result;
            }
            _summaryCache[cacheKey] = result;
            _renderSummaryBullets(bulletsEl, result.bullets);
            bulletsEl.style.display = 'block';
            metaEl.textContent = selectedModel;
            cachedEl.textContent = result.cached ? '✓ iz cache-a' : '';
            return result;
        } catch (e) {
        }
    }

    try {
        let pageText = '';
        try {
            const resp = await fetch(url);
            const html = await resp.text();
            pageText = html.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
                .replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, '')
                .replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 8000);
        } catch (e) {
            pageText = `Stranica: ${url}`;
        }

        const prompt = `You are a concise summarizer. Respond with exactly 3 bullet points using the • character. Each bullet is one clear sentence in Croatian language. No intro text, no conclusion.\n\nSummarize the key points of this web page in 3 bullet points:\n\nURL: ${url}\n\n${pageText}`;
        const summary = await runAiTextRequest(prompt, {
            provider: selectedProvider,
            model: selectedModel,
            temperature: 0.3,
            maxOutputTokens: 400
        });
        const bullets = summary.split('\n').map(l => l.trim()).filter(l => l.length > 0 && (l.startsWith('•') || l.startsWith('-') || /^\d\./.test(l)));

        loader.style.display = 'none';
        _summaryCache[cacheKey] = { bullets, summary };
        _renderSummaryBullets(bulletsEl, bullets.length ? bullets : [summary]);
        bulletsEl.style.display = 'block';
        metaEl.textContent = selectedModel;
        cachedEl.textContent = '';
        return { ok: true, bullets, summary };
    } catch (err) {
        loader.style.display = 'none';
        _renderSummaryError(bulletsEl, err.message);
        bulletsEl.style.display = 'block';
        return { ok: false, error: err.message };
    }
}

function _renderSummaryBullets(el, bullets) {
    el.innerHTML = '';
    if (!bullets || !bullets.length) {
        el.innerHTML = '<div style="color:var(--text3);font-size:12px">Nema sažetka.</div>';
        return;
    }
    bullets.forEach((b, i) => {
        const clean = b.replace(/^[•\-\d\.\s]+/, '').trim();
        const div = document.createElement('div');
        div.className = 'asc-bullet';
        div.innerHTML = `<div class="asc-bullet-dot">${i + 1}</div><div>${clean}</div>`;
        el.appendChild(div);
    });
}
function _renderSummaryError(el, msg) {
    el.innerHTML = `<div style="color:var(--red);font-size:12px">⚠️ ${msg}</div>`;
}

