    window.parseTikTokOwnerFromUrl = function parseTikTokOwnerFromUrl(url) {
        try {
            const pathname = new URL(String(url || ''), window.location.origin).pathname || '';
            const m = pathname.match(/\/(@[^\/?#]+)/i);
            return m ? decodeURIComponent(m[1]).replace(/^@+/, '') : '';
        } catch (_) {
            return '';
        }
    };
    function normalizeTikTokProfileHandle(value) {
        const raw = String(value || '').trim();
        if (!raw) return '';
        const fromUrl = parseTikTokOwnerFromUrl(raw);
        const base = String(fromUrl || raw).trim().replace(/^@+/, '');
        if (!base) return '';
        const strict = base.match(/^([a-z0-9._]{2,40})$/i);
        if (strict && strict[1]) return strict[1].toLowerCase();
        const fromMention = base.match(/@([a-z0-9._]{2,40})/i);
        if (fromMention && fromMention[1]) return fromMention[1].toLowerCase();
        const fallback = base
            .toLowerCase()
            .replace(/[^a-z0-9._\s-]+/g, ' ')
            .trim()
            .replace(/[\s-]+/g, '.')
            .replace(/\.{2,}/g, '.')
            .replace(/^\.+|\.+$/g, '');
        return /^[a-z0-9._]{2,40}$/.test(fallback) ? fallback : '';
    }
    function isUnknownTkaiUserName(value) {
        return /^(?:unknown|undefined|null|chat\s*user|user)$/i.test(String(value || '').trim());
    }
    function normalizeTkaiDisplayUserName(value) {
        const raw = String(value || '').replace(/\s+/g, ' ').trim();
        if (!raw || isUnknownTkaiUserName(raw)) return '';
        const handle = normalizeTikTokProfileHandle(raw);
        if (handle && /^@?[a-z0-9._]{2,40}$/i.test(raw)) return handle;
        const cleaned = raw
            .replace(/\b(?:lvl|lv|level|razina)\s*[:#-]?\s*\d{1,3}\b/gi, ' ')
            .replace(/^(?:lvl|lv|level|razina)?\s*[:#-]?\s*\d{1,3}\s+/i, '')
            .replace(/^[^\p{L}@#]+/u, '')
            .replace(/^@+/, '')
            .replace(/[,:;|].*$/, '')
            .replace(/\s{2,}/g, ' ')
            .trim();
        if (!cleaned || isUnknownTkaiUserName(cleaned)) return '';
        if (/^[#@]?\d{1,3}$/.test(cleaned)) return '';
        if (!/\p{L}/u.test(cleaned)) return '';
        return cleaned.slice(0, 60);
    }
    function resolveTkaiMessageUser(message) {
        const direct = normalizeTkaiDisplayUserName(message?.user || '');
        if (direct) return direct;
        const handle = normalizeTikTokProfileHandle(message?.userHandle || message?.profileHandle || '');
        if (handle) return handle;
        const sources = [
            message?.rawText,
            message?.giftRawText,
            message?.text,
            message?.ariaLabel,
            message?.title
        ].map((value) => String(value || '').replace(/\s+/g, ' ').trim()).filter(Boolean);
        const patterns = [
            /^\s*(.{2,80}?)\s*[:\-–—]\s+.{1,}$/u,
            /^\s*(.{2,80}?)\s+(?:sent|gave|gifted|donated|joined|shared|liked|poklon(?:io|ila)?|darovao|darovala|donirao|donirala|u[sš]ao|u[sš]la|podijelio|podijelila)\b/iu,
            /^\s*(.{2,80}?)\s+(?:said|commented|wrote|ka[žz]e|komentira)\b/iu
        ];
        for (const source of sources) {
            for (const pattern of patterns) {
                const match = source.match(pattern);
                const user = normalizeTkaiDisplayUserName(match?.[1] || '');
                if (user) return user;
            }
        }
        return '';
    }
    function repairTkaiMessageIdentity(message) {
        if (!message || typeof message !== 'object') return message;
        const user = resolveTkaiMessageUser(message);
        const handle = normalizeTikTokProfileHandle(message.userHandle || message.profileHandle || user || '');
        if (!user && !handle) return message;
        return {
            ...message,
            user: user || handle || message.user,
            userHandle: normalizeTikTokProfileHandle(message.userHandle || message.profileHandle || handle || '')
        };
    }
    function resolveTikTokProfileHandle(user, message = null) {
        const direct = normalizeTikTokProfileHandle(
            message?.userHandle
            || message?.profileHandle
            || user
            || ''
        );
        if (direct) return direct;
        const targetUser = String(user || '').trim().toLowerCase();
        if (!targetUser) return '';
        for (let i = collectedMessages.length - 1; i >= 0; i -= 1) {
            const row = collectedMessages[i];
            if (!row) continue;
            if (String(row.user || '').trim().toLowerCase() !== targetUser) continue;
            const handle = normalizeTikTokProfileHandle(row.userHandle || row.profileHandle || '');
            if (handle) return handle;
        }
        return normalizeTikTokProfileHandle(user);
    }
    function openTikTokProfileTab(user, message = null) {
        const handle = resolveTikTokProfileHandle(user, message);
        if (!handle) {
            showToast('⚠️ TikTok handle nije pronađen');
            return;
        }
        createTab('https://www.tiktok.com/@' + encodeURIComponent(handle), '@' + handle, true);
    }
    function updateTkaiStreamOwner(owner, sourceUrl) {
        if (!streamOwnerEl) return;
        const fromOwner = String(owner || '').trim().replace(/^@+/, '');
        const fallback = parseTikTokOwnerFromUrl(sourceUrl || getActiveTab()?.url || '');
        const resolved = (fromOwner || fallback || '').slice(0, 40);
        streamOwnerEl.textContent = resolved ? ('@' + resolved) : '@-';
        streamOwnerEl.title = resolved ? ('Live stream owner: @' + resolved) : 'Live stream owner nije detektiran';
    }
    function formatNum(value) {
        const n = Number(value || 0);
        if (!Number.isFinite(n)) return '0';
        return n.toLocaleString('hr-HR');
    }
    function formatDurationHoursMinutes(totalMs) {
        const mins = Math.max(0, Math.floor(Number(totalMs || 0) / 60000));
        const h = Math.floor(mins / 60);
        const m = mins % 60;
        return `${h}h ${m}m`;
    }
    function setSongToolStatus(text) {
        document.querySelectorAll('#tkaiSongToolsStatus, #tkaiSongRecStatus, #tkaiLiveSongToolsStatus').forEach((node) => {
            if (node) node.textContent = String(text || '');
        });
    }
    function setSongToolButtonState(tool, busy) {
        const isSongRec = tool === 'songrec';
        const ids = isSongRec
            ? ['#tkaiSongRecNowBtn', '#tkaiLiveSongRecNow']
            : ['#tkaiDjCcNowBtn', '#tkaiLiveDjCcNow'];
        const idleLabel = isSongRec ? 'SongRec now' : 'DJ CC now';
        const busyLabel = isSongRec ? 'SongRec...' : 'DJ CC...';
        ids.forEach((sel) => {
            document.querySelectorAll(sel).forEach((btn) => {
                btn.disabled = !!busy;
                btn.textContent = busy ? busyLabel : idleLabel;
            });
        });
    }
    async function runSongRecRecognition(manualTrigger) {
        setSongToolButtonState('songrec', true);
        if (!window.etherx?.songrec?.recognize) {
            setSongToolStatus('SongRec: API nije dostupan');
            if (manualTrigger) showToast('SongRec API nije dostupan. Provjeri preload/main integraciju.');
            setSongToolButtonState('songrec', false);
            return;
        }

        const cfg = DB.getSettings() || {};
        const command = String(cfg.tkaiSongRecCommand || 'songrec').trim() || 'songrec';
        const outputDevice = String(cfg.tkaiSongRecOutputDevice || '').trim();
        const timeoutMs = Math.max(2000, Math.min(25000, Number(cfg.tkaiSongRecTimeoutMs || 12000) || 12000));
        setSongToolStatus('SongRec: slusam...');
        if (manualTrigger) showToast('▶ SongRec pokrenut');

        try {
            const result = await window.etherx.songrec.recognize({ command, timeoutMs, outputDevice });
            if (!result?.ok) {
                setSongToolStatus('SongRec: greska');
                if (manualTrigger) showToast('SongRec greska: ' + (result?.error || 'nepoznata greska'));
                setSongToolButtonState('songrec', false);
                return;
            }

            const title = String(result.title || '').trim();
            if (!title) {
                setSongToolStatus('SongRec: nema detekcije');
                if (manualTrigger) showToast('SongRec nije prepoznao pjesmu.');
                setSongToolButtonState('songrec', false);
                return;
            }

            const trackMsg = {
                id: 'songrec_' + Date.now() + '_' + Math.random().toString(36).slice(2),
                user: 'SYSTEM (SongRec)',
                text: title,
                type: 'song',
                ts: Date.now(),
            };
            collectedMessages.push(trackMsg);
            const maxLen = Math.max(120, Number(DB.getSettings().tkaiMsgBuffer || 300));
            if (collectedMessages.length > maxLen) collectedMessages = collectedMessages.slice(-maxLen);

            setSongToolStatus('SongRec: ' + title);
            renderMessages();
            updateSessionStatsUI();
            if (manualTrigger) showToast('🎵 SongRec: ' + title);
        } catch (err) {
            setSongToolStatus('SongRec: greska');
            if (manualTrigger) showToast('SongRec poziv nije uspio: ' + String(err?.message || err));
        } finally {
            setSongToolButtonState('songrec', false);
        }
    }
    window.runSongRecRecognition = runSongRecRecognition;

    async function runDjCcNow(manualTrigger) {
        setSongToolButtonState('djcc', true);
        setSongToolStatus('DJ CC: čitam titlove...');
        if (manualTrigger) showToast('▶ DJ CC pokrenut');
        try {
            await scrapeTikTokChat();
            const latestCaption = [...collectedMessages].reverse().find((m) => String(m?.type || '').toLowerCase() === 'caption');
            if (!latestCaption) {
                setSongToolStatus('DJ CC: nema novih titlova');
                if (manualTrigger) showToast('DJ CC nije našao svježe titlove.');
                return;
            }
            const text = String(latestCaption.text || '').trim();
            const shortText = text.length > 96 ? text.slice(0, 96) + '...' : text;
            setSongToolStatus('DJ CC: ' + shortText);
            if (isCcReadEnabled()) {
                await handleIncomingCaption(latestCaption).catch(() => { });
            }
            if (manualTrigger) showToast('💬 DJ CC: ' + shortText);
        } catch (err) {
            setSongToolStatus('DJ CC: greška');
            if (manualTrigger) showToast('DJ CC poziv nije uspio: ' + String(err?.message || err));
        } finally {
            setSongToolButtonState('djcc', false);
        }
    }
    window.runDjCcNow = runDjCcNow;

    const TKAI_FAV_SOUNDS_KEY = 'ex_tkai_fav_sounds';
    function readTkaiFavSounds() {
        try {
            const rows = JSON.parse(localStorage.getItem(TKAI_FAV_SOUNDS_KEY) || '[]');
            return Array.isArray(rows) ? rows.map((v) => String(v || '').trim()).filter(Boolean) : [];
        } catch (_) {
            return [];
        }
    }
    function writeTkaiFavSounds(rows) {
        try { localStorage.setItem(TKAI_FAV_SOUNDS_KEY, JSON.stringify(Array.isArray(rows) ? rows : [])); } catch (_) { }
    }
    function collectTkaiSoundCandidates(limit = 24) {
        const seen = new Set();
        const out = [];
        for (let i = collectedMessages.length - 1; i >= 0 && out.length < limit; i -= 1) {
            const row = collectedMessages[i];
            const type = String(row?.type || '').toLowerCase();
            if (type !== 'song' && type !== 'caption') continue;
            const text = String(row?.text || '').trim();
            if (!text || seen.has(text.toLowerCase())) continue;
            seen.add(text.toLowerCase());
            out.push(text);
        }
        return out;
    }
    function playTkaiSoundPreview(text) {
        const phrase = String(text || '').trim();
        if (!phrase) return;
        if ('speechSynthesis' in window && window.speechSynthesis) {
            try {
                const u = new SpeechSynthesisUtterance(phrase);
                u.lang = 'en-US';
                u.rate = 1;
                u.pitch = 1;
                window.speechSynthesis.cancel();
                window.speechSynthesis.speak(u);
                return;
            } catch (_) { }
        }
        showToast('Sound preview nije podržan u ovom okruženju.');
    }
    function renderTkaiFavSoundsQuick(mode = 'fav') {
        const wrap = document.getElementById('tkaiFavSoundsQuickWrap');
        const list = document.getElementById('tkaiFavSoundsQuickList');
        if (!wrap || !list) return;
        const fav = readTkaiFavSounds();
        const candidates = collectTkaiSoundCandidates(30);
        const rows = mode === 'all'
            ? Array.from(new Set(candidates.concat(fav))).slice(0, 24)
            : fav.slice(0, 24);

        wrap.style.display = '';
        list.innerHTML = '';

        if (!rows.length) {
            list.innerHTML = '<span style="font-size:10px;color:var(--text3)">Nema favoriziranih soundova. Klikni Soundboard pa ⭐ na stavku.</span>';
            return;
        }

        rows.forEach((label) => {
            const holder = document.createElement('div');
            holder.style.cssText = 'display:flex;align-items:center;gap:4px;max-width:100%';
            const playBtn = document.createElement('button');
            playBtn.className = 'tkai-insights-btn';
            playBtn.type = 'button';
            playBtn.textContent = '▶ ' + (label.length > 40 ? label.slice(0, 40) + '...' : label);
            playBtn.title = label;
            playBtn.style.maxWidth = '220px';
            playBtn.style.overflow = 'hidden';
            playBtn.style.textOverflow = 'ellipsis';
            playBtn.addEventListener('click', () => playTkaiSoundPreview(label));

            const starBtn = document.createElement('button');
            starBtn.className = 'tkai-insights-btn';
            starBtn.type = 'button';
            const isFav = fav.some((v) => v.toLowerCase() === label.toLowerCase());
            starBtn.textContent = isFav ? '★' : '☆';
            starBtn.title = isFav ? 'Ukloni iz favorita' : 'Dodaj u favorite';
            starBtn.addEventListener('click', () => {
                const current = readTkaiFavSounds();
                const idx = current.findIndex((v) => v.toLowerCase() === label.toLowerCase());
                if (idx >= 0) {
                    current.splice(idx, 1);
                    writeTkaiFavSounds(current);
                    showToast('Uklonjeno iz favorita.');
                } else {
                    current.unshift(label);
                    writeTkaiFavSounds(Array.from(new Set(current)).slice(0, 40));
                    showToast('Dodano u favorite.');
                }
                renderTkaiFavSoundsQuick(mode);
            });

            holder.appendChild(playBtn);
            holder.appendChild(starBtn);
            list.appendChild(holder);
        });
    }
    function getUserColor(name) {
        const input = String(name || '').trim().toLowerCase();
        let h = 0;
        for (let i = 0; i < input.length; i += 1) h = (h * 31 + input.charCodeAt(i)) >>> 0;
        const hue = h % 360;
        return `hsl(${hue} 78% 72%)`;
    }
    function buildUserStats(messages, limit) {
        const scanLimit = Math.max(30, Math.min(1000, Number(limit || 200)));
        const base = (Array.isArray(messages) ? messages : collectedMessages).slice(-scanLimit);
        const map = new Map();
        base.forEach((m) => {
            const user = String(m?.user || '').trim();
            if (!user) return;
            if (!map.has(user)) map.set(user, { user, total: 0, chat: 0, gifts: 0, joins: 0, likes: 0, shares: 0, lastTs: 0, firstSeen: Number(m.ts || 0), coins: 0, texts: new Map(), giftTypes: new Map(), lastMessage: '', appearances: [] });
            const row = map.get(user);
            const mTs = Number(m.ts || 0);
            if (mTs && (row.firstSeen === 0 || mTs < row.firstSeen)) row.firstSeen = mTs;
            if (mTs) row.appearances.push(mTs);
            row.total += 1;
            const type = normalizeTkaiMessageType(m);
            if (type === 'gift' || type === 'subscriber') {
                const meta = safeResolveGiftMetaFromMessage(m);
                const quantity = Math.max(1, Number(m.quantity || meta?.quantity || 1));
                const giftName = String(m.giftName || '').trim() || String(meta?.giftName || '').trim() || String(m.text || '').trim() || 'gift';
                const coins = Math.max(0, Number(m.coins || meta?.coins || parseCoinsFromText(String(m.text || '')) || 0));
                row.gifts += quantity;
                row.coins += coins;
                row.giftTypes.set(giftName, (row.giftTypes.get(giftName) || 0) + quantity);
            }
            else if (type === 'join') row.joins += 1;
            else if (type === 'like') row.likes += Math.max(1, Number(m.quantity || 1));
            else if (type === 'share') row.shares += 1;
            else row.chat += 1;
            const rawText = String(m.text || '').trim();
            const txt = rawText.toLowerCase();
            if (txt) {
                row.texts.set(txt, (row.texts.get(txt) || 0) + 1);
                row.lastMessage = rawText.slice(0, 160);
            }
            row.lastTs = Math.max(row.lastTs, Number(m.ts || 0));
        });
        return Array.from(map.values())
            .map((r) => ({
                user: r.user,
                total: r.total,
                chat: r.chat,
                gifts: r.gifts,
                joins: r.joins,
                likes: r.likes,
                shares: r.shares,
                lastTs: r.lastTs,
                firstSeen: r.firstSeen,
                appearances: r.appearances.length,
                coins: r.coins,
                repeatMax: Math.max(0, ...Array.from(r.texts.values())),
                giftTypes: Array.from(r.giftTypes.entries()).sort((a, b) => Number(b[1] || 0) - Number(a[1] || 0)).slice(0, 4),
                lastMessage: r.lastMessage
            }))
            .sort((a, b) => b.coins - a.coins || b.gifts - a.gifts || b.total - a.total || b.lastTs - a.lastTs);
    }
    function buildDailyStats(messages, limit) {
        const scanLimit = Math.max(30, Math.min(2000, Number(limit || 200)));
        const base = (Array.isArray(messages) ? messages : collectedMessages).slice(-scanLimit);
        const map = new Map();
        base.forEach((m) => {
            const d = new Date(Number(m.ts || Date.now()));
            const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
            if (!map.has(key)) map.set(key, { day: key, total: 0, chat: 0, gifts: 0, joins: 0, likes: 0, shares: 0, users: new Set() });
            const row = map.get(key);
            const type = normalizeTkaiMessageType(m);
            row.total += 1;
            if (type === 'gift' || type === 'subscriber') row.gifts += 1;
            else if (type === 'join') row.joins += 1;
            else if (type === 'like') row.likes += Math.max(1, Number(m?.quantity || 1));
            else if (type === 'share') row.shares += 1;
            else row.chat += 1;
            if (m.user) row.users.add(String(m.user));
        });
        return Array.from(map.values())
            .map((r) => ({
                day: r.day,
                total: r.total,
                chat: r.chat,
                gifts: r.gifts,
                joins: r.joins,
                likes: r.likes,
                shares: r.shares,
                users: r.users.size
            }))
            .sort((a, b) => String(b.day).localeCompare(String(a.day)));
    }
    function applyTkaiPanelScale() {
        const panel = document.getElementById('tiktokAIPanel');
        if (!panel) return;
        const s = DB.getSettings();
        const uiScale = Math.max(80, Math.min(140, Number(s.tkaiUiScale || 100)));
        const fontScale = Math.max(85, Math.min(170, Number(s.tkaiFontScale || 100)));
        panel.style.setProperty('--tkai-ui-scale', String(uiScale / 100));
        panel.style.setProperty('--tkai-font-scale', String(fontScale / 100));
        requestAnimationFrame(() => ensurePanelInViewport(panel));
    }
    function renderUserSummary() {
        if (!userSummaryListEl || !userSummaryMetaEl) return;
        const s = DB.getSettings();
        const limit = Number(s.tkaiUserScanLimit || 200);
        const users = buildUserStats(collectedMessages, limit);
        userSummaryMetaEl.textContent = `${formatNum(users.length)} korisnika • scan ${formatNum(limit)} poruka`;
        userSummaryListEl.innerHTML = '';
        users.slice(0, 18).forEach((u) => {
            const userMsgs = collectedMessages.filter((m) => String(m?.user || '').trim().toLowerCase() === String(u.user || '').trim().toLowerCase());
            const sentiment = computeUserSentiment(userMsgs);
            const pill = document.createElement('button');
            pill.type = 'button';
            pill.className = 'tkai-user-pill';
            pill.style.borderColor = getUserColor(u.user);
            pill.style.color = getUserColor(u.user);
            pill.textContent = `${sentiment.emoji} @${u.user} (${u.total})`;
            pill.title = `Klik: otvori poruke | Desni klik: kopiraj @mention\nSentiment: ${sentiment.label} (${sentiment.pos}+ / ${sentiment.neg}-)`;
            pill.addEventListener('click', () => {
                showTkaiUserMessagesModal(u.user);
            });
            pill.addEventListener('contextmenu', (ev) => {
                ev.preventDefault();
                navigator.clipboard.writeText('@' + u.user + ' ').then(() => showToast('📋 Kopirano @' + u.user)).catch(() => { });
            });
            userSummaryListEl.appendChild(pill);
        });
    }
    function renderShadowbanUserStats() {
        if (!shadowbanUserStatsEl || !shadowbanUserFilterEl) return;
        const selected = shadowbanUserFilterEl.value || '__all__';
        const rows = selected === '__all__'
            ? lastShadowbanUserStats
            : lastShadowbanUserStats.filter((r) => r.user === selected);
        shadowbanUserStatsEl.innerHTML = rows.length
            ? rows.map((r) => {
                const botHint = r.repeatMax >= 4 || (r.total >= 10 && r.chat >= 8) ? ' • moguci bot' : '';
                return `<div style="margin:2px 0;color:${getUserColor(r.user)}">@${escHtml(r.user)}: ${formatNum(r.total)} msg (${formatNum(r.chat)} chat, ${formatNum(r.gifts)} gift, ${formatNum(r.joins)} join)${botHint}</div>`;
            }).join('')
            : '<div style="color:var(--text3)">Nema podataka za korisnika.</div>';
        if (shadowbanUserCountEl) shadowbanUserCountEl.textContent = `${formatNum(rows.length)} prikazano`;
    }
    function refreshShadowbanUserFilterOptions() {
        if (!shadowbanUserFilterEl) return;
        const current = shadowbanUserFilterEl.value || '__all__';
        shadowbanUserFilterEl.innerHTML = '';
        const allOpt = document.createElement('option');
        allOpt.value = '__all__';
        allOpt.textContent = 'Svi korisnici';
        shadowbanUserFilterEl.appendChild(allOpt);
        lastShadowbanUserStats.forEach((r) => {
            const opt = document.createElement('option');
            opt.value = r.user;
            opt.textContent = `@${r.user} (${formatNum(r.total)})`;
            shadowbanUserFilterEl.appendChild(opt);
        });
        shadowbanUserFilterEl.value = lastShadowbanUserStats.some((r) => r.user === current) ? current : '__all__';
    }
