    // ── Filter starred messages ─────────────────────────────────────────
    let starredMsgIds = new Set();
    let filterStarredActive = false;
    if (filterStarredBtn) {
        filterStarredBtn.addEventListener('click', () => {
            filterStarredActive = !filterStarredActive;
            filterStarredBtn.textContent = filterStarredActive ? '⭐ Starred' : '⭐ Sve';
            filterStarredBtn.style.background = filterStarredActive ? 'rgba(255,213,0,.25)' : '';
            renderMessages();
            if (filterStarredActive && starredMsgIds.size === 0) showToast('⭐ Nema označenih poruka. Dvostruki klik na poruku za označavanje.');
        });
    }

    // ── Apply feature toggles from settings ──────────────────────────────
    function applyTkaiFeatureToggles() {
        const s = DB.getSettings();
        const vis = (id, settingKey, def = true) => {
            const el = document.getElementById(id);
            if (!el) return;
            const on = s[settingKey] !== undefined ? s[settingKey] !== false && s[settingKey] !== 'false' : def;
            el.style.display = on ? '' : 'none';
        };
        // Apply custom gift gallery header title
        const giftHeaderTitle = document.getElementById('tkaiGiftGalleryHeaderTitle');
        if (giftHeaderTitle) {
            const customTitle = String(s.tkaiGiftGalleryTitle || '').trim();
            giftHeaderTitle.textContent = customTitle || '🎁 Gift Galerija';
        }
        vis('tkaiStatsStrip', 'tkaiShowStats');
        vis('tkaiInsights', 'tkaiShowInsights');
        vis('tkaiGiftGallery', 'tkaiShowGiftGallery');
        vis('tkaiTopSupporters', 'tkaiShowTopSupporters');
        vis('tkaiUserSummary', 'tkaiShowTopSupporters');
        vis('tkaiShadowbanCard', 'tkaiShowShadowban');
        vis('tkaiSpikesCard', 'tkaiShowSpikes');
        vis('tkaiRecommendationsCard', 'tkaiShowRecommendations');
        vis('tkaiJoinsCard', 'tkaiScanJoins');
        vis('tkaiQuestionsCard', 'tkaiShowQuestions');
        vis('tkaiPieCard', 'tkaiShowPieBreakdown');
        const songCard = document.getElementById('tkaiSongsCard');
        if (songCard) songCard.style.display = '';
        if (recJumpBtn) {
            const popEnabled = s.tkaiRecommendationsPopoutEnabled === true;
            const jumpEnabled = s.tkaiRecommendationJumpPulseEnabled === true;
            if (!popEnabled || !jumpEnabled) {
                recJumpBtn.style.display = 'none';
                recJumpBtn.classList.remove('live');
            }
        }

        // Safety net: if every insights card ended hidden (bad saved state), bring core cards back.
        const insightsRoot = document.getElementById('tkaiInsights');
        if (insightsRoot) {
            const cards = Array.from(insightsRoot.querySelectorAll('.tkai-insights-card'));
            const visibleCards = cards.filter(c => c.style.display !== 'none');
            if (cards.length > 0 && visibleCards.length === 0) {
                ['tkaiSpikesCard', 'tkaiRecommendationsCard', 'tkaiPieCard', 'tkaiSongsCard'].forEach((id) => {
                    const el = document.getElementById(id);
                    if (el) el.style.display = '';
                });
            }
        }
    }

    function normalizeTkaiHexColor(value, fallback) {
        const v = String(value || '').trim();
        return /^#([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(v) ? v : fallback;
    }

    function applyTkaiButtonTheme() {
        const s = DB.getSettings();
        const primary = normalizeTkaiHexColor(s.tkaiBtnColorPrimary, '#667eea');
        const secondary = normalizeTkaiHexColor(s.tkaiBtnColorSecondary, '#764ba2');
        const insights = normalizeTkaiHexColor(s.tkaiBtnColorInsights, '#2dd4bf');
        const panel = document.getElementById('tiktokAIPanel');
        if (!panel) return;

        const scanBtnEl = document.getElementById('tkaiBtnToggle');
        if (scanBtnEl) {
            if (scanActive) {
                scanBtnEl.style.background = 'linear-gradient(135deg,#16a34a,#22c55e)';
                scanBtnEl.style.borderColor = 'rgba(34,197,94,.65)';
                scanBtnEl.style.color = '#fff';
                scanBtnEl.style.boxShadow = '0 0 0 1px rgba(34,197,94,.45) inset, 0 0 10px rgba(34,197,94,.35)';
            } else {
                scanBtnEl.style.background = `linear-gradient(135deg, ${secondary}, ${primary})`;
                scanBtnEl.style.borderColor = 'rgba(255,255,255,.2)';
                scanBtnEl.style.color = '#fff';
                scanBtnEl.style.boxShadow = 'none';
            }
        }

        panel.querySelectorAll('.tkai-gen-btn').forEach(btn => {
            if (btn.id === 'tkaiClearBtn') return;
            btn.style.background = `linear-gradient(135deg, ${primary}, ${secondary})`;
            btn.style.borderColor = 'rgba(255,255,255,.2)';
            btn.style.color = '#fff';
        });

        panel.querySelectorAll('.tkai-insights-btn, .tkai-collapse-btn').forEach(btn => {
            btn.style.background = `linear-gradient(135deg, ${insights}, ${primary})`;
            btn.style.borderColor = 'rgba(255,255,255,.22)';
            btn.style.color = '#fff';
        });
        applyTkaiPanelScale();
    }

    // Apply on panel open
    const tkaiThemeBtn = document.getElementById('btnTikTokAI');
    if (tkaiThemeBtn && tkaiThemeBtn.dataset.tkaiThemeBound !== '1') {
        tkaiThemeBtn.dataset.tkaiThemeBound = '1';
        tkaiThemeBtn.addEventListener('click', () => {
            setTimeout(() => {
                applyTkaiFeatureToggles();
                applyTkaiButtonTheme();
                initInsightCardControls();
            }, 50);
        });
    }
    // Re-apply whenever a tkai feature toggle is clicked in settings
    document.getElementById('settingsPanel')?.addEventListener('click', e => {
        const t = e.target.closest('.toggle[data-setting]');
        if (t && t.dataset.setting && t.dataset.setting.startsWith('tkaiShow')) setTimeout(applyTkaiFeatureToggles, 30);
        if (t && t.dataset.setting === 'tkaiAutosaveEnabled') setTimeout(initTkaiAutosave, 10);
    });
    document.getElementById('settingsPanel')?.addEventListener('input', e => {
        const t = e.target.closest('[data-setting]');
        if (!t || !t.dataset.setting) return;
        if (t.dataset.setting.startsWith('tkaiBtnColor') || t.dataset.setting === 'tkaiUiScale' || t.dataset.setting === 'tkaiFontScale') {
            setTimeout(applyTkaiButtonTheme, 10);
        }
        if (t.dataset.setting === 'tkaiAutosaveSeconds') {
            setTimeout(initTkaiAutosave, 10);
        }
        if (t.dataset.setting === 'tkaiGiftGalleryTitle') {
            const el = document.getElementById('tkaiGiftGalleryHeaderTitle');
            if (el) el.textContent = t.value.trim() || '🎁 Gift Galerija';
        }
    });
    applyTkaiFeatureToggles();
    applyTkaiButtonTheme();
    initInsightCardControls();

    // ── Gift gallery Sakrij/Prikaži ──────────────────────────────────────
    let giftGalleryVisible = true;
    giftToggleBtn?.addEventListener('click', () => {
        giftGalleryVisible = !giftGalleryVisible;
        const galleryEl = document.getElementById('tkaiGiftGallery');
        if (galleryEl) galleryEl.style.display = giftGalleryVisible ? '' : 'none';
        giftToggleBtn.textContent = giftGalleryVisible ? 'Sakrij' : 'Prikaži';
    });

    const tkaiMinBtn = document.getElementById('minimizeTiktokAIPanel');
    const TKAI_MIN_KEY = 'ex_tkai_panel_minimized';
    const applyTkaiMinimized = (minimized) => {
        panel.classList.toggle('tkai-minimized', !!minimized);
        if (tkaiMinBtn) {
            tkaiMinBtn.textContent = minimized ? '▢' : '−';
            tkaiMinBtn.title = minimized ? 'Proširi' : 'Spusti / proširi';
        }
    };
    // Always open expanded so the panel remains easy to control.
    applyTkaiMinimized(false);
    try { localStorage.removeItem(TKAI_MIN_KEY); } catch (_) { }
    tkaiMinBtn?.addEventListener('click', (e) => {
        e.stopPropagation();
        const next = !panel.classList.contains('tkai-minimized');
        applyTkaiMinimized(next);
        try { localStorage.setItem(TKAI_MIN_KEY, next ? '1' : '0'); } catch (_) { }
    });

    document.getElementById('closeTiktokAIPanel')?.addEventListener('click', stopScanning);
    document.addEventListener('keydown', onTikTokHoldLShortcut);
    updateHoldLButton();
    updateInsightsUI();
    if (holdLActive) startHoldL().catch(() => { });

    // ── TikTok AI panel move/resize ──────────────────────────────────────────
    (function initTikTokPanelMoveResize() {
        const dragHandle = document.getElementById('tiktokAIPanelHeader');
        if (!dragHandle || !panel || panel.dataset.moveResizeReady === '1') return;
        panel.dataset.moveResizeReady = '1';

        const MIN_W = 360;
        const MIN_H = 340;
        const DEFAULT_W = 460;
        const DEFAULT_H = 580;
        let activeOp = null;

        function getBounds(width, height) {
            const topBoundary = getPanelTopBoundary();
            const maxW = Math.max(MIN_W, window.innerWidth - 12);
            const maxH = Math.max(MIN_H, window.innerHeight - topBoundary - 8);
            const w = Math.max(MIN_W, Math.min(Number(width) || DEFAULT_W, maxW));
            const h = Math.max(MIN_H, Math.min(Number(height) || Math.min(DEFAULT_H, maxH), maxH));
            return {
                topBoundary,
                width: w,
                height: h,
                maxLeft: Math.max(0, window.innerWidth - w - 6),
                maxTop: Math.max(topBoundary, window.innerHeight - h - 6),
            };
        }

        function applyLayout(left, top, width, height) {
            const bounds = getBounds(width, height);
            const x = Math.max(0, Math.min(Number(left) || 0, bounds.maxLeft));
            const y = Math.max(bounds.topBoundary, Math.min(Number(top) || bounds.topBoundary, bounds.maxTop));
            panel.style.right = 'auto';
            panel.style.top = 'auto';
            panel.style.left = x + 'px';
            panel.style.bottom = Math.max(0, window.innerHeight - y - bounds.height) + 'px';
            panel.style.width = bounds.width + 'px';
            panel.style.height = bounds.height + 'px';
            return { left: x, top: y, width: bounds.width, height: bounds.height };
        }

        function currentLayout() {
            const rect = panel.getBoundingClientRect();
            return {
                left: rect.left,
                top: rect.top,
                width: rect.width || panel.offsetWidth || DEFAULT_W,
                height: rect.height || panel.offsetHeight || DEFAULT_H,
            };
        }

        function saveLayoutNow() {
            const rect = panel.getBoundingClientRect();
            const layout = clampTkaiPanelLayout({
                left: rect.left,
                bottom: window.innerHeight - rect.bottom,
                width: rect.width || panel.offsetWidth,
                height: rect.height || panel.offsetHeight,
            });
            try {
                localStorage.setItem(TKAI_PANEL_LAYOUT_KEY, JSON.stringify(layout));
                localStorage.setItem('ex_tkai_panel_pos', JSON.stringify({ left: layout.left, bottom: layout.bottom }));
                localStorage.setItem('ex_tkai_panel_size', JSON.stringify({ width: layout.width, height: layout.height }));
            } catch (_) { }
        }

        function resetPanelLayout() {
            const bounds = getBounds(DEFAULT_W, DEFAULT_H);
            const left = Math.max(0, window.innerWidth - bounds.width - 8);
            const top = Math.max(bounds.topBoundary, window.innerHeight - bounds.height - 10);
            panel.style.transition = 'left .16s ease, bottom .16s ease, width .16s ease, height .16s ease';
            applyLayout(left, top, bounds.width, bounds.height);
            try {
                localStorage.removeItem(TKAI_PANEL_LAYOUT_KEY);
                localStorage.removeItem('ex_tkai_panel_pos');
                localStorage.removeItem('ex_tkai_panel_size');
            } catch (_) { }
            setTimeout(() => { panel.style.transition = 'none'; }, 180);
        }

        function beginPointerOp(event, mode, dir = '') {
            if (event.button != null && event.button !== 0) return;
            if (mode === 'move' && event.target.closest('button, select, input, textarea, a')) return;
            const start = currentLayout();
            activeOp = {
                mode,
                dir,
                pointerId: event.pointerId,
                startX: event.clientX,
                startY: event.clientY,
                start,
            };
            panel.classList.add(mode === 'move' ? 'tkai-panel-moving' : 'tkai-panel-resizing');
            panel.style.transition = 'none';
            document.body.classList.add('tkai-panel-interacting');
            try { event.currentTarget.setPointerCapture?.(event.pointerId); } catch (_) { }
            event.preventDefault();
            event.stopPropagation();
        }

        function movePointerOp(event) {
            if (!activeOp) return;
            const dx = event.clientX - activeOp.startX;
            const dy = event.clientY - activeOp.startY;
            const s = activeOp.start;
            if (activeOp.mode === 'move') {
                applyLayout(s.left + dx, s.top + dy, s.width, s.height);
                event.preventDefault();
                return;
            }

            let left = s.left;
            let top = s.top;
            let width = s.width;
            let height = s.height;
            if (activeOp.dir.includes('e')) width = s.width + dx;
            if (activeOp.dir.includes('s')) height = s.height + dy;
            if (activeOp.dir.includes('w')) {
                width = s.width - dx;
                left = s.left + dx;
            }
            if (activeOp.dir.includes('n')) {
                height = s.height - dy;
                top = s.top + dy;
            }

            const bounds = getBounds(width, height);
            if (activeOp.dir.includes('w') && bounds.width === MIN_W) left = s.left + s.width - MIN_W;
            if (activeOp.dir.includes('n') && bounds.height === MIN_H) top = s.top + s.height - MIN_H;
            applyLayout(left, top, bounds.width, bounds.height);
            event.preventDefault();
        }

        function endPointerOp(event) {
            if (!activeOp) return;
            if (event?.pointerId != null && activeOp.pointerId !== event.pointerId) return;
            panel.classList.remove('tkai-panel-moving', 'tkai-panel-resizing');
            document.body.classList.remove('tkai-panel-interacting');
            activeOp = null;
            saveLayoutNow();
        }

        dragHandle.addEventListener('pointerdown', (event) => beginPointerOp(event, 'move'));
        dragHandle.addEventListener('dblclick', (event) => {
            if (event.target.closest('button, select, input, textarea, a')) return;
            resetPanelLayout();
        });

        ['n', 's', 'e', 'w', 'ne', 'nw', 'se', 'sw'].forEach((dir) => {
            let handle = panel.querySelector('.tkai-resize-' + dir);
            if (!handle) {
                handle = document.createElement('div');
                handle.className = 'tkai-resize-handle tkai-resize-' + dir;
                panel.appendChild(handle);
            }
            handle.addEventListener('pointerdown', (event) => beginPointerOp(event, 'resize', dir));
        });

        document.addEventListener('pointermove', movePointerOp);
        document.addEventListener('pointerup', endPointerOp);
        document.addEventListener('pointercancel', endPointerOp);
        window.addEventListener('blur', endPointerOp);
        window.addEventListener('resize', () => {
            const cur = currentLayout();
            applyLayout(cur.left, cur.top, cur.width, cur.height);
            saveLayoutNow();
        });

        if (!restoreTikTokPanelLayout()) {
            const cur = currentLayout();
            applyLayout(cur.left, cur.top, cur.width, cur.height);
        }
    })();
    function renderBookmarksPanel() {
        const list = document.getElementById('bmList'); const bm = DB.getBookmarks();
        if (bm.length === 0) { list.innerHTML = '<div style="text-align:center;padding:32px;color:var(--text3);font-size:12px">No bookmarks yet<br><br>Press Ctrl+D to bookmark the current page</div>'; return; }
        list.innerHTML = '';
        // Toolbar: New Folder button
        const toolbar = document.createElement('div');
        toolbar.style.cssText = 'display:flex;gap:6px;padding:4px 8px;border-bottom:1px solid var(--border)';
        toolbar.innerHTML = '<button id="bmAddFolder" style="background:var(--bg3);border:1px solid var(--border2);border-radius:4px;color:var(--text2);padding:2px 8px;cursor:pointer;font-size:11px">📁 New Folder</button>';
        list.appendChild(toolbar);
        toolbar.querySelector('#bmAddFolder').addEventListener('click', async () => {
            const name = await showPrompt('Folder name:');
            if (name && name.trim()) { DB.createBookmarkFolder(name.trim()); renderBookmarksPanel(); }
        });
        // Group by folder
        const folders = DB.getBookmarkFolderList();
        const unfiled = bm.filter(b => !b.folder);
        // Render folders
        folders.forEach(folder => {
            const folderBm = bm.filter(b => b.folder === folder);
            const fDiv = document.createElement('div');
            fDiv.style.cssText = 'margin-top:4px';
            const fHeader = document.createElement('div');
            fHeader.style.cssText = 'display:flex;align-items:center;padding:4px 8px;cursor:pointer;color:var(--text2);font-size:12px;gap:4px;background:var(--bg2);border-radius:4px;margin:2px 4px';
            fHeader.innerHTML = `<span>📁</span><span style="flex:1">${folder} (${folderBm.length})</span><button class="bm-del-folder" style="background:none;border:none;color:var(--text3);cursor:pointer;font-size:11px" title="Delete folder">×</button>`;
            fHeader.querySelector('.bm-del-folder').addEventListener('click', e => { e.stopPropagation(); if (confirm('Delete folder "' + folder + '"? Bookmarks will be moved to root.')) { DB.deleteBookmarkFolder(folder); renderBookmarksPanel(); } });
            const fBody = document.createElement('div');
            fBody.style.cssText = 'display:none;padding-left:12px';
            fHeader.addEventListener('click', () => { fBody.style.display = fBody.style.display === 'none' ? 'block' : 'none'; });
            folderBm.forEach(b => fBody.appendChild(_createBmEntry(b)));
            fDiv.appendChild(fHeader);
            fDiv.appendChild(fBody);
            list.appendChild(fDiv);
        });
        // Render unfiled bookmarks
        if (unfiled.length) {
            const title = document.createElement('div'); title.className = 'p-section-title'; title.textContent = 'Bookmarks'; list.appendChild(title);
            unfiled.forEach(b => list.appendChild(_createBmEntry(b)));
        }
    }
    function _createBmEntry(b) {
        const el = document.createElement('div'); el.className = 'p-entry';
        el.innerHTML = `<div class="p-entry-icon">🌐</div><div class="p-entry-title" title="${b.url}">${b.title || b.url}</div><div class="p-entry-meta">${timeAgo(b.ts)}</div><button class="p-entry-move" title="Move to folder" style="background:none;border:none;color:var(--text3);cursor:pointer;font-size:10px;margin-right:4px">📁</button><button class="p-entry-del">×</button>`;
        el.querySelector('.p-entry-title').addEventListener('click', () => { navigateTo(b.url); closeAllPanels(); });
        el.querySelector('.p-entry-del').addEventListener('click', e => { e.stopPropagation(); DB.removeBookmark(b.url); renderBookmarksPanel(); });
        el.querySelector('.p-entry-move').addEventListener('click', async e => {
            e.stopPropagation();
            const folders = DB.getBookmarkFolderList();
            if (folders.length === 0) { showToast('Create a folder first'); return; }
            const choice = await showPrompt('Move to folder:\\n' + folders.map((f, i) => (i + 1) + '. ' + f).join('\\n') + '\\n\\nEnter folder name or number:');
            if (!choice) return;
            const target = folders[parseInt(choice) - 1] || choice;
            DB.updateBookmark(b.url, { folder: target });
            renderBookmarksPanel();
            showToast('Moved to 📁 ' + target);
        });
        return el;
    }
    function renderHistoryPanel() {
        const list = document.getElementById('histList'); const hist = DB.getHistory();
        if (hist.length === 0) { list.innerHTML = '<div style="text-align:center;padding:32px;color:var(--text3);font-size:12px">No history yet</div>'; return; }
        list.innerHTML = '';
        const groups = {}; hist.forEach(h => { const d = new Date(h.ts).toDateString(); (groups[d] = groups[d] || []).push(h); });
        Object.entries(groups).forEach(([day, entries]) => {
            const t = document.createElement('div'); t.className = 'p-section-title'; t.textContent = new Date(entries[0].ts).toDateString() === new Date().toDateString() ? 'Today' : day; list.appendChild(t);
            entries.forEach(h => {
                const el = document.createElement('div'); el.className = 'p-entry';
                el.innerHTML = `<div class="p-entry-icon">🌐</div><div class="p-entry-title" title="${h.url}">${h.title || h.url}</div><div class="p-entry-meta">${new Date(h.ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>`;
                el.addEventListener('click', () => { navigateTo(h.url); closeAllPanels(); }); list.appendChild(el);
            });
        });
    }
    // Expose panel renderers globally so callers outside this IIFE can access them
    window.renderBookmarksPanel = renderBookmarksPanel;
    window.renderHistoryPanel = renderHistoryPanel;
    document.getElementById('clearHistBtn').addEventListener('click', () => { DB.clearHistory(); renderHistoryPanel(); showToast('History cleared'); });

    // ── Downloads Panel Renderer ──────────────────────────────────────────────
    // In-memory map of active downloads (id → data) for live progress updates
    const _activeDownloads = new Map();

    function _fmtBytes(b) {
        if (!b || b <= 0) return '';
        if (b >= 1073741824) return (b / 1073741824).toFixed(2) + ' GB';
        if (b >= 1048576) return (b / 1048576).toFixed(1) + ' MB';
        if (b >= 1024) return (b / 1024).toFixed(0) + ' KB';
        return b + ' B';
    }

    function _dlStatusIcon(status) {
        if (status === 'completed') return '✅';
        if (status === 'failed' || status === 'cancelled') return '❌';
        if (status === 'paused') return '⏸️';
        if (status === 'progressing' || status === 'started') return '⏬';
        return '⬇️';
    }

    function renderDownloadsPanel() {
        const list = document.getElementById('dlList');
        // Merge DB downloads with in-memory active ones (active overrides DB for same id)
        const dbDownloads = DB.getDownloads();
        const merged = new Map();
        dbDownloads.forEach(d => merged.set(d.id, d));
        _activeDownloads.forEach((d, id) => merged.set(id, { ...merged.get(id), ...d }));
        const downloads = [...merged.values()].sort((a, b) => (b.ts || 0) - (a.ts || 0));

        if (downloads.length === 0) {
            list.innerHTML = '<div style="text-align:center;padding:32px;color:var(--text3);font-size:12px">⬇️ Nema preuzimanja</div>';
            return;
        }
        list.innerHTML = '';
        downloads.forEach(d => {
            const el = document.createElement('div');
            el.className = 'p-entry';
            el.style.cssText = 'flex-direction:column;align-items:stretch;gap:0;padding:8px 10px;';
            el.dataset.dlid = d.id;

            const fname = d.filename || d.url?.split('/').pop()?.split('?')[0] || 'download';
            const isActive = d.status === 'progressing' || d.status === 'started';
            const isDone = d.status === 'completed';
            const isFailed = d.status === 'failed' || d.status === 'cancelled';
            const hasSavePath = !!(d.savePath);

            // Progress
            const pct = (d.totalBytes > 0) ? Math.round((d.receivedBytes / d.totalBytes) * 100) : (isDone ? 100 : 0);
            const recvStr = _fmtBytes(d.receivedBytes);
            const totalStr = _fmtBytes(d.totalBytes);
            const sizeStr = isDone ? totalStr : (recvStr && totalStr ? recvStr + ' / ' + totalStr : recvStr || totalStr || '');

            // Top row: icon + name + delete
            const topRow = document.createElement('div');
            topRow.style.cssText = 'display:flex;align-items:center;gap:6px;';
            topRow.innerHTML = `
          <span style="font-size:14px">${_dlStatusIcon(d.status)}</span>
          <span class="dl-fname" title="${escHtml(d.url || '')}" style="flex:1;font-size:12px;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;cursor:pointer">${escHtml(fname)}</span>
          <span style="font-size:10px;color:var(--text3);white-space:nowrap">${timeAgo(d.ts)}</span>
          <button class="p-entry-del" style="flex-shrink:0">×</button>
        `;
            el.appendChild(topRow);

            // Progress bar (samo za aktivne ili ako imamo postotak)
            if (isActive || (pct > 0 && pct < 100)) {
                const barWrap = document.createElement('div');
                barWrap.style.cssText = 'margin-top:5px;background:var(--bg3);border-radius:3px;height:4px;overflow:hidden;';
                const bar = document.createElement('div');
                bar.className = 'dl-progress-bar';
                bar.style.cssText = `height:100%;background:var(--accent);border-radius:3px;width:${pct}%;transition:width .3s;`;
                barWrap.appendChild(bar);
                el.appendChild(barWrap);
            }

            // Meta row: size + action buttons
            const metaRow = document.createElement('div');
            metaRow.style.cssText = 'display:flex;align-items:center;gap:4px;margin-top:4px;';
            let metaHTML = `<span style="font-size:10px;color:var(--text3);flex:1">${escHtml(sizeStr)}`;
            if (isActive && pct > 0) metaHTML += ` &mdash; ${pct}%`;
            metaHTML += `</span>`;

            // Action buttons — only in Electron where savePath is available
            if (isDone && hasSavePath) {
                metaHTML += `
            <button class="dl-btn-open" title="Otvori fajl" style="background:var(--bg3);border:1px solid var(--border2);border-radius:4px;color:var(--text2);cursor:pointer;font-size:10px;padding:1px 7px">▶ Otvori</button>
            <button class="dl-btn-folder" title="Prikaži u folderu" style="background:var(--bg3);border:1px solid var(--border2);border-radius:4px;color:var(--text2);cursor:pointer;font-size:10px;padding:1px 7px">📂 Folder</button>
          `;
            } else if (!isDone && !isFailed) {
                // Show URL as clickable
                metaHTML += `<span style="font-size:10px;color:var(--text3);max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;cursor:pointer" class="dl-url-lnk" title="${escHtml(d.url || '')}">${escHtml((d.url || '').replace(/^https?:\/\//, '').slice(0, 40))}</span>`;
            }
            metaRow.innerHTML = metaHTML;
            el.appendChild(metaRow);

            // Events
            topRow.querySelector('.dl-fname').addEventListener('click', () => { if (d.url) navigateTo(d.url); });
            el.querySelector('.p-entry-del').addEventListener('click', ev => {
                ev.stopPropagation();
                _activeDownloads.delete(d.id);
                DB.deleteDownload(d.id);
                renderDownloadsPanel();
                _updateDlBadge();
            });
            if (isDone && hasSavePath) {
                metaRow.querySelector('.dl-btn-open')?.addEventListener('click', ev => {
                    ev.stopPropagation();
                    window.etherx?.shell?.openPath(d.savePath).catch?.(() => { });
                });
                metaRow.querySelector('.dl-btn-folder')?.addEventListener('click', ev => {
                    ev.stopPropagation();
                    window.etherx?.shell?.showItemInFolder(d.savePath).catch?.(() => { });
                });
            }
            metaRow.querySelector('.dl-url-lnk')?.addEventListener('click', ev => {
                ev.stopPropagation();
                if (d.url) navigateTo(d.url);
            });

            list.appendChild(el);
        });
    }

    function _updateDlBadge() {
        const activeCount = [..._activeDownloads.values()].filter(d => d.status === 'progressing' || d.status === 'started').length;
        let badge = document.getElementById('dlBadge');
        const btn = document.getElementById('btnDownloads');
        if (!btn) return;
        if (activeCount > 0) {
            if (!badge) {
                badge = document.createElement('span');
                badge.id = 'dlBadge';
                badge.style.cssText = 'position:absolute;top:0;right:0;background:var(--accent);color:#fff;border-radius:8px;font-size:8px;font-weight:700;padding:1px 4px;pointer-events:none;line-height:1.4';
                btn.style.position = 'relative';
                btn.appendChild(badge);
            }
            badge.textContent = activeCount;
        } else {
            badge?.remove();
        }
    }

    function openDownloadsPanelWithRefresh() {
        renderDownloadsPanel();
        const panel = document.getElementById('dlPanel');
        if (panel && !panel.classList.contains('open')) {
            closeAllPanels();
            panel.classList.add('open');
        }
    }

    document.getElementById('dlClearAll')?.addEventListener('click', () => {
        _activeDownloads.clear();
        DB.clearDownloads();
        renderDownloadsPanel();
        _updateDlBadge();
        showToast('Preuzimanja obrisana');
    });

    document.getElementById('dlOpenFolder')?.addEventListener('click', async () => {
        if (window.etherx?.shell) {
            // Try to open the most recent download's folder, or default downloads dir
            const recent = DB.getDownloads().find(d => d.savePath);
            if (recent?.savePath) {
                window.etherx.shell.showItemInFolder(recent.savePath);
            } else {
                // Resolve downloads folder via IPC then open it
                const dlPath = await window.etherx.app?.getDownloadsPath?.().catch(() => null);
                if (dlPath) window.etherx.shell.openPath(dlPath);
                else showToast('⚠️ Nema preuzetih datoteka');
            }
        } else {
            showToast('Dostupno samo u Electron verziji');
        }
    });

    document.getElementById('btnDownloads').addEventListener('click', () => { renderDownloadsPanel(); togglePanel('dlPanel'); });

    if (window.etherx?.on) {
        window.etherx.on('download-update', (download) => {
            if (!download?.id) return;
            if (download.status === 'completed' || download.status === 'failed' || download.status === 'cancelled') {
                _activeDownloads.delete(download.id);
                DB.upsertDownload(download);
            } else {
                // Keep active in memory for live progress
                _activeDownloads.set(download.id, download);
            }
            // Auto-open panel on first start
            if (download.status === 'started') {
                openDownloadsPanelWithRefresh();
                showToast('⬇️ Preuzimanje započeto: ' + (download.filename || ''));
            }
            // Show completion toast
            if (download.status === 'completed') {
                showToast('✅ Preuzeto: ' + (download.filename || ''));
                openDownloadsPanelWithRefresh();
            }
            if (download.status === 'failed') {
                showToast('❌ Preuzimanje nije uspjelo: ' + (download.filename || ''));
            }
            // Live update existing entry if panel is open
            const panel = document.getElementById('dlPanel');
            if (panel?.classList.contains('open')) {
                // Try to update just the progress bar without full re-render
                const entryEl = document.querySelector(`[data-dlid="${download.id}"]`);
                if (entryEl) {
                    const pct = (download.totalBytes > 0) ? Math.round((download.receivedBytes / download.totalBytes) * 100) : 0;
                    const bar = entryEl.querySelector('.dl-progress-bar');
                    if (bar) bar.style.width = pct + '%';
                    const recvStr = _fmtBytes(download.receivedBytes);
                    const totalStr = _fmtBytes(download.totalBytes);
                    const metaSpan = entryEl.querySelector('span[style*="flex:1"]');
                    if (metaSpan) metaSpan.textContent = (recvStr && totalStr ? recvStr + ' / ' + totalStr : recvStr || '') + (pct > 0 ? ' — ' + pct + '%' : '');
                } else {
                    renderDownloadsPanel();
                }
            }
            _updateDlBadge();
        });
    }

    // ── Bot Detection System ──────────────────────────────────────────────────────
    function runBotDetectionTests() {
        const resultsContainer = document.getElementById('botDetectResults');
        const scoreEl = document.getElementById('botDetectScore');
        const scoreBarEl = document.getElementById('botDetectScoreBar');
        const verdictEl = document.getElementById('botDetectVerdict');

        resultsContainer.innerHTML = '<div style="text-align:center;color:var(--text2);padding:20px">Running tests...</div>';

        setTimeout(() => {
            const tests = [
                { name: 'WebDriver Detection', test: testWebDriver, weight: 20 },
                { name: 'Automation Tools', test: testAutomation, weight: 20 },
                { name: 'Headless Detection', test: testHeadless, weight: 15 },
                { name: 'Plugins Check', test: testPlugins, weight: 10 },
                { name: 'Canvas Fingerprint', test: testCanvas, weight: 10 },
                { name: 'Screen Consistency', test: testScreen, weight: 10 },
                { name: 'Languages Check', test: testLanguages, weight: 5 },
                { name: 'Hardware Info', test: testHardware, weight: 5 },
                { name: 'Chrome Properties', test: testChrome, weight: 5 }
            ];

            let totalScore = 0;
            let maxScore = 0;
            const results = [];

            tests.forEach(({ name, test, weight }) => {
                const result = test();
                results.push({ name, ...result, weight });
                if (result.passed) totalScore += weight;
                maxScore += weight;
            });

            const percentage = Math.round((totalScore / maxScore) * 100);

            // Update score display
            scoreEl.textContent = percentage;
            scoreBarEl.style.width = percentage + '%';

            // Color code based on score
            let color, verdict;
            if (percentage >= 80) {
                color = '#4ade80';
                scoreBarEl.style.background = 'linear-gradient(90deg,#4ade80,#22c55e)';
                verdict = '✅ Human-like behavior detected';
            } else if (percentage >= 50) {
                color = '#facc15';
                scoreBarEl.style.background = 'linear-gradient(90deg,#facc15,#eab308)';
                verdict = '⚠️ Suspicious patterns detected';
            } else {
                color = '#f87171';
                scoreBarEl.style.background = 'linear-gradient(90deg,#f87171,#ef4444)';
                verdict = '🚫 Bot-like behavior detected';
            }

            scoreEl.style.color = color;
            verdictEl.textContent = verdict;

            // Render results
            resultsContainer.innerHTML = results.map(r => `
          <div style="background:rgba(255,255,255,.05);border-radius:6px;padding:10px">
            <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px">
              <span style="font-size:13px;font-weight:600;color:var(--text)">${r.name}</span>
              <span style="font-size:12px;padding:2px 8px;border-radius:12px;background:${r.passed ? 'rgba(74,222,128,.2)' : 'rgba(248,113,113,.2)'};color:${r.passed ? '#4ade80' : '#f87171'}">${r.passed ? '✓ Pass' : '✗ Fail'}</span>
            </div>
            <div style="font-size:12px;color:var(--text2);line-height:1.4">${r.detail}</div>
          </div>
        `).join('');
        }, 100);
    }

    // Bot detection test functions
    function testWebDriver() {
        const detected = navigator.webdriver === true;
        return {
            passed: !detected,
            detail: detected ? 'navigator.webdriver is true (automation detected)' : 'No webdriver property detected'
        };
    }

    function testAutomation() {
        const checks = {
            phantom: window.callPhantom || window._phantom,
            puppeteer: window.document.__playwright || window.document.__puppeteer,
            domAutomation: window.domAutomation || window.domAutomationController,
            nightmare: window.__nightmare
        };

        const detected = Object.keys(checks).filter(k => checks[k]);
        return {
            passed: detected.length === 0,
            detail: detected.length > 0 ? `Detected: ${detected.join(', ')}` : 'No automation tools detected'
        };
    }

    function testHeadless() {
        const ua = navigator.userAgent;
        const headlessUA = /HeadlessChrome|PhantomJS/i.test(ua);
        const noVendor = !navigator.vendor || navigator.vendor === '';
        const isHeadless = headlessUA || noVendor;

        return {
            passed: !isHeadless,
            detail: isHeadless ? (headlessUA ? 'Headless browser detected in User-Agent' : 'Missing browser vendor') : 'Normal browser detected'
        };
    }

    function testPlugins() {
        const pluginCount = navigator.plugins?.length || 0;
        const passed = pluginCount > 0;

        return {
            passed,
            detail: passed ? `${pluginCount} plugins detected (normal)` : 'No plugins detected (suspicious for bot)'
        };
    }

    function testCanvas() {
        try {
            const canvas = document.createElement('canvas');
            const ctx = canvas.getContext('2d');
            ctx.textBaseline = 'top';
            ctx.font = '14px Arial';
            ctx.fillText('EtherX Test 🤖', 2, 2);
            const hash = canvas.toDataURL();
            const passed = hash && hash.length > 100;

            return {
                passed,
                detail: passed ? 'Canvas fingerprint generated successfully' : 'Canvas fingerprinting blocked or failed'
            };
        } catch (e) {
            return { passed: false, detail: 'Canvas test error: ' + e.message };
        }
    }

    function testScreen() {
        const screenW = screen.width;
        const screenH = screen.height;
        const windowW = window.innerWidth;
        const windowH = window.innerHeight;
        const avail = screen.availWidth;

        const mismatch = screenW < windowW || screenH < windowH || avail === 0;

        return {
            passed: !mismatch,
            detail: mismatch ? `Screen/window size mismatch (${screenW}x${screenH} vs ${windowW}x${windowH})` : `Screen: ${screenW}x${screenH}, Window: ${windowW}x${windowH}`
        };
    }

    function testLanguages() {
        const langs = navigator.languages || [];
        const langCount = langs.length;
        const passed = langCount > 0;

        return {
            passed,
            detail: passed ? `${langCount} language(s): ${langs.slice(0, 3).join(', ')}` : 'No languages detected'
        };
    }

    function testHardware() {
        const cores = navigator.hardwareConcurrency || 0;
        const passed = cores > 0 && cores <= 64;

        return {
            passed,
            detail: passed ? `${cores} CPU cores detected` : cores === 0 ? 'No CPU cores reported' : 'Unusual CPU core count'
        };
    }

    function testChrome() {
        const hasChrome = !!window.chrome;
        const hasRuntime = hasChrome && typeof window.chrome.runtime !== 'undefined';

        return {
            passed: hasChrome,
            detail: hasChrome ? (hasRuntime ? 'Chrome/Chromium detected with runtime' : 'Chrome detected') : 'No Chrome object detected'
        };
    }

    /* toggle handlers moved to initSettingsPanel() — removed duplicate */
    document.getElementById('btnDevtools').addEventListener('click', toggleDevtools);
    document.getElementById('btnBotDetection').addEventListener('click', () => togglePanel('botDetectionPanel'));
    document.getElementById('botDetectRunAll').addEventListener('click', runBotDetectionTests);

    // ── EtherX Shield Panel ────────────────────────────────────────────────────
