    // ── DevTools tab switching
    document.querySelectorAll('.dt-tab').forEach(tab => {
        tab.addEventListener('click', () => {
            document.querySelectorAll('.dt-tab').forEach(t => t.classList.remove('active'));
            document.querySelectorAll('.dt-pane').forEach(p => p.classList.remove('active'));
            tab.classList.add('active');
            const pane = document.getElementById('pane-' + tab.dataset.pane);
            if (pane) pane.classList.add('active');
            if (!STATE.devtoolsOpen) { STATE.devtoolsOpen = true; document.getElementById('devtools').classList.add('open'); }
            if (tab.dataset.pane === 'application') renderAppTab('localstorage');
            if (tab.dataset.pane === 'network') _flushNetBuffer();
            if (tab.dataset.pane === 'performance') collectPerfMetrics();
        });
    });

    // ── Resize handle
    (function () {
        const handle = document.getElementById('dtResize');
        const dt = document.getElementById('devtools');
        if (!handle || !dt) return;
        let dragging = false, startY = 0, startH = 0;
        handle.addEventListener('mousedown', e => { dragging = true; startY = e.clientY; startH = dt.offsetHeight; document.body.style.cursor = 'ns-resize'; e.preventDefault(); });
        document.addEventListener('mousemove', e => { if (!dragging) return; const delta = startY - e.clientY; dt.style.height = Math.min(Math.max(startH + delta, 120), window.innerHeight * 0.85) + 'px'; });
        document.addEventListener('mouseup', () => { if (dragging) { dragging = false; document.body.style.cursor = ''; } });
    })();

    // ── Console engine
    const consoleOutput = document.getElementById('consoleOutput');
    let dtErrCount = 0, dtWarnCount = 0;
    const DEVTOOLS_CONSOLE_CLOSED_CAPTURE_KEY = 'devtoolsConsoleCaptureWhenClosed';
    const DEVTOOLS_CONSOLE_MAX_LINES = 400;
    function updateDtBadges() {
        const eb = document.getElementById('dtErrBadge'); const wb = document.getElementById('dtWarnBadge');
        if (eb) eb.textContent = dtErrCount || ''; if (wb) wb.textContent = dtWarnCount || '';
    }
    let _conFilterTimer = null;
    function shouldMirrorConsoleWhenClosed() {
        try {
            const value = DB.getSettings()?.[DEVTOOLS_CONSOLE_CLOSED_CAPTURE_KEY];
            return value === true || value === 'true';
        } catch (_) {
            return false;
        }
    }
    function shouldCaptureConsoleDom() {
        return !!STATE.devtoolsOpen || shouldMirrorConsoleWhenClosed();
    }
    function stringifyConsoleArgs(args) {
        return args.map(a => {
            if (a instanceof Error) return a.message || String(a);
            if (typeof a === 'object') {
                try { return JSON.stringify(a); } catch (_) { return String(a); }
            }
            return String(a);
        }).join(' ');
    }
    function consoleLog(type, msg, src) {
        try {
            if (!consoleOutput) return;
            if (!shouldCaptureConsoleDom()) {
                if (type === 'error') { dtErrCount++; updateDtBadges(); }
                if (type === 'warn') { dtWarnCount++; updateDtBadges(); }
                return;
            }
            const line = document.createElement('div'); line.className = 'cl ' + type;
            const time = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
            const srcHtml = src ? `<span class="csrc">${escHtml(String(src))}</span>` : '';
            const icon = type === 'error' ? '⊗ ' : type === 'warn' ? '⚠ ' : type === 'info' ? 'ℹ ' : type === 'success' ? '✓ ' : type === 'verbose' ? '· ' : '';
            const safeMsg = typeof msg === 'string' ? msg : String(msg || '');
            line.innerHTML = `<span class="cp">${time}</span><span class="cm">${icon}${safeMsg}</span>${srcHtml}`;
            consoleOutput.appendChild(line); consoleOutput.scrollTop = consoleOutput.scrollHeight;
            while (consoleOutput.children.length > DEVTOOLS_CONSOLE_MAX_LINES) {
                consoleOutput.removeChild(consoleOutput.firstElementChild);
            }
            if (type === 'error') { dtErrCount++; updateDtBadges(); }
            if (type === 'warn') { dtWarnCount++; updateDtBadges(); }
            if (!_conFilterTimer) { _conFilterTimer = setTimeout(() => { _conFilterTimer = null; applyConsoleFilter(); }, 150); }
        } catch (e) { /* prevent recursion */ }
    }
    globalThis.__etherxConsoleLogImpl = consoleLog;

    // ── Hook browser console & errors ────────────────────────────────────────
    (function hookBrowserConsole() {
        const origLog = console.log, origWarn = console.warn, origError = console.error, origInfo = console.info;
        console.log = function (...args) { if (shouldCaptureConsoleDom()) consoleLog('log', stringifyConsoleArgs(args), 'index.html'); origLog.apply(console, args); };
        console.warn = function (...args) { if (shouldCaptureConsoleDom()) consoleLog('warn', stringifyConsoleArgs(args), 'index.html'); origWarn.apply(console, args); };
        console.error = function (...args) {
            const msg = stringifyConsoleArgs(args);
            // Silence Electron-internal ERR_ABORTED (-3) which is normal during navigation
            if (msg.includes('ERR_ABORTED (-3)')) { origError.apply(console, args); return; }
            if (shouldCaptureConsoleDom()) consoleLog('error', msg, 'index.html');
            origError.apply(console, args);
        };
        console.info = function (...args) { if (shouldCaptureConsoleDom()) consoleLog('info', stringifyConsoleArgs(args), 'index.html'); origInfo.apply(console, args); };

        // Global error handler
        window.addEventListener('error', e => {
            // Suppress Electron's internal webview dom-ready guard error — the prototype
            // patch in the electronWebview block handles it gracefully at the JS level.
            if (e.message && e.message.includes('WebView must be attached')) return;
            consoleLog('error', `${e.message} at ${e.filename}:${e.lineno}:${e.colno}`, e.filename || 'index.html');
        });
        window.addEventListener('unhandledrejection', e => {
            consoleLog('error', 'Unhandled Promise Rejection: ' + (e.reason?.message || e.reason || 'Unknown'), 'Promise');
        });

        // Try to hook iframe console
        function hookFrameConsole() {
            if (!shouldCaptureConsoleDom()) return;
            const fr = document.getElementById('browseFrame');
            if (!fr) return;
            try {
                const win = fr.contentWindow;
                if (!win) return;
                const origFLog = win.console.log, origFWarn = win.console.warn, origFError = win.console.error;
                win.console.log = function (...args) { if (shouldCaptureConsoleDom()) consoleLog('log', stringifyConsoleArgs(args), 'page'); origFLog.apply(win.console, args); };
                win.console.warn = function (...args) { if (shouldCaptureConsoleDom()) consoleLog('warn', stringifyConsoleArgs(args), 'page'); origFWarn.apply(win.console, args); };
                win.console.error = function (...args) { if (shouldCaptureConsoleDom()) consoleLog('error', stringifyConsoleArgs(args), 'page'); origFError.apply(win.console, args); };
                win.addEventListener('error', e => consoleLog('error', `Page: ${e.message} at ${e.filename}:${e.lineno}`, 'page'));
                win.addEventListener('unhandledrejection', e => consoleLog('error', 'Page Promise Rejection: ' + (e.reason?.message || e.reason), 'page'));
            } catch (e) { /* cross-origin, can't hook */ }
        }
        const fr = document.getElementById('browseFrame');
        if (fr) {
            fr.addEventListener('load', () => setTimeout(hookFrameConsole, 100));
            fr.addEventListener('did-finish-load', () => setTimeout(hookFrameConsole, 100));
        }
    })();

    // ── Console input
    document.getElementById('consoleInput').addEventListener('keydown', e => {
        if (e.key !== 'Enter' || !e.target.value.trim()) return;
        const code = e.target.value;
        consoleLog('log', '<span style="color:#858585">❯ </span>' + escHtml(code), 'console');
        try { const r = eval(code); if (r !== undefined) consoleLog('info', '← ' + JSON.stringify(r, null, 1), '<eval>:1'); }
        catch (err) { consoleLog('error', err.message, '<eval>:1'); }
        e.target.value = '';
    });

    // ── Console filter
    let dtLevelFilter = { error: true, warn: true, info: true, log: true, verbose: true };
    let dtTextFilter = '';
    document.querySelectorAll('.con-lvl').forEach(btn => {
        btn.addEventListener('click', () => {
            const lvl = btn.dataset.lvl; dtLevelFilter[lvl] = !dtLevelFilter[lvl];
            btn.classList.toggle('on', dtLevelFilter[lvl]); applyConsoleFilter();
        });
    });
    const conFilterEl = document.getElementById('conFilter');
    if (conFilterEl) conFilterEl.addEventListener('input', e => { dtTextFilter = e.target.value.toLowerCase(); applyConsoleFilter(); });
    function applyConsoleFilter() {
        const els = consoleOutput ? consoleOutput.children : document.querySelectorAll('#consoleOutput .cl');
        for (let i = 0, len = els.length; i < len; i++) {
            const el = els[i];
            if (!el.classList.contains('cl')) continue;
            const cm = el.querySelector('.cm');
            const msg = cm ? cm.textContent.toLowerCase() : '';
            const type = el.classList.contains('error') ? 'error' : el.classList.contains('warn') ? 'warn' : el.classList.contains('info') ? 'info' : el.classList.contains('verbose') ? 'verbose' : 'log';
            const lvl = type === 'success' ? 'log' : type;
            el.style.display = (dtLevelFilter[lvl] !== false && (!dtTextFilter || msg.includes(dtTextFilter))) ? '' : 'none';
        }
    }

    // ── Clear console
    function clearConsole() {
        if (consoleOutput) consoleOutput.innerHTML = '';
        dtErrCount = 0; dtWarnCount = 0; updateDtBadges();
    }
    document.getElementById('conClear')?.addEventListener('click', clearConsole);
    document.getElementById('dtBtnClear')?.addEventListener('click', clearConsole);

    // ── Inspect Mode ──────────────────────────────────────────────────────────
    let INSPECT_MODE = false;
    let inspectTarget = null;

    document.getElementById('dtBtnInspect')?.addEventListener('click', () => {
        INSPECT_MODE = !INSPECT_MODE;
        const btn = document.getElementById('dtBtnInspect');
        btn.style.background = INSPECT_MODE ? '#4a9eff' : '';
        btn.style.color = INSPECT_MODE ? '#fff' : '';
        const overlay = document.getElementById('inspectOverlay');
        if (!INSPECT_MODE) {
            overlay.style.display = 'none';
            document.removeEventListener('mousemove', inspectMouseMove);
            document.removeEventListener('click', inspectClick, true);
            return;
        }
        showToast('🔍 Inspect mode ON — hover over elements, click to select');
        document.addEventListener('mousemove', inspectMouseMove);
        document.addEventListener('click', inspectClick, true);
    });

    function inspectMouseMove(e) {
        if (!INSPECT_MODE) return;
        let target = document.elementFromPoint(e.clientX, e.clientY);
        if (!target || target.id === 'inspectOverlay' || target.id === 'inspectTooltip' || target.closest('#devtools') || target.closest('#toast')) {
            document.getElementById('inspectOverlay').style.display = 'none';
            return;
        }
        inspectTarget = target;
        const rect = target.getBoundingClientRect();
        const overlay = document.getElementById('inspectOverlay');
        const tooltip = document.getElementById('inspectTooltip');
        overlay.style.display = 'block';
        overlay.style.left = rect.left + 'px';
        overlay.style.top = rect.top + 'px';
        overlay.style.width = rect.width + 'px';
        overlay.style.height = rect.height + 'px';
        const tag = target.tagName.toLowerCase();
        const cls = target.className ? '.' + (typeof target.className === 'string' ? target.className.trim().split(/\s+/).join('.') : '') : '';
        const computed = window.getComputedStyle(target);
        const font = computed.fontFamily.split(',')[0].replace(/['"]/g, '') + ' ' + computed.fontSize;
        tooltip.textContent = `${tag}${cls} | ${Math.round(rect.width)}×${Math.round(rect.height)} | ${font}`;
    }

    function inspectClick(e) {
        if (!INSPECT_MODE) return;
        e.preventDefault();
        e.stopPropagation();
        INSPECT_MODE = false;
        document.getElementById('dtBtnInspect').style.background = '';
        document.getElementById('dtBtnInspect').style.color = '';
        document.getElementById('inspectOverlay').style.display = 'none';
        document.removeEventListener('mousemove', inspectMouseMove);
        document.removeEventListener('click', inspectClick, true);
        if (inspectTarget) {
            selectElement(inspectTarget);
            switchDevToolTab('elements');
            showToast('✅ Element selected: ' + inspectTarget.tagName.toLowerCase());
        }
    }

    // ── Elements Tab: DOM Tree ─────────────────────────────────────────────────
    let selectedElement = null;

    document.getElementById('elemRefreshBtn')?.addEventListener('click', renderDOMTree);

    function renderDOMTree() {
        const getFrame = () => document.getElementById('browseFrame');
        const frame = new Proxy({}, { get: (t, p) => typeof getFrame()[p] === "function" ? getFrame()[p].bind(getFrame()) : getFrame()[p], set: (t, p, v) => { getFrame()[p] = v; return true; } });
        const view = document.getElementById('elemView');
        if (!view) return;
        view.innerHTML = '<div style="color:#888;padding:8px">Loading DOM tree...</div>';
        setTimeout(() => {
            try {
                const doc = (frame && (frame.contentDocument || frame.contentWindow?.document)) || document;
                view.innerHTML = '';
                renderNode(doc.documentElement || doc.body, 0);
                showToast('🔄 DOM tree refreshed');
            } catch (e) {
                view.innerHTML = `<div style="color:#f48771;padding:12px;font-size:12px">
            <div style="font-size:14px;margin-bottom:8px">⚠️ Cross-Origin Restriction</div>
            <div style="color:#aaa;margin-bottom:8px">Cannot access the DOM tree of this page due to cross-origin security restrictions.</div>
            <div style="color:#888;font-size:11px">
              <div>• In <strong>Electron mode</strong>, webview DOM can be inspected via real DevTools (Ctrl+Shift+I).</div>
              <div>• In <strong>web/proxy mode</strong>, some cross-origin frames are blocked by the browser.</div>
              <div style="margin-top:8px">You can still inspect the <strong>browser UI</strong> by clicking ↺ Refresh when no page is loaded.</div>
            </div>
          </div>`;
                if (!e.message?.includes('cross-origin') && !e.message?.includes('Blocked a frame') && !e.message?.includes('named property')) {
                    consoleLog('error', 'DOM tree render failed: ' + e.message, 'Elements');
                }
            }
        }, 50);
    }

    function renderNode(node, depth) {
        if (!node) return;
        const view = document.getElementById('elemView');

        // Text nodes
        if (node.nodeType === 3) {
            const text = (node.textContent || '').trim();
            if (!text || text.length === 0) return;
            const el = document.createElement('div');
            el.className = 'el-node el-text-node';
            el.style.paddingLeft = (depth * 16 + 4) + 'px';
            el.innerHTML = `<span class="el-text">"${escHtml(text.slice(0, 60))}${text.length > 60 ? '...' : ''}"</span>`;
            view.appendChild(el);
            return;
        }

        // Element nodes
        if (node.nodeType !== 1) return;
        const el = document.createElement('div');
        el.className = 'el-node';
        el.style.paddingLeft = (depth * 16) + 'px';
        el._nodeRef = node;

        const tag = node.tagName.toLowerCase();
        const attrs = Array.from(node.attributes || [])
            .map(a => ` <span class="el-attr">${escHtml(a.name)}</span>=<span class="el-str">"${escHtml(a.value.slice(0, 40))}${a.value.length > 40 ? '...' : ''}"</span>`)
            .join('');
        const hasChildren = (node.children && node.children.length > 0) || (node.childNodes && Array.from(node.childNodes).some(n => n.nodeType === 1 || (n.nodeType === 3 && n.textContent.trim())));
        const arrow = hasChildren ? '<span class="el-arrow">▸</span>' : '<span style="display:inline-block;width:10px"></span>';

        el.innerHTML = `${arrow}<span class="el-tag">&lt;${tag}</span>${attrs}<span class="el-tag">&gt;</span>`;
        el.onclick = (e) => {
            e.stopPropagation();
            document.querySelectorAll('.el-node').forEach(n => n.classList.remove('el-selected'));
            el.classList.add('el-selected');
            selectElement(node);
            if (hasChildren && el.querySelector('.el-arrow')) {
                const arrowEl = el.querySelector('.el-arrow');
                const isExpanded = arrowEl.textContent === '▾';
                arrowEl.textContent = isExpanded ? '▸' : '▾';
                let nextEl = el.nextElementSibling;
                while (nextEl && nextEl.style.paddingLeft && parseInt(nextEl.style.paddingLeft) > parseInt(el.style.paddingLeft)) {
                    nextEl.style.display = isExpanded ? 'none' : '';
                    nextEl = nextEl.nextElementSibling;
                }
            }
        };

        view.appendChild(el);

        // Render children
        if (hasChildren && node.childNodes) {
            Array.from(node.childNodes).forEach(child => renderNode(child, depth + 1));
        }
    }

    // ── Elements Sidebar Tabs ──────────────────────────────────────────────────
    document.querySelectorAll('.elem-stab').forEach(tab => {
        tab.addEventListener('click', () => {
            document.querySelectorAll('.elem-stab').forEach(t => t.classList.remove('active'));
            document.querySelectorAll('.estab-pane').forEach(p => p.style.display = 'none');
            tab.classList.add('active');
            const pane = document.getElementById('estab-' + tab.dataset.estab);
            if (pane) pane.style.display = 'block';
        });
    });

    function selectElement(elem) {
        if (!elem || elem.nodeType !== 1) return;
        selectedElement = elem;

        // Styles tab — inline + computed preview
        const inline = elem.style?.cssText || '/* No inline styles */';
        const inlineEl = document.getElementById('elemInlineStyles');
        if (inlineEl) inlineEl.textContent = inline;

        try {
            const computed = window.getComputedStyle(elem);
            const previewEl = document.getElementById('elemComputedPreview');
            if (previewEl) {
                previewEl.innerHTML = `
            <strong>width:</strong> ${computed.width}<br>
            <strong>height:</strong> ${computed.height}<br>
            <strong>display:</strong> ${computed.display}<br>
            <strong>position:</strong> ${computed.position}<br>
            <strong>color:</strong> <span style="display:inline-block;width:12px;height:12px;background:${computed.color};border:1px solid #555;vertical-align:middle"></span> ${computed.color}<br>
            <strong>background:</strong> <span style="display:inline-block;width:12px;height:12px;background:${computed.backgroundColor};border:1px solid #555;vertical-align:middle"></span> ${computed.backgroundColor}<br>
            <strong>font:</strong> ${computed.fontFamily.split(',')[0].replace(/['"]/g, '')} ${computed.fontSize} ${computed.fontWeight}
          `;
            }

            // Computed tab — all properties
            const fullEl = document.getElementById('elemComputedFull');
            if (fullEl) {
                const all = Array.from(computed).sort().map(prop => `<div><strong>${prop}:</strong> ${computed.getPropertyValue(prop)}</div>`).join('');
                fullEl.innerHTML = all || 'No computed styles';
            }

            // Layout tab — box model
            const w = parseInt(computed.width) || 0;
            const h = parseInt(computed.height) || 0;
            const m = computed.margin || '0';
            const b = computed.border || 'none';
            const p = computed.padding || '0';
            const boxW = document.getElementById('boxWidth');
            const boxH = document.getElementById('boxHeight');
            const boxM = document.getElementById('boxMargin');
            const boxB = document.getElementById('boxBorder');
            const boxP = document.getElementById('boxPadding');
            const posEl = document.getElementById('elemPosition');
            if (boxW) boxW.textContent = w;
            if (boxH) boxH.textContent = h;
            if (boxM) boxM.textContent = m;
            if (boxB) boxB.textContent = b;
            if (boxP) boxP.textContent = p;
            if (posEl) posEl.textContent = `position: ${computed.position} | top: ${computed.top} | left: ${computed.left} | z-index: ${computed.zIndex}`;

            // Events tab
            const eventsEl = document.getElementById('elemEvents');
            if (eventsEl) {
                eventsEl.innerHTML = '<div style="color:#888">Event listeners are not accessible in this browser implementation</div>';
            }
        } catch (e) {
            consoleLog('error', 'Failed to compute element styles: ' + e.message, 'Elements');
        }
    }

    // ── Network log
    const networkLog = document.getElementById('networkLog');
    const _netBuffer = [];  // buffer entries captured when DevTools is closed
    const _NET_BUF_MAX = 300;
    if (Array.isArray(globalThis.__etherxNetBuffer) && globalThis.__etherxNetBuffer.length) {
        _netBuffer.push(...globalThis.__etherxNetBuffer.slice(-_NET_BUF_MAX));
        globalThis.__etherxNetBuffer = _netBuffer;
    } else {
        globalThis.__etherxNetBuffer = _netBuffer;
    }
    function _renderNetEntry(entry) {
        if (!networkLog) return;
        const { url, type, status, size, time } = entry;
        const tr = document.createElement('tr');
        const name = (url.split('/').pop().split('?')[0] || '/').slice(0, 40);
        const t = type || 'HTML'; const s = status || 200; const sz = size || (Math.floor(Math.random() * 200 + 10) + 'KB'); const ms = time || (Math.floor(Math.random() * 200 + 20) + 'ms');
        const badgeClass = { 'HTML': 'b-html', 'JS': 'b-js', 'CSS': 'b-css', 'Img': 'b-img', 'XHR': 'b-xhr', 'WS': 'b-ws' }[t] || 'b-html';
        const bar = Math.min(100, Math.floor(Math.random() * 80 + 10));
        tr.dataset.type = t;
        tr.innerHTML = `<td title="${escHtml(url)}">${escHtml(name)}</td><td style="color:${s >= 400 ? '#f48771' : '#89d185'}">${s}</td><td><span class="badge ${badgeClass}">${t}</span></td><td>${sz}</td><td>${ms}</td><td><div class="net-bar-wrap"><div class="net-bar" style="width:${bar}%"></div></div></td>`;
        networkLog.appendChild(tr);
    }
    globalThis.__etherxRenderNetEntry = _renderNetEntry;
    function _flushNetBuffer() {
        if (!networkLog || !_netBuffer.length) return;
        _netBuffer.forEach(entry => _renderNetEntry(entry));
        _netBuffer.length = 0;
    }
    function logNetworkEntry(url, type, status, size, time) {
        const entry = { url, type: type || 'HTML', status: status || 200, size, time };
        // Always buffer so history is available when DevTools opens
        _netBuffer.push(entry);
        if (_netBuffer.length > _NET_BUF_MAX) _netBuffer.shift();
        // Only render immediately if DevTools is open
        if (STATE.devtoolsOpen) _renderNetEntry(entry);
    }

    // ── Network controls
    document.getElementById('netClear')?.addEventListener('click', () => { if (networkLog) networkLog.innerHTML = ''; _netBuffer.length = 0; });
    document.querySelectorAll('.net-type-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            document.querySelectorAll('.net-type-btn').forEach(b => b.classList.remove('on'));
            btn.classList.add('on');
            document.querySelectorAll('#networkLog tr').forEach(tr => {
                tr.style.display = (btn.dataset.ntype === 'All' || tr.dataset.type === btn.dataset.ntype) ? '' : 'none';
            });
        });
    });
    document.getElementById('netFilter')?.addEventListener('input', e => {
        const q = e.target.value.toLowerCase();
        document.querySelectorAll('#networkLog tr').forEach(tr => { tr.style.display = tr.textContent.toLowerCase().includes(q) ? '' : 'none'; });
    });

    // ── Performance tab controls
    const _perfMetricIds = ['perfFcp', 'perfLcp', 'perfTbt', 'perfCls', 'perfTti', 'perfLoad', 'perfMemory', 'perfDomCount'];
    function _collectPerfMetrics() {
        try {
            const nav = performance.getEntriesByType('navigation')[0];
            if (nav) {
                const load = document.getElementById('perfLoad'); if (load) load.textContent = nav.loadEventEnd.toFixed(0) + 'ms';
                const tti = document.getElementById('perfTti'); if (tti) tti.textContent = nav.domInteractive.toFixed(0) + 'ms';
                const dom = document.getElementById('perfDomCount'); if (dom) dom.textContent = document.querySelectorAll('*').length;
            }
            const mem = performance.memory;
            if (mem) { const el = document.getElementById('perfMemory'); if (el) el.textContent = (mem.usedJSHeapSize / 1048576).toFixed(1) + 'MB'; }
            const paints = performance.getEntriesByType('paint');
            paints.forEach(p => {
                if (p.name === 'first-contentful-paint') { const el = document.getElementById('perfFcp'); if (el) el.textContent = p.startTime.toFixed(0) + 'ms'; }
            });
        } catch (e) { }
        const t = document.getElementById('perfTime'); if (t) t.textContent = new Date().toLocaleTimeString();
    }
    document.getElementById('perfRecord')?.addEventListener('click', function () {
        this.style.color = '#27c93f';
        _collectPerfMetrics();
        setTimeout(() => { this.style.color = ''; }, 2000);
    });
    document.getElementById('perfReload')?.addEventListener('click', () => {
        const frame = document.getElementById('browseFrame') || document.getElementById('browseFrameWeb');
        if (frame) { try { if (frame.reload) frame.reload(); else frame.src = frame.src; } catch (e) { } }
        setTimeout(_collectPerfMetrics, 3000);
    });
    document.getElementById('perfClear')?.addEventListener('click', () => {
        _perfMetricIds.forEach(id => { const el = document.getElementById(id); if (el) el.textContent = '—'; });
        const t = document.getElementById('perfTime'); if (t) t.textContent = '—';
    });

    // ── Application tab
    const _appMap = { 'appLocalStorage': 'localstorage', 'appSessionStorage': 'sessionstorage', 'appCookies': 'cookies', 'appIndexedDB': 'indexeddb', 'appCacheStorage': 'cache', 'appServiceWorkers': 'sw', 'appSqliteHistory': 'sqlite-history', 'appSqliteTabs': 'sqlite-tabs', 'appSqliteBookmarks': 'sqlite-bookmarks', 'appSqliteAiCache': 'sqlite-aicache', 'appSqliteSettings': 'sqlite-settings', 'appSqliteUser': 'sqlite-user', 'appSqliteNotes': 'sqlite-notes', 'appSqliteDownloads': 'sqlite-downloads', 'appSqliteSessions': 'sqlite-sessions', 'appSqlitePasswords': 'sqlite-passwords' };
    Object.entries(_appMap).forEach(([id, type]) => {
        document.getElementById(id)?.addEventListener('click', () => {
            document.querySelectorAll('.app-item').forEach(x => x.classList.remove('active'));
            document.getElementById(id).classList.add('active');
            renderAppTab(type);
        });
    });
    function renderAppTab(type) {
        const c = document.getElementById('appContent'); if (!c) return;
        const activeTab = getActiveTab();
        const activeUrl = activeTab?.url || '';
        const activeHost = (() => { try { return activeUrl ? new URL(activeUrl).hostname : ''; } catch (_) { return ''; } })();
        const storageHint = window.electronWebview
            ? `<div style="padding:8px 10px;border-bottom:1px solid var(--border);background:rgba(74,158,255,.08);color:#9cc9ff;font-size:10px;line-height:1.45">
                Application panel ovdje prikazuje EtherX shell/storage. Za storage web stranice ${activeHost ? '<strong>' + escHtml(activeHost) + '</strong>' : ''} otvori native webview DevTools.
                <button onclick="window.openActiveWebviewDevTools?.()" style="margin-left:8px;background:var(--accent);border:none;color:#fff;border-radius:3px;cursor:pointer;font-size:10px;padding:1px 6px">Open Webview DevTools</button>
              </div>`
            : '';
        if (type === 'localstorage') {
            const keys = [];
            for (let i = 0; i < localStorage.length; i++) { const k = localStorage.key(i); if (k != null) keys.push(k); }
            if (!keys.length) { c.innerHTML = storageHint + '<p style="color:#555;font-size:11px;padding:8px">No local storage data.</p>'; return; }
            keys.sort();
            c.innerHTML = storageHint + '<table class="app-table"><thead><tr><th>Key</th><th>Value</th></tr></thead><tbody>' +
                keys.map(k => { let v = localStorage.getItem(k) || ''; if (v.length > 120) v = v.slice(0, 120) + '…'; return `<tr><td>${escHtml(k)}</td><td>${escHtml(v)}</td></tr>`; }).join('') + '</tbody></table>';
        } else if (type === 'sessionstorage') {
            const keys = [];
            for (let i = 0; i < sessionStorage.length; i++) { const k = sessionStorage.key(i); if (k != null) keys.push(k); }
            if (!keys.length) { c.innerHTML = storageHint + '<p style="color:#555;font-size:11px;padding:8px">Session storage je prazan.<br><small style="color:#444">EtherX koristi localStorage bridge (renderer-storage.json) za trajne podatke. Provjeri <strong>Local Storage</strong> tab.</small></p>'; return; }
            c.innerHTML = storageHint + '<table class="app-table"><thead><tr><th>Key</th><th>Value</th></tr></thead><tbody>' +
                keys.map(k => `<tr><td>${escHtml(k)}</td><td>${escHtml(sessionStorage.getItem(k) || '')}</td></tr>`).join('') + '</tbody></table>';
        } else if (type === 'cookies') {
            c.innerHTML = storageHint + '<p style="color:#858585;font-size:11px;padding:8px">⏳ Loading cookies…</p>';
            // In Electron: read cookies from session via IPC
            // Get URL of active tab for context (or get all cookies)
            const activeUrl = getActiveTab()?.url || '';
            const cookieFetch = (window.electronWebview && window.etherx?.cookies?.getAll)
                ? window.etherx.cookies.getAll(activeUrl || undefined)
                : Promise.resolve(null);
            cookieFetch.then(res => {
                // etherx.cookies.getAll may return an array directly or {ok, cookies}
                let electronCookies = [];
                if (Array.isArray(res)) {
                    electronCookies = res;
                } else if (res && res.ok && Array.isArray(res.cookies)) {
                    electronCookies = res.cookies;
                } else if (res && Array.isArray(res.cookies)) {
                    electronCookies = res.cookies;
                }
                // fallback: document.cookie (works in web/same-origin mode)
                const docCookies = document.cookie ? document.cookie.split(';').map(p => { const [k, ...v] = p.trim().split('='); return { name: k, value: v.join('='), domain: window.location.hostname, path: '/' }; }) : [];
                const all = electronCookies.length ? electronCookies : docCookies;
                if (!all.length) {
                    c.innerHTML = storageHint + '<p style="color:#555;font-size:11px;padding:8px">No cookies set for this session.<br><small style="color:#444">Ako očekuješ TikTok cookies, provjeri da TikTok tab koristi isti partition i otvori native webview DevTools.</small></p>';
                    return;
                }
                c.innerHTML = storageHint + `<div style="padding:8px 10px;font-size:10px;color:#858585;border-bottom:1px solid var(--border)">Cookies • ${all.length} entries ${activeUrl ? '(for: ' + escHtml(new URL(activeUrl).hostname) + ')' : '(all)'}
            <button onclick="${window.electronWebview ? "window.etherx?.cookies?.clearAll?.().then(()=>renderAppTab('cookies'))" : "document.cookie.split(';').forEach(c=>{const n=c.split('=')[0].trim();document.cookie=n+'=;expires=Thu,01 Jan 1970 00:00:00 GMT;path=/'});renderAppTab('cookies')"}" style="margin-left:8px;background:#c0392b;border:none;color:#fff;border-radius:3px;cursor:pointer;font-size:10px;padding:1px 6px">🗑 Clear All</button>
            <button onclick="renderAppTab('cookies')" style="margin-left:4px;background:#333;border:none;color:#aaa;border-radius:3px;cursor:pointer;font-size:10px;padding:1px 6px">↺</button></div>` +
                    '<table class="app-table"><thead><tr><th>Name</th><th>Value</th><th>Domain</th><th>Partition</th><th>Path</th><th>Secure</th><th>Size</th></tr></thead><tbody>' +
                    all.map(ck => `<tr><td style="color:var(--accent)">${escHtml(ck.name)}</td><td style="max-width:150px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${escHtml(ck.value)}">${escHtml((ck.value || '').slice(0, 50))}</td><td style="color:#888">${escHtml(ck.domain || '')}</td><td style="color:#777">${escHtml(ck.partition || 'document')}</td><td style="color:#888">${escHtml(ck.path || '/')}</td><td style="text-align:center">${ck.secure ? '🔒' : ''}</td><td style="color:#777">${((ck.name || '').length + (ck.value || '').length)} B</td></tr>`).join('') + '</tbody></table>';
            });

            // ── SQLite tables ──────────────────────────────────────────────────
        } else if (type === 'sqlite-history') {
            c.innerHTML = _sqliteLoading('History');
            const fetchHist = (window.electronWebview && window.etherx?.history?.getAll)
                ? window.etherx.history.getAll()
                : Promise.resolve(DB.getHistory());
            fetchHist.then(rows => {
                if (!rows || !rows.length) { c.innerHTML = _sqliteEmpty('history'); return; }
                c.innerHTML = `<div style="padding:8px 10px;font-size:10px;color:#858585;border-bottom:1px solid var(--border)">SQLite • etherx.db • table: <strong>history</strong> • ${rows.length} rows</div>` +
                    '<table class="app-table"><thead><tr><th>#</th><th>URL</th><th>Title</th><th>Visits</th><th>Last Visited</th></tr></thead><tbody>' +
                    rows.slice(0, 200).map((r, i) => {
                        let ts = Number(r.ts || r.last_visited || 0);
                        if (ts > 0 && ts < 1e12) ts *= 1000;
                        const date = ts ? new Date(ts).toLocaleString('hr-HR') : '';
                        const url = r.url || ''; const short = url.length > 50 ? url.slice(0, 50) + '…' : url;
                        return `<tr><td style="color:#555">${i + 1}</td><td title="${escHtml(url)}"><a href="#" onclick='navigateTo(${JSON.stringify(url)});return false' style="color:var(--accent)">${escHtml(short)}</a></td><td>${escHtml(r.title || '')}</td><td style="text-align:center">${r.visit_count || 1}</td><td style="color:#777;white-space:nowrap">${date}</td></tr>`;
                    }).join('') + '</tbody></table>';
            });
        } else if (type === 'sqlite-tabs') {
            c.innerHTML = _sqliteLoading('Open Tabs');
            // Always use live STATE.tabs as the source of truth; SQLite data may be stale
            const liveRows = STATE.tabs.map(t => ({ url: t.url, title: t.title, isActive: t.id === STATE.activeTabId, isPinned: t.pinned, groupName: t.group }));
            const fetchTabs = (window.electronWebview && window.etherx?.tabs?.getAll && !liveRows.length)
                ? window.etherx.tabs.getAll()
                : Promise.resolve(liveRows);
            fetchTabs.then(rows => {
                // Prefer live STATE.tabs; fall back to SQLite result only if no live tabs
                const merged = liveRows.length ? liveRows : (rows && rows.length ? rows : []);
                if (!merged || !merged.length) { c.innerHTML = _sqliteEmpty('open_tabs'); return; }
                c.innerHTML = `<div style="padding:8px 10px;font-size:10px;color:#858585;border-bottom:1px solid var(--border)">Tabs • <strong>live</strong> • ${merged.length} otvorenih</div>` +
                    '<table class="app-table"><thead><tr><th>#</th><th>URL</th><th>Naslov</th><th>Aktivna</th><th>Prikačena</th><th>Grupa</th></tr></thead><tbody>' +
                    merged.map((r, i) => {
                        const url = r.url || ''; const short = url.length > 45 ? url.slice(0, 45) + '…' : url;
                        return `<tr><td style="color:#555">${i + 1}</td><td title="${escHtml(url)}"><a href="#" onclick='navigateTo(${JSON.stringify(url)});return false' style="color:var(--accent)">${escHtml(short)}</a></td><td>${escHtml(r.title || 'New Tab')}</td><td style="text-align:center">${r.isActive || r.is_active ? '✅' : ''}</td><td style="text-align:center">${r.isPinned || r.is_pinned ? '📌' : ''}</td><td style="color:#888">${escHtml(r.groupName || r.group_name || '')}</td></tr>`;
                    }).join('') + '</tbody></table>';
            });
        } else if (type === 'sqlite-bookmarks') {
            c.innerHTML = _sqliteLoading('Bookmarks');
            const fetchBm = (window.electronWebview && window.etherx?.bookmarks?.getAll)
                ? window.etherx.bookmarks.getAll()
                : Promise.resolve([]);
            fetchBm.then(sqliteRows => {
                // Always merge with localStorage bookmarks (primary store for web mode)
                const localRows = DB.getBookmarks();
                // Deduplicate by URL: prefer SQLite rows, fill in rest from localStorage
                const seen = new Set((sqliteRows || []).map(r => r.url));
                const merged = [...(sqliteRows || []), ...localRows.filter(r => !seen.has(r.url))];
                const rows = merged;
                if (!rows || !rows.length) { c.innerHTML = _sqliteEmpty('bookmarks'); return; }
                c.innerHTML = `<div style="padding:8px 10px;font-size:10px;color:#858585;border-bottom:1px solid var(--border)">SQLite • etherx.db • table: <strong>bookmarks</strong> • ${rows.length} rows</div>` +
                    '<table class="app-table"><thead><tr><th>#</th><th>URL</th><th>Title</th><th>Folder</th><th>Added</th></tr></thead><tbody>' +
                    rows.map((r, i) => {
                        const url = r.url || ''; const short = url.length > 45 ? url.slice(0, 45) + '…' : url;
                        let ts = Number(r.ts || r.created_at || 0);
                        if (ts > 0 && ts < 1e12) ts *= 1000;
                        const date = ts ? new Date(ts).toLocaleDateString('hr-HR') : '';
                        return `<tr><td style="color:#555">${i + 1}</td><td title="${escHtml(url)}"><a href="#" onclick='navigateTo(${JSON.stringify(url)});return false' style="color:var(--accent)">${escHtml(short)}</a></td><td>${escHtml(r.title || '')}</td><td style="color:#888">${escHtml(r.folder || 'Bookmarks Bar')}</td><td style="color:#777;white-space:nowrap">${date}</td></tr>`;
                    }).join('') + '</tbody></table>';
            });
        } else if (type === 'sqlite-aicache') {
            c.innerHTML = _sqliteLoading('AI Cache');
            const fetchCache = (window.electronWebview && window.etherx?.ai?.getCachedSummaries)
                ? window.etherx.ai.getCachedSummaries(100)
                : Promise.resolve(Object.entries(_summaryCache || {}).map(([hash, v]) => ({ url_hash: hash, url: '', summary: v.summary || '', model: 'gemini-2.5-flash', created_at: '' })));
            fetchCache.then(rows => {
                if (!rows || !rows.length) { c.innerHTML = _sqliteEmpty('ai_cache'); return; }
                c.innerHTML = `<div style="padding:8px 10px;font-size:10px;color:#858585;border-bottom:1px solid var(--border)">SQLite • etherx.db • table: <strong>ai_cache</strong> • ${rows.length} rows • <button onclick="(window.etherx?.ai?.clearAiCache?.() || (_summaryCache && Object.keys(_summaryCache).forEach(k=>delete _summaryCache[k])));renderAppTab('sqlite-aicache')" style="background:#c0392b;border:none;color:#fff;border-radius:3px;cursor:pointer;font-size:10px;padding:1px 6px">Clear Cache</button></div>` +
                    '<table class="app-table"><thead><tr><th>#</th><th>URL</th><th>Summary</th><th>Model</th><th>Cached</th></tr></thead><tbody>' +
                    rows.map((r, i) => {
                        const url = r.url || ''; const short = url.length > 35 ? url.slice(0, 35) + '…' : url;
                        const sum = (r.summary || '').slice(0, 80) + ((r.summary || '').length > 80 ? '…' : '');
                        let ts = Number(r.created_at || 0);
                        if (ts > 0 && ts < 1e12) ts *= 1000;
                        const date = ts ? new Date(ts).toLocaleDateString('hr-HR') : '';
                        return `<tr><td style="color:#555">${i + 1}</td><td title="${escHtml(url)}" style="color:var(--accent);max-width:120px">${escHtml(short)}</td><td style="max-width:200px;color:#ccc">${escHtml(sum)}</td><td style="color:#4285f4">${escHtml(r.model || '')}</td><td style="color:#777;white-space:nowrap">${date}</td></tr>`;
                    }).join('') + '</tbody></table>';
            });
        } else if (type === 'sqlite-settings') {
            c.innerHTML = _sqliteLoading('Settings');
            const fetchSettings = (window.electronWebview && window.etherx?.settings?.get)
                ? window.etherx.settings.get()
                : Promise.resolve(DB.getSettings());
            fetchSettings.then(obj => {
                // Merge SQLite result with localStorage settings (SQLite may be empty on first run)
                const localSettings = DB.getSettings();
                const merged = Object.assign({}, localSettings, (obj && typeof obj === 'object' ? obj : {}));
                const entries = Object.entries(merged);
                if (!entries.length) { c.innerHTML = _sqliteEmpty('settings'); return; }
                const HIDDEN_KEYS = /api[_.]?key|api[_.]?secret|secret|password|token/i;
                const MODEL_KEYS = /ai[_.]?model|model[_.]?name/i;
                c.innerHTML = `<div style="padding:8px 10px;font-size:10px;color:#858585;border-bottom:1px solid var(--border)">SQLite • etherx.db • table: <strong>settings</strong> • ${entries.length} rows
            <button onclick="renderAppTab('sqlite-settings')" style="margin-left:8px;background:#333;border:none;color:#aaa;border-radius:3px;cursor:pointer;font-size:10px;padding:1px 6px">↺ Refresh</button></div>` +
                    '<table class="app-table"><thead><tr><th>Key</th><th>Value</th><th style="width:60px"></th></tr></thead><tbody id="settingsTableBody">' +
                    entries.map(([k, v]) => {
                        let display;
                        if (HIDDEN_KEYS.test(k)) {
                            display = '<span style="color:#666;letter-spacing:2px">••••••••••</span>';
                        } else if (MODEL_KEYS.test(k)) {
                            // Show only provider prefix (e.g. "gemini" from "gemini-2.5-flash"), not the exact model string
                            const provider = String(v).split(/[-/_]/)[0] || '—';
                            display = '<span style="color:#888">' + escHtml(provider) + ' <span style="color:#555">(configuriran)</span></span>';
                        } else {
                            display = escHtml(String(v).slice(0, 100));
                        }
                        return `<tr><td style="color:var(--yellow)">${escHtml(k)}</td><td style="color:#ccc" id="sv_${escHtml(k)}">${display}</td><td><button onclick="_editSetting('${escHtml(k)}')" style="background:none;border:1px solid #555;border-radius:3px;color:#aaa;cursor:pointer;font-size:10px;padding:1px 5px">✏️</button> <button onclick="_deleteSetting('${escHtml(k)}')" style="background:none;border:1px solid #c0392b44;border-radius:3px;color:#e74c3c;cursor:pointer;font-size:10px;padding:1px 5px">✕</button></td></tr>`;
                    }).join('') + '</tbody></table>' +
                    `<div style="padding:8px 10px;border-top:1px solid var(--border);display:flex;gap:6px">
              <input id="newSettingKey" placeholder="key" style="flex:1;background:var(--bg3);border:1px solid var(--border2);border-radius:4px;color:var(--text);padding:3px 6px;font-size:11px">
              <input id="newSettingVal" placeholder="value" style="flex:2;background:var(--bg3);border:1px solid var(--border2);border-radius:4px;color:var(--text);padding:3px 6px;font-size:11px">
              <button onclick="_addSetting()" style="background:var(--accent);border:none;border-radius:4px;color:#fff;cursor:pointer;font-size:11px;padding:3px 10px">+ Add</button>
            </div>`;
            });

        } else if (type === 'sqlite-user') {
            c.innerHTML = _sqliteLoading('User Profile');
            const fetchUser = (window.electronWebview && window.etherx?.userProfile?.get)
                ? window.etherx.userProfile.get()
                : Promise.resolve(DB.getUser());
            fetchUser.then(u => {
                if (!u) u = DB.getUser();
                c.innerHTML = `<div style="padding:8px 10px;font-size:10px;color:#858585;border-bottom:1px solid var(--border)">SQLite • etherx.db • table: <strong>user_profile</strong> • 1 row</div>
            <div style="padding:12px">
              <div style="display:flex;align-items:center;gap:12px;margin-bottom:16px">
                <div id="userAvatarDisp" style="font-size:36px;cursor:pointer;display:flex;align-items:center;justify-content:center;width:48px;height:48px;border-radius:50%;overflow:hidden;background:var(--bg3)" title="Click to change avatar" onclick="_changeUserAvatar()">${u.avatarUrl ? '<img src="' + escHtml(u.avatarUrl) + '" style="width:48px;height:48px;object-fit:cover;border-radius:50%">' : escHtml(u.avatar || '👤')}</div>
                <div>
                  <div style="font-size:13px;font-weight:600;color:var(--text)">${escHtml(u.name || u.displayName || '(no name)')}</div>
                  <div style="font-size:11px;color:var(--text3)">${escHtml(u.email || '(no email)')}</div>
                </div>
              </div>
              <table class="app-table"><thead><tr><th>Field</th><th>Value</th><th style="width:60px"></th></tr></thead><tbody>
                ${['name', 'email', 'avatar', 'bio', 'website', 'location'].map(f => `<tr><td style="color:var(--yellow)">${f}</td><td id="uf_${f}" style="color:#ccc">${escHtml(String(u[f] || ''))}</td><td><button onclick="_editUserField('${f}')" style="background:none;border:1px solid #555;border-radius:3px;color:#aaa;cursor:pointer;font-size:10px;padding:1px 5px">✏️</button></td></tr>`).join('')}
              </tbody></table>
              <div style="padding:8px 0;font-size:10px;color:#555">Created: ${u.createdAt ? new Date(u.createdAt).toLocaleString('hr-HR') : '—'} &nbsp;|&nbsp; Updated: ${u.updatedAt ? new Date(u.updatedAt).toLocaleString('hr-HR') : '—'}</div>
            </div>`;
            });

        } else if (type === 'sqlite-notes') {
            c.innerHTML = _sqliteLoading('Notes');
            const fetchNotes = (window.electronWebview && window.etherx?.notes?.get)
                ? window.etherx.notes.get()
                : Promise.resolve([]);
            fetchNotes.then(sqliteRows => {
                const localRows = DB.getNotes();
                const merged = (sqliteRows || []).map(r => ({
                    id: r.id,
                    title: r.title,
                    content: r.content,
                    ts: r.updated_at * 1000
                })).concat(localRows.filter(l => !(sqliteRows || []).some(s => s.id === l.id)));

                c.innerHTML = `<div style="padding:8px 10px;font-size:10px;color:#858585;border-bottom:1px solid var(--border)">SQLite • etherx.db • table: <strong>notes</strong> • ${merged.length} rows
            <button onclick="renderAppTab('sqlite-notes')" style="margin-left:8px;background:#333;border:none;color:#aaa;border-radius:3px;cursor:pointer;font-size:10px;padding:1px 6px">↺</button></div>` +
                    (merged.length ? '<table class="app-table"><thead><tr><th>#</th><th>Title</th><th>Content</th><th>Date</th><th style="width:70px"></th></tr></thead><tbody>' +
                        merged.map((n, i) => {
                            const dt = new Date(n.ts).toLocaleDateString('hr-HR');
                            const body = (n.content || '').slice(0, 60) + ((n.content || '').length > 60 ? '…' : '');
                            const delFn = window.electronWebview ? `window.etherx.notes.delete(${n.id})` : `DB.deleteNote(${n.id})`;
                            return `<tr><td style="color:#555">${i + 1}</td><td style="color:var(--accent);font-weight:600">${escHtml(n.title || 'Untitled')}</td><td style="color:#ccc">${escHtml(body)}</td><td style="color:#777;white-space:nowrap">${dt}</td><td><button onclick="_editNote(${n.id})" style="background:none;border:1px solid #555;border-radius:3px;color:#aaa;cursor:pointer;font-size:10px;padding:1px 4px">✏️</button> <button onclick="${delFn};renderAppTab('sqlite-notes')" style="background:none;border:1px solid #c0392b44;border-radius:3px;color:#e74c3c;cursor:pointer;font-size:10px;padding:1px 4px">✕</button></td></tr>`;
                        }).join('') + '</tbody></table>' : '<p style="color:#555;font-size:11px;padding:12px">No notes yet.</p>') +
                    `<div style="padding:8px 10px;border-top:1px solid var(--border);display:flex;gap:6px">
              <input id="newNoteTitle" placeholder="Title" style="flex:1;background:var(--bg3);border:1px solid var(--border2);border-radius:4px;color:var(--text);padding:3px 6px;font-size:11px">
              <input id="newNoteContent" placeholder="Content…" style="flex:3;background:var(--bg3);border:1px solid var(--border2);border-radius:4px;color:var(--text);padding:3px 6px;font-size:11px">
              <button onclick="_addNote()" style="background:var(--accent);border:none;border-radius:4px;color:#fff;cursor:pointer;font-size:11px;padding:3px 10px">+ Add</button>
            </div>`;
            });

        } else if (type === 'sqlite-downloads') {
            c.innerHTML = _sqliteLoading('Downloads');
            const fetchDl = (window.electronWebview && window.etherx?.downloads?.get)
                ? window.etherx.downloads.get(200)
                : Promise.resolve([]);
            fetchDl.then(sqliteRows => {
                const localRows = DB.getDownloads();
                const merged = (sqliteRows || []).map(r => ({
                    id: r.id,
                    ts: r.created_at * 1000,
                    filename: r.filename,
                    url: r.url,
                    size: r.file_size
                })).concat(localRows.filter(l => !(sqliteRows || []).some(s => s.id === l.id)));

                if (!merged.length) { c.innerHTML = _sqliteEmpty('downloads'); return; }
                c.innerHTML = `<div style="padding:8px 10px;font-size:10px;color:#858585;border-bottom:1px solid var(--border)">SQLite • etherx.db • table: <strong>downloads</strong> • ${merged.length} rows
            <button onclick="${window.electronWebview ? 'window.etherx.downloads.clear()' : 'DB.clearDownloads()'};renderAppTab('sqlite-downloads')" style="margin-left:8px;background:#c0392b;border:none;color:#fff;border-radius:3px;cursor:pointer;font-size:10px;padding:1px 6px">🗑 Clear All</button></div>` +
                    '<table class="app-table"><thead><tr><th>#</th><th>Filename</th><th>URL</th><th>Size</th><th>Date</th><th></th></tr></thead><tbody>' +
                    merged.slice(0, 200).map((r, i) => {
                        const dt = r.ts ? new Date(r.ts).toLocaleDateString('hr-HR') : '';
                        const url = (r.url || '').slice(0, 40) + '…';
                        const delFn = window.electronWebview ? `window.etherx.downloads.delete(${r.id})` : `DB.deleteDownload(${r.id})`;
                        return `<tr><td style="color:#555">${i + 1}</td><td style="color:var(--accent)">${escHtml(r.filename || r.name || '?')}</td><td title="${escHtml(r.url || '')}" style="color:#888">${escHtml(url)}</td><td style="color:#aaa">${r.size || ''}</td><td style="color:#777;white-space:nowrap">${dt}</td><td><button onclick="${delFn};renderAppTab('sqlite-downloads')" style="background:none;border:1px solid #c0392b44;border-radius:3px;color:#e74c3c;cursor:pointer;font-size:10px;padding:1px 4px">✕</button></td></tr>`;
                    }).join('') + '</tbody></table>';
            });
        } else if (type === 'sqlite-sessions') {
            c.innerHTML = _sqliteLoading('Sessions');
            const fetchSessions = (window.electronWebview && window.etherx?.sessions?.get)
                ? window.etherx.sessions.get(50)
                : Promise.resolve([]);
            fetchSessions.then(sqliteRows => {
                const localRows = DB.getSessions();
                // Merge and normalize: SQLite uses tabs_json, localStorage uses tabs
                const merged = (sqliteRows || []).map(r => ({
                    id: r.id,
                    ts: r.created_at * 1000, // SQLite is in seconds
                    name: r.name,
                    tabs: JSON.parse(r.tabs_json || '[]'),
                    count: JSON.parse(r.tabs_json || '[]').length
                })).concat(localRows.filter(l => !(sqliteRows || []).some(s => s.id === l.id)));

                if (!merged.length && STATE.tabs.length) { DB.saveSession(STATE.tabs); renderAppTab('sqlite-sessions'); return; }
                if (!merged.length) { c.innerHTML = _sqliteEmpty('sessions'); return; }

                c.innerHTML = `<div style="padding:8px 10px;font-size:10px;color:#858585;border-bottom:1px solid var(--border)">SQLite • etherx.db • table: <strong>sessions</strong> • ${merged.length} saved sessions
            <button onclick="DB.saveSession(STATE.tabs);renderAppTab('sqlite-sessions')" style="margin-left:8px;background:var(--accent);border:none;color:#fff;border-radius:3px;cursor:pointer;font-size:10px;padding:1px 6px">💾 Save Current</button></div>` +
                    '<table class="app-table"><thead><tr><th>#</th><th>Tabovi</th><th>Saved</th><th style="width:80px"></th></tr></thead><tbody>' +
                    merged.map((r, i) => {
                        const dt = new Date(r.ts).toLocaleString('hr-HR');
                        const preview = (r.tabs || []).slice(0, 3).map(t => escHtml((t.title || t.url || '?').slice(0, 20))).join(', ') + (r.tabs?.length > 3 ? '…' : '');
                        return `<tr><td style="color:#555">${i + 1}</td><td style="color:#ccc;font-size:10px">${r.count || 0} tabs: ${preview}</td><td style="color:#777;white-space:nowrap;font-size:10px">${dt}</td><td><button onclick="_restoreSession(${r.id})" style="background:none;border:1px solid #555;border-radius:3px;color:#aaa;cursor:pointer;font-size:10px;padding:1px 5px">↺ Restore</button> <button onclick="_deleteSession(${r.id})" style="background:none;border:1px solid #c0392b44;border-radius:3px;color:#e74c3c;cursor:pointer;font-size:10px;padding:1px 4px">✕</button></td></tr>`;
                    }).join('') + '</tbody></table>';
            });
        } else if (type === 'sqlite-passwords') {
            c.innerHTML = _sqliteLoading('Passwords');
            const fetchPw = (window.electronWebview && window.etherx?.passwords?.list)
                ? window.etherx.passwords.list()
                : Promise.resolve(getSavedPasswords());
            fetchPw.then(rows => {
                if (!rows || !rows.length) { c.innerHTML = _sqliteEmpty('passwords'); return; }
                c.innerHTML = `<div style="padding:8px 10px;font-size:10px;color:#858585;border-bottom:1px solid var(--border)">SQLite • etherx.db • table: <strong>passwords</strong> • ${rows.length} entries <span style="color:#e74c3c">(passwords are masked)</span></div>` +
                    '<table class="app-table"><thead><tr><th>#</th><th>Site</th><th>Username</th><th>Password</th><th>Added</th></tr></thead><tbody>' +
                    rows.map((r, i) => {
                        let ts = Number(r.ts || r.created_at || 0);
                        if (ts > 0 && ts < 1e12) ts *= 1000;
                        const date = ts ? new Date(ts).toLocaleDateString('hr-HR') : '';
                        return `<tr><td style="color:#555">${i + 1}</td><td style="color:var(--accent)">${escHtml(r.site || '')}</td><td style="color:#ccc">${escHtml(r.username || '')}</td><td style="color:#555">••••••••</td><td style="color:#777;white-space:nowrap">${date}</td></tr>`;
                    }).join('') + '</tbody></table>';
            });

        } else if (type === 'indexeddb') {
            c.innerHTML = storageHint + '<p style="color:#858585;font-size:11px;padding:8px">⏳ Učitavanje IndexedDB…</p>';
            if (!window.indexedDB) { c.innerHTML = storageHint + '<p style="color:#555;font-size:11px;padding:8px">IndexedDB nije dostupan u ovom kontekstu.</p>'; return; }
            const dbListPromise = (typeof indexedDB.databases === 'function') ? indexedDB.databases() : Promise.resolve([]);
            dbListPromise.then(dbs => {
                if (!dbs || !dbs.length) { c.innerHTML = storageHint + '<p style="color:#555;font-size:11px;padding:12px">🗄️ Nema IndexedDB baza podataka u EtherX shell kontekstu.<br><small style="color:#444">Za IndexedDB web stranice otvori native webview DevTools na aktivnom tabu.</small></p>'; return; }
                c.innerHTML = storageHint + `<div style="padding:8px 10px;font-size:10px;color:#858585;border-bottom:1px solid var(--border)">IndexedDB • <strong>${dbs.length}</strong> baza</div>` +
                    '<table class="app-table"><thead><tr><th>Naziv</th><th>Verzija</th></tr></thead><tbody>' +
                    dbs.map(db => `<tr><td style="color:var(--accent)">${escHtml(db.name || '')}</td><td style="color:#888">${db.version || 1}</td></tr>`).join('') +
                    '</tbody></table>';
            }).catch(() => { c.innerHTML = storageHint + '<p style="color:#555;font-size:11px;padding:8px">IndexedDB: greška pri čitanju baza podataka.</p>'; });
        } else if (type === 'cache' || type === 'sw') {
            c.innerHTML = storageHint + `<p style="color:#555;font-size:11px;padding:12px">${type === 'cache' ? 'Cache Storage' : 'Service Workers'} za web stranice žive u webview originu, ne u EtherX shellu.<br><small style="color:#444">Otvori native webview DevTools na aktivnom tabu i tamo pogledaj Application → ${type === 'cache' ? 'Cache Storage' : 'Service Workers'}.</small></p>`;
        } else {
            c.innerHTML = storageHint + '<p style="color:#555;font-size:11px;padding:8px">No data available.</p>';
        }
    }
    function _sqliteLoading(name) { return `<div style="padding:16px;color:#858585;font-size:12px;display:flex;align-items:center;gap:8px"><div style="width:14px;height:14px;border:2px solid #555;border-top-color:#4a9eff;border-radius:50%;animation:spin .8s linear infinite"></div>Loading ${name} from SQLite…</div>`; }
    function _sqliteEmpty(table) { return `<p style="color:#555;font-size:11px;padding:12px">🗄️ Table <strong>${escHtml(table)}</strong> is empty.</p>`; }
    function escHtml(s) { return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;'); }

    // ── DevTools Tab Switcher ─────────────────────────────────────────────────
    function switchDevToolTab(paneName) {
        document.querySelectorAll('.dt-tab').forEach(t => t.classList.remove('active'));
        document.querySelectorAll('.dt-pane').forEach(p => p.classList.remove('active'));
        const tab = document.querySelector(`.dt-tab[data-pane="${paneName}"]`);
        const pane = document.getElementById('pane-' + paneName);
        if (tab) tab.classList.add('active');
        if (pane) pane.classList.add('active');
    }

    // ── Application tab CRUD helpers ──────────────────────────────────────────
    async function _editSetting(k) {
        const HIDDEN = ['gemini_api_key', 'openai_api_key', 'api_key'];
        const s = DB.getSettings();
        const cur = HIDDEN.some(h => k.includes(h)) ? '' : (s[k] !== undefined ? String(s[k]) : '');
        const nv = await showPrompt('Edit setting: ' + k, cur);
        if (nv === null) return;
        let parsed = nv;
        if (nv === 'true') parsed = true; else if (nv === 'false') parsed = false; else if (!isNaN(nv) && nv !== '') parsed = Number(nv);
        DB.saveSetting(k, parsed);
        renderAppTab('sqlite-settings');
        showToast('✅ Setting "' + k + '" updated');
    }
    function _deleteSetting(k) {
        if (!confirm('Delete setting: ' + k + '?')) return;
        const s = DB.getSettings();
        delete s[k];
        const { publicSettings, secretSettings } = splitSensitiveSettingsObject(s);
        SECURE_SETTINGS_CACHE = { ...secretSettings };
        writePublicSettingsSnapshot(publicSettings);
        if (window.etherx?.settings?.save) window.etherx.settings.save({ ...publicSettings, ...secretSettings }).catch(() => { });
        persistSensitiveSettings({ ...publicSettings, ...secretSettings }).catch(() => { });
        renderAppTab('sqlite-settings');
        showToast('🗑 Setting "' + k + '" deleted');
    }
    function _addSetting() {
        const k = document.getElementById('newSettingKey')?.value?.trim();
        const v = document.getElementById('newSettingVal')?.value?.trim();
        if (!k) { showToast('⚠️ Key cannot be empty'); return; }
        let parsed = v;
        if (v === 'true') parsed = true; else if (v === 'false') parsed = false; else if (!isNaN(v) && v !== '') parsed = Number(v);
        DB.saveSetting(k, parsed);
        renderAppTab('sqlite-settings');
        showToast('✅ Setting "' + k + '" added');
    }
    async function _editUserField(f) {
        const u = DB.getUser();
        const nv = await showPrompt('Edit ' + f + ':', u[f] || '');
        if (nv === null) return;
        DB.saveUser({ [f]: nv });
        renderAppTab('sqlite-user');
        showToast('✅ User ' + f + ' updated');
    }
    async function _changeUserAvatar() {
        const choice = await showPrompt('Avatar options:\n1. Enter emoji (e.g. 👤 🦊 🎮)\n2. Type "upload" to upload an image\n\nEnter emoji or "upload":', DB.getUser().avatar || '👤');
        if (choice === null) return;
        if (choice.toLowerCase() === 'upload') {
            if (window.electronAPI) {
                window.electronAPI.invoke('app:chooseProfilePicture').then(dataUrl => {
                    if (dataUrl) { DB.saveUser({ avatar: '', avatarUrl: dataUrl }); renderAppTab('sqlite-user'); showToast('✅ Profile picture updated'); }
                });
            } else {
                const input = document.createElement('input'); input.type = 'file'; input.accept = 'image/*';
                input.addEventListener('change', () => {
                    const file = input.files[0]; if (!file) return;
                    const reader = new FileReader();
                    reader.onload = () => { DB.saveUser({ avatar: '', avatarUrl: reader.result }); renderAppTab('sqlite-user'); showToast('✅ Profile picture updated'); };
                    reader.readAsDataURL(file);
                });
                input.click();
            }
        } else {
            DB.saveUser({ avatar: choice, avatarUrl: '' });
            renderAppTab('sqlite-user');
        }
    }
    function _addNote() {
        const t = document.getElementById('newNoteTitle')?.value?.trim();
        const body = document.getElementById('newNoteContent')?.value?.trim();
        if (!t) { showToast('⚠️ Note title cannot be empty'); return; }
        DB.addNote({ title: t, content: body || '' });
        renderAppTab('sqlite-notes');
        showToast('📝 Note added: ' + t);
    }
    async function _editNote(id) {
        const n = DB.getNotes().find(x => x.id === id);
        if (!n) return;
        const nt = await showPrompt('Title:', n.title || '');
        if (nt === null) return;
        const nb = await showPrompt('Content:', n.content || '');
        if (nb === null) return;
        DB.updateNote(id, { title: nt, content: nb });
        renderAppTab('sqlite-notes');
        showToast('📝 Note updated');
    }
    function _restoreSession(id) {
        const sessions = DB.getSessions();
        const sess = sessions.find(s => s.id === id);
        if (!sess || !sess.tabs?.length) { showToast('⚠️ Session is empty'); return; }
        if (!confirm('Restore session with ' + sess.tabs.length + ' tabs? This will open them as new tabs.')) return;
        sess.tabs.forEach(t => createTab(t.url, t.title, false));
        showToast('↺ Session restored: ' + sess.tabs.length + ' tabs');
    }
    function _deleteSession(id) {
        const sessions = DB.getSessions().filter(s => s.id !== id);
        localStorage.setItem('ex_sessions', JSON.stringify(sessions));
        renderAppTab('sqlite-sessions');
        showToast('🗑 Session deleted');
    }
    Object.assign(window, {
        renderAppTab,
        _editSetting,
        _deleteSetting,
        _addSetting,
        _editUserField,
        _changeUserAvatar,
        _addNote,
        _editNote,
        _restoreSession,
        _deleteSession,
    });

    // ── Performance metrics
    function collectPerfMetrics() {
        try {
            const nav = performance.getEntriesByType('navigation')[0];
            if (nav) {
                const load = (nav.loadEventEnd - nav.startTime).toFixed(0);
                const tti = (nav.domInteractive - nav.startTime).toFixed(0);
                const el = document.getElementById('perfLoad'); if (el) el.textContent = load + 'ms';
                const et = document.getElementById('perfTti'); if (et) et.textContent = tti + 'ms';
            }
            performance.getEntriesByType('paint').forEach(p => {
                if (p.name === 'first-contentful-paint') { const el = document.getElementById('perfFcp'); if (el) el.textContent = p.startTime.toFixed(0) + 'ms'; }
            });
            // Memory info (Chrome/Electron)
            if (performance.memory) {
                const mem = performance.memory;
                const el = document.getElementById('perfMemory');
                if (el) el.textContent = (mem.usedJSHeapSize / 1048576).toFixed(1) + ' MB / ' + (mem.totalJSHeapSize / 1048576).toFixed(1) + ' MB';
            }
            // DOM stats
            const domCount = document.querySelectorAll('*').length;
            const dc = document.getElementById('perfDomCount'); if (dc) dc.textContent = domCount + ' elements';
        } catch (e) { }
    }
