                coins: giftMeta ? Math.max(0, Number(giftMeta.coins || 0)) : 0,
                riskLevel,
                riskCategory: String(row.riskCategory || row.guardCategory || row.category || '-'),
                riskSource: String(row.guardSource || row.riskSource || '-'),
