    document.getElementById('ctx-paste-text').addEventListener('click', async () => {
        try {
            const text = await navigator.clipboard.readText();
            const el = _ctxFocusedEl || document.activeElement;
            if (el && (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA' || el.isContentEditable)) {
                const s = el.selectionStart ?? 0, end = el.selectionEnd ?? 0;
                if (el.isContentEditable) {
                    document.execCommand('insertText', false, text);
                } else {
                    el.value = el.value.slice(0, s) + text + el.value.slice(end);
                    el.selectionStart = el.selectionEnd = s + text.length;
                    el.dispatchEvent(new Event('input', { bubbles: true }));
                }
            } else { document.execCommand('paste'); }
            showToast('📌 Zalijepljeno');
        } catch (_) { showToast('⚠️ Dozvoli pristup međuspremniku u postavkama preglednika'); }
    });
