    function showPrompt(message, defaultVal = '', opts = {}) {
        return new Promise(resolve => {
            const overlay = document.createElement('div');
            overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:99999;display:flex;align-items:center;justify-content:center';
            const box = document.createElement('div');
            box.style.cssText = 'background:var(--bg1,#1e1e1e);border:1px solid var(--border,#444);border-radius:10px;padding:20px 24px;min-width:320px;max-width:480px;font-family:system-ui,sans-serif;font-size:13px;color:var(--text1,#e8e8e8);box-shadow:0 8px 32px rgba(0,0,0,.6)';
            const msg = document.createElement('div');
            msg.style.cssText = 'margin-bottom:12px;line-height:1.5;white-space:pre-wrap;word-break:break-word';
            msg.textContent = message;
            const input = document.createElement('input');
            input.type = opts.password ? 'password' : 'text';
            input.value = String(defaultVal ?? '');
            input.style.cssText = 'width:100%;box-sizing:border-box;padding:7px 10px;background:var(--bg2,#2a2a2a);border:1px solid var(--border2,#555);border-radius:6px;color:var(--text1,#e8e8e8);font-size:13px;outline:none;margin-bottom:14px';
            const btns = document.createElement('div');
            btns.style.cssText = 'display:flex;gap:8px;justify-content:flex-end';
            const cancelBtn = document.createElement('button');
            cancelBtn.textContent = 'Cancel';
            cancelBtn.style.cssText = 'padding:6px 16px;background:var(--bg3,#333);border:1px solid var(--border2,#555);border-radius:6px;color:var(--text2,#aaa);cursor:pointer;font-size:12px';
            const okBtn = document.createElement('button');
            okBtn.textContent = 'OK';
            okBtn.style.cssText = 'padding:6px 16px;background:var(--accent,#4c8ef7);border:none;border-radius:6px;color:#fff;cursor:pointer;font-size:12px;font-weight:500';
            const done = val => { overlay.remove(); resolve(val); };
            okBtn.addEventListener('click', () => done(input.value));
            cancelBtn.addEventListener('click', () => done(null));
            input.addEventListener('keydown', e => {
                e.stopPropagation();
                if (e.key === 'Enter') done(input.value);
                if (e.key === 'Escape') done(null);
            });
            overlay.addEventListener('click', e => {
                if (e.target !== overlay) return;
                if (opts.dismissOnOverlay === true) done(null);
            });
            btns.append(cancelBtn, okBtn);
            box.append(msg, input, btns);
            overlay.appendChild(box);
            document.body.appendChild(overlay);
            setTimeout(() => { input.focus(); input.select(); }, 10);
        });
    }
    // Cache clock-related settings so DB.getSettings() is not called on every tick.
    let _clockCfgCache = null;
    let _clockIntervalId = null;
    function _refreshClockCfgCache() { _clockCfgCache = DB.getSettings(); }
    function updateClock() {
        if (!_clockCfgCache) _refreshClockCfgCache();
        const cfg = _clockCfgCache;
        const now = new Date();
        const h12 = cfg.clockFormat === '12h';
        const showSec = cfg.clockShowSeconds === true;
        const opts = { hour: '2-digit', minute: '2-digit', hour12: h12 };
        if (showSec) opts.second = '2-digit';
        const t = now.toLocaleTimeString([], opts);
        const d = now.toLocaleDateString('hr-HR', { weekday: 'short', day: 'numeric', month: 'short' });
        const clockPfx = (typeof _titlebarIcons !== 'undefined' && _titlebarIcons['titleClock']) || '';
        const datePfx = (typeof _titlebarIcons !== 'undefined' && _titlebarIcons['titleDate']) || '';
        const clockEl = document.getElementById('titleClock');
        clockEl.textContent = (clockPfx ? clockPfx + ' ' : '') + t;
        const clockColor = cfg.clockColor || '#ffffff';
        clockEl.style.color = clockColor;
        const clockSize = cfg.clockSize || 15;
        clockEl.style.fontSize = clockSize + 'px';
        document.getElementById('sbTime').textContent = t;
        const de = document.getElementById('titleDate');
        if (de) {
            de.textContent = (datePfx ? datePfx + ' ' : '') + d;
            de.style.color = cfg.dateColor || '#ffffff';
            de.style.fontSize = (cfg.dateSize || 12) + 'px';
        }
    }
    function _startClockInterval() {
        if (_clockIntervalId) clearInterval(_clockIntervalId);
        _refreshClockCfgCache();
        const showSec = _clockCfgCache.clockShowSeconds === true;
        // Update every second when seconds are visible; every 30 s otherwise.
        _clockIntervalId = setInterval(updateClock, showSec ? 1000 : 30000);
    }
    updateClock(); _startClockInterval();
    // Re-start clock after settings save so format/interval reflects new values.
    if (typeof window !== 'undefined') {
        const _origSaveSettings = window.saveSettings;
        if (typeof _origSaveSettings === 'function') {
            window._afterSaveSettingsHooks = window._afterSaveSettingsHooks || [];
            window._afterSaveSettingsHooks.push(() => { _clockCfgCache = null; _startClockInterval(); });
        }
    }
    function timeAgo(ts) { const d = Date.now() - ts; if (d < 60000) return 'now'; if (d < 3600000) return Math.floor(d / 60000) + 'm'; if (d < 86400000) return Math.floor(d / 3600000) + 'h'; return Math.floor(d / 86400000) + 'd'; }

    function forwardClipboardShortcutToActiveWebview(action) {
        const tab = getActiveTab();
        const webview = document.getElementById('browseFrame_' + (tab?.id || '')) || document.getElementById('browseFrame');
        if (!webview || webview.tagName !== 'WEBVIEW' || typeof webview.executeJavaScript !== 'function') return false;

        const run = async () => {
            const clipText = action === 'paste'
                ? await navigator.clipboard.readText().catch(() => '')
                : '';
            const script = `(() => {
                const action = ${JSON.stringify(action)};
                const clipText = ${JSON.stringify(clipText)};
                const active = document.activeElement;
                const editable = !!(active && (active.isContentEditable || active.tagName === 'TEXTAREA' || active.tagName === 'INPUT' || active.getAttribute?.('role') === 'textbox'));

                if (action === 'copy') return !!document.execCommand('copy');
                if (action === 'cut') return !!document.execCommand('cut');
                if (action === 'selectAll') return !!document.execCommand('selectAll');

                if (action === 'paste') {
                    if (!editable) return false;
                    if (active && active.isContentEditable) {
                        try {
                            document.execCommand('insertText', false, clipText);
                        } catch (_) {
                            active.textContent = clipText;
                        }
                        active.dispatchEvent(new Event('input', { bubbles: true }));
                        return true;
                    }
                    if (active && (active.tagName === 'TEXTAREA' || active.tagName === 'INPUT')) {
                        const start = Number(active.selectionStart || 0);
                        const end = Number(active.selectionEnd || 0);
                        const value = String(active.value || '');
                        active.value = value.slice(0, start) + clipText + value.slice(end);
                        const pos = start + clipText.length;
                        active.selectionStart = pos;
                        active.selectionEnd = pos;
                        active.dispatchEvent(new Event('input', { bubbles: true }));
                        return true;
                    }
                }
                return false;
            })()`;
            try { await webview.executeJavaScript(script, true); } catch (_) { }
        };

        void run();
        return true;
    }

    document.addEventListener('keydown', e => {
        const ctrl = e.ctrlKey || e.metaKey; const shift = e.shiftKey;
        // Never intercept clipboard/undo/redo — let OS and webview handle natively
        // Also skip all Ctrl shortcuts when focus is in input/textarea to allow paste etc.
        const isInput = e.target && (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable);
        if (ctrl && !shift && ['c', 'C', 'v', 'V', 'x', 'X', 'a', 'A', 'z', 'Z', 'y', 'Y'].includes(e.key)) {
            const key = String(e.key || '').toLowerCase();
            const action = key === 'c' ? 'copy' : key === 'v' ? 'paste' : key === 'x' ? 'cut' : key === 'a' ? 'selectAll' : '';
            if (!isInput && action && forwardClipboardShortcutToActiveWebview(action)) {
                e.preventDefault();
                return;
            }
            return;
        }
        if (isInput && ctrl) return; // Allow all Ctrl+key in inputs
        if (ctrl && e.key === 't') { e.preventDefault(); createTab(); }
        else if (ctrl && e.key === 'w') { e.preventDefault(); closeTab(STATE.activeTabId); }
        else if (ctrl && e.key === 'r') { e.preventDefault(); document.getElementById('btnReload').click(); }
        else if (ctrl && e.key === 'f') { e.preventDefault(); openFind(); }
        else if (ctrl && e.key === 'd') { e.preventDefault(); addBookmark(); }
        else if (ctrl && e.key === 'h') { e.preventDefault(); renderHistoryPanel(); togglePanel('histPanel'); }
        else if (ctrl && e.key === 'b') { e.preventDefault(); renderBookmarksPanel(); togglePanel('bmPanel'); }
        else if (ctrl && e.key === 'j') { e.preventDefault(); togglePanel('dlPanel'); }
        else if (ctrl && e.key === 'l') { e.preventDefault(); urlInput.focus(); urlInput.select(); }
        else if (ctrl && (e.key === '=' || e.key === '+')) { e.preventDefault(); setZoom(STATE.zoom + 10); }
        else if (ctrl && e.key === '-') { e.preventDefault(); setZoom(STATE.zoom - 10); }
        else if (ctrl && e.key === '0') { e.preventDefault(); setZoom(100); }
        else if (ctrl && !shift && e.key === 'm') { e.preventDefault(); if (typeof window.startTkaiScanShortcut === 'function') window.startTkaiScanShortcut(); }
        else if (ctrl && shift && e.key === 'M') { e.preventDefault(); toggleRespMode(); }
        else if (ctrl && shift && e.key === '\\') { e.preventDefault(); toggleTabOverview(); }
        else if (ctrl && shift && e.key === 'D') { e.preventDefault(); const cur = DB.getSettings().pageDarkMode || false; applyPageDarkMode(!cur); }
        else if (ctrl && shift && (e.key === 'A' || e.key === 'a')) { e.preventDefault(); summarizeCurrentPage(); }
        else if (ctrl && e.key === 'Tab') { e.preventDefault(); document.getElementById('mi-next-tab').click(); }
        else if (ctrl && shift && e.key === 'Tab') { e.preventDefault(); document.getElementById('mi-prev-tab').click(); }
        else if (e.key === 'F12') { e.preventDefault(); toggleDevtools(); }
        else if (e.key === 'F11') { e.preventDefault(); document.getElementById('mi-fullscreen').click(); }
        else if ((function () {
            const sc = (DB.getSettings().screenshotShortcut || 'Ctrl+Shift+S').split('+');
            const needCtrl = sc.includes('Ctrl'), needAlt = sc.includes('Alt'), needShift = sc.includes('Shift');
            const mainKey = sc.filter(k => !['Ctrl', 'Alt', 'Shift'].includes(k))[0] || '';
            return ctrl === needCtrl && e.altKey === needAlt && shift === needShift && (e.key === mainKey || e.key.toUpperCase() === mainKey.toUpperCase());
        })()) { e.preventDefault(); startRegionScreenshot(); } // default: rectangle region screenshot
        else if (e.key === 'F5' && shift) {
            e.preventDefault();
            // Hard reload: clear document cookies for current tab then reload
            const tab = getActiveTab();
            const host = tab?.url ? (() => { try { return new URL(tab.url).hostname; } catch (e2) { return ''; } })() : '';
            document.cookie.split(';').forEach(c => {
                const name = c.trim().split('=')[0];
                if (name) { document.cookie = name + '=;expires=Thu, 01 Jan 1970 00:00:00 GMT;path=/'; document.cookie = name + '=;expires=Thu, 01 Jan 1970 00:00:00 GMT;path=/;domain=' + host; }
            });
            document.getElementById('btnReload').click();
            showToast('🍪 Cookies cleared — reloading…');
        }
        else if (e.key === 'F5') { e.preventDefault(); document.getElementById('btnReload').click(); }
        else if (e.key === 'Escape') { closeFind(); closeAllPanels(); ctxMenu.classList.remove('show'); document.getElementById('tabOverview').classList.remove('show'); }
        else if (e.altKey && e.key === 'ArrowLeft') { document.getElementById('btnBack').click(); }
        else if (e.altKey && e.key === 'ArrowRight') { document.getElementById('btnFwd').click(); }
        else if (!ctrl && !e.altKey && !isInput && e.key.length === 1 && e.key !== ' ') {
            // Redirect typing to URL bar when on a blank/NTP tab
            const activeTab = STATE.tabs.find(t => t.id === STATE.activeTabId);
            if (!activeTab?.url) {
                e.preventDefault();
                const inp = document.getElementById('urlInput');
                if (inp) { inp.focus(); inp.value = e.key; inp.setSelectionRange(1, 1); }
            }
        }
    });
