        tabGeneral: 'general', tabUpdates: 'updates', tabTabs: 'tabs', tabAutofill: 'autofill', tabPasswords: 'passwords',
        tabSearch: 'search', tabSecurity: 'security', tabPrivacy: 'privacy', tabWebsites: 'websites',
