    function syncTkaiLanguageSelects(langPack = LANGS.en) {
        const replySel = document.querySelector('#stab-ai-live-chat [data-setting="tkaiReplyLang"]');
        const readSel = document.querySelector('#stab-ai-live-chat [data-setting="tkaiReadLang"]');
        const translateSel = document.querySelector('#stab-ai-live-chat [data-setting="tkaiTranslateLang"]');
        if (!replySel || !readSel || !translateSel) return;

        const settings = DB.getSettings();
        const prevReply = replySel.value || settings.tkaiReplyLang || 'en_auto';
        const prevRead = readSel.value || settings.tkaiReadLang || 'auto';
        const prevTranslate = translateSel.value || settings.tkaiTranslateLang || 'auto';

        const langOptions = Object.entries(LANGS).map(([code, data]) => {
            const name = (data && data.name) ? data.name : code.toUpperCase();
            return `<option value="${code}">${name}</option>`;
        }).join('');

        replySel.innerHTML = `<option value="en_auto">${langPack.tkaiReplyLangEnglishAuto || LANGS.en.tkaiReplyLangEnglishAuto || 'English (AUTO)'}</option><option value="auto">${langPack.tkaiAutoMatchChatLang || LANGS.en.tkaiAutoMatchChatLang || 'Auto (match chat language)'}</option><option value="read">${langPack.tkaiReplyLangReadLang || LANGS.en.tkaiReplyLangReadLang || 'Same as reading language'}</option>${langOptions}`;
        readSel.innerHTML = `<option value="auto">${langPack.tkaiAutoDetectLang || LANGS.en.tkaiAutoDetectLang || 'Auto-detect'}</option>${langOptions}`;
        translateSel.innerHTML = `<option value="auto">${langPack.tkaiTranslateLangAutoRead || LANGS.en.tkaiTranslateLangAutoRead || 'Auto (use reading language)'}</option>${langOptions}`;

        const allowedReply = new Set(['en_auto', 'auto', 'read', ...Object.keys(LANGS)]);
        replySel.value = allowedReply.has(prevReply) ? prevReply : 'en_auto';
        readSel.value = LANGS[prevRead] || prevRead === 'auto' ? prevRead : 'auto';
        translateSel.value = LANGS[prevTranslate] || prevTranslate === 'auto' ? prevTranslate : 'auto';
    }

    function applyLanguage(code) {
        const lang = { ...LANGS.en, ...(LANGS[code] || {}) };
        // Helper: replace the visible label text of an element, preserving child spans
        function setLabel(el, text) {
            // Remove existing text nodes only (keep child elements like .icon, .sc, .sit-icon)
            Array.from(el.childNodes).filter(n => n.nodeType === 3).forEach(n => n.remove());
            // Find insertion point — only look at DIRECT children to avoid NotFoundError
            const iconSpan = Array.from(el.children).find(c => c.classList.contains('icon') || c.classList.contains('sit-icon'));
            const textNode = document.createTextNode(text);
            if (iconSpan && iconSpan.nextSibling) {
                el.insertBefore(textNode, iconSpan.nextSibling);
            } else if (iconSpan) {
                el.appendChild(textNode);
            } else {
                // For menu-item top labels (data-menu), insert before .dropdown
                const dropdown = Array.from(el.children).find(c => c.classList.contains('dropdown'));
                if (dropdown) { el.insertBefore(textNode, dropdown); }
                else { el.prepend(textNode); }
            }
        }
        // Menu items — preserve icons (span.icon) and shortcuts (span.sc)
        Object.entries(LANG_MAP).forEach(([key, sel]) => {
            if (!lang[key]) return;
            document.querySelectorAll(sel).forEach(el => setLabel(el, lang[key]));
        });
        // Settings sidebar tab buttons
        Object.entries(LANG_TAB_MAP).forEach(([key, stab]) => {
            if (!lang[key]) return;
            const btn = document.querySelector(`.sit-btn[data-stab="${stab}"]`);
            if (btn) setLabel(btn, lang[key]);
        });
        // Settings panel title
        const sTitle = document.querySelector('#settingsPanel .panel-title');
        if (sTitle && lang.settingsTitle) sTitle.textContent = lang.settingsTitle;
        // Generic data-i18n handling
        document.querySelectorAll('[data-i18n]').forEach(el => {
            const key = el.dataset.i18n;
            if (lang[key]) {
                if (el.tagName === 'INPUT' && (el.type === 'button' || el.type === 'submit')) el.value = lang[key];
                else if (el.tagName === 'INPUT' && el.placeholder) el.placeholder = lang[key];
                else if (el.tagName === 'TEXTAREA' && Object.prototype.hasOwnProperty.call(el, 'placeholder')) el.placeholder = lang[key];
                else if (el.tagName === 'OPTION') el.textContent = lang[key];
                else setLabel(el, lang[key]);
            }
        });
        // Language preview
        ['lp-file', 'lp-edit', 'lp-view', 'lp-history', 'lp-bookmarks',
            'lp-settings', 'lp-general', 'lp-appearance', 'lp-language',
            'lp-newTab', 'lp-closeTab', 'lp-bookmarkPage'].forEach(id => {
                const el = document.getElementById(id);
                if (el && lang[id]) el.textContent = lang[id];
            });
        const prevDesc = document.getElementById('langPreviewDesc');
        if (prevDesc) prevDesc.textContent = lang.preview || '';
        syncTkaiLanguageSelects(lang);
        // Persist
        DB.saveSetting('uiLanguage', code);
    }

    (function initLanguage() {
        const sel = document.getElementById('langSelect');
        if (!sel) return;
        // Keep language list in sync with LANGS map.
        sel.innerHTML = Object.entries(LANGS)
            .map(([code, data]) => `<option value="${code}">${data.flag || '🌐'} ${data.name || code}</option>`)
            .join('');
        const saved = DB.getSettings().uiLanguage || 'en';
        const initial = LANGS[saved] ? saved : 'en';
        sel.value = initial;
        applyLanguage(initial);
        sel.addEventListener('change', () => { applyLanguage(sel.value); showToast(LANGS[sel.value]?.flag + ' ' + LANGS[sel.value]?.name + ' applied'); });
        // Download button (simulates caching — stores flag in settings)
        document.getElementById('langDownloadBtn')?.addEventListener('click', () => {
            const code = sel.value;
            const status = document.getElementById('langStatusRow');
            if (status) { status.style.display = ''; status.textContent = '⏳ Downloading ' + LANGS[code]?.name + ' pack…'; }
            setTimeout(() => {
                DB.saveSetting('langPack_' + code, true);
                if (status) { status.textContent = '✅ ' + LANGS[code]?.name + ' language pack cached offline.'; }
                showToast('✅ ' + LANGS[code]?.name + ' language pack ready');
            }, 1200);
        });
    })();

