    function openCustomToolbar() {
        const overlay = document.getElementById('customToolbarOverlay');
        const grid = document.getElementById('cttGrid');
        if (!overlay || !grid) return;
        const settings = DB.getSettings();
        grid.innerHTML = '';
        // Load saved order from localStorage
        let savedOrder = [];
        try { savedOrder = JSON.parse(localStorage.getItem('ex_toolbar_order') || '[]'); } catch (_) { }
        // Sort CTT_BUTTONS by saved order, appending any not yet saved
        const orderedButtons = savedOrder.length
            ? [...savedOrder.map(key => CTT_BUTTONS.find(b => b.key === key)).filter(Boolean),
            ...CTT_BUTTONS.filter(b => !savedOrder.includes(b.key))]
            : CTT_BUTTONS;
        let _cttDragSrc = null;
        orderedButtons.forEach(def => {
            const isOn = settings[def.key] !== false;
            const btn = document.getElementById(def.id);
            const tile = document.createElement('div');
            tile.className = 'ctt-tile' + (isOn ? '' : ' disabled');
            tile.dataset.key = def.key;
            tile.dataset.id = def.id;
            tile.draggable = true;
            // Use actual button icon if button exists and has text
            const liveIcon = btn ? (btn.textContent.trim().charAt(0) || def.icon) : def.icon;
            tile.innerHTML = `<div class="ctt-tile-icon">${liveIcon}</div><div class="ctt-tile-name">${def.name}</div><div class="ctt-tile-dot"></div>`;
            // Toggle on/off click
            tile.addEventListener('click', () => {
                const on = !tile.classList.contains('disabled');
                const newOn = !on;
                tile.classList.toggle('disabled', !newOn);
                DB.saveSetting(def.key, newOn);
                if (btn) btn.style.display = newOn ? '' : 'none';
                const settingToggle = document.querySelector(`#stab-appearance .toggle[data-setting="${def.key}"]`);
                if (settingToggle) { newOn ? settingToggle.classList.add('on') : settingToggle.classList.remove('on'); }
            });
            // Drag-and-drop reordering
            tile.addEventListener('dragstart', (e) => {
                _cttDragSrc = tile;
                e.dataTransfer.effectAllowed = 'move';
                setTimeout(() => tile.classList.add('dragging'), 0);
            });
            tile.addEventListener('dragend', () => {
                tile.classList.remove('dragging');
                grid.querySelectorAll('.ctt-tile').forEach(t => t.classList.remove('drag-over'));
            });
            tile.addEventListener('dragover', (e) => {
                e.preventDefault();
                e.dataTransfer.dropEffect = 'move';
                if (_cttDragSrc && _cttDragSrc !== tile) tile.classList.add('drag-over');
            });
            tile.addEventListener('dragleave', () => tile.classList.remove('drag-over'));
            tile.addEventListener('drop', (e) => {
                e.preventDefault();
                e.stopPropagation();
                if (_cttDragSrc && _cttDragSrc !== tile) {
                    const tiles = [...grid.querySelectorAll('.ctt-tile')];
                    const srcIdx = tiles.indexOf(_cttDragSrc);
                    const dstIdx = tiles.indexOf(tile);
                    if (srcIdx < dstIdx) tile.after(_cttDragSrc); else tile.before(_cttDragSrc);
                    const newOrder = [...grid.querySelectorAll('.ctt-tile')].map(t => t.dataset.key);
                    localStorage.setItem('ex_toolbar_order', JSON.stringify(newOrder));
                    _applyToolbarOrder(newOrder);
                }
                tile.classList.remove('drag-over');
            });
            grid.appendChild(tile);
        });
        overlay.classList.add('show');
        // Close any open dropdowns
        document.querySelectorAll('.menu-item.open').forEach(m => m.classList.remove('open'));
    }

    function _applyToolbarOrder(orderedKeys) {
        const keyToId = Object.fromEntries(CTT_BUTTONS.map(b => [b.key, b.id]));
        const cttIdSet = new Set(CTT_BUTTONS.map(b => b.id));
        // Build ordered element array
        const ordered = orderedKeys.map(k => document.getElementById(keyToId[k] || '')).filter(Boolean);
        CTT_BUTTONS.forEach(b => { if (!orderedKeys.includes(b.key)) { const el = document.getElementById(b.id); if (el && !ordered.includes(el)) ordered.push(el); } });
        if (!ordered.length) return;
        const parent = ordered[0].parentNode;
        if (!parent) return;
        // Find first non-CTT sibling (will be anchor after we remove CTT buttons)
        const siblings = Array.from(parent.children);
        const firstCttIdx = siblings.findIndex(n => cttIdSet.has(n.id));
        if (firstCttIdx === -1) return;
        let anchor = null;
        for (let i = firstCttIdx; i < siblings.length; i++) {
            if (!cttIdSet.has(siblings[i].id)) { anchor = siblings[i]; break; }
        }
        // Detach all CTT buttons and re-insert in new order
        ordered.forEach(el => el.parentNode && el.parentNode.removeChild(el));
        ordered.forEach(el => { if (anchor && anchor.parentNode === parent) parent.insertBefore(el, anchor); else parent.appendChild(el); });
    }

