    // ── Profile Dropdown in Title Bar ──
    (function initProfileDropdown() {
        const btn = document.getElementById('titleProfileBtn');
        const dd = document.getElementById('profileDropdown');
        const nameEl = document.getElementById('activeProfileName');
        if (!btn || !dd) return;
        const ACTIVE_KEY = 'ex_active_profile';
        function getProfiles() {
            const defName = localStorage.getItem('ex_default_persona_name') || 'Default';
            return [{ name: defName, ts: 0 }].concat(JSON.parse(localStorage.getItem('ex_profiles') || '[]'));
        }
        function getActive() {
            const defName = localStorage.getItem('ex_default_persona_name') || 'Default';
            return localStorage.getItem(ACTIVE_KEY) || defName;
        }
        function setActive(name) { localStorage.setItem(ACTIVE_KEY, name); nameEl.textContent = name; }
        window.refreshProfileDropdown = function render() {
            const profiles = getProfiles();
            const active = getActive();
            nameEl.textContent = active;
            dd.innerHTML = '';
            profiles.forEach(p => {
                const item = document.createElement('div'); item.className = 'pd-item' + (p.name === active ? ' active' : '');
                item.innerHTML = (p.name === active ? '✓ ' : ' ') + p.name;
                item.addEventListener('click', () => { setActive(p.name); dd.classList.remove('open'); showToast('👤 Profile: ' + p.name); window.refreshProfileDropdown(); window.refreshSettingsProfiles?.(); });
                dd.appendChild(item);
            });
            const sep = document.createElement('div'); sep.className = 'pd-sep'; dd.appendChild(sep);
            const manage = document.createElement('div'); manage.className = 'pd-item';
            manage.innerHTML = '⚙ Manage Profiles…';
            manage.addEventListener('click', () => {
                dd.classList.remove('open');
                if (window.openSettingsTab) window.openSettingsTab('profiles');
            });
            dd.appendChild(manage);
        }
        btn.addEventListener('click', e => { e.stopPropagation(); dd.classList.toggle('open'); window.refreshProfileDropdown(); });
        document.addEventListener('click', () => dd.classList.remove('open'));
        dd.addEventListener('click', e => e.stopPropagation());
        window.refreshProfileDropdown();
    })();

