    // ── Restore last session tabs ─────────────────────────────────────────────
    (function restoreSession() {
        const _hash = window.location.hash.slice(1);

        // Handle fresh new window (should not restore previous session)
        if (_hash === 'fresh-window') {
            createTab();
            renderQuickLinks();
            history.replaceState(null, '', window.location.pathname);
            consoleLog('info', '🆕 New window opened (empty)');
            consoleLog('success', '⬡ Web3 provider: window.ethereum injected');
            return;
        }

        // Handle new window with specific URL
        if (_hash.startsWith('new-window=')) {
            const _url = decodeURIComponent(_hash.slice('new-window='.length));
            createTab(_url || '');
            renderQuickLinks();
            history.replaceState(null, '', window.location.pathname);
            consoleLog('info', '🪟 New window opened with URL: ' + _url);
            consoleLog('success', '⬡ Web3 provider: window.ethereum injected');
            return;
        }

        // Handle split screen left window (load specific tab)
        if (_hash.startsWith('split-left=')) {
            const _url = decodeURIComponent(_hash.slice('split-left='.length));
            createTab(_url || '');
            renderQuickLinks();
            history.replaceState(null, '', window.location.pathname);
            consoleLog('info', '▥ Split screen left window: ' + _url);
            consoleLog('success', '⬡ Web3 provider: window.ethereum injected');
            return;
        }

        // Handle "Move Tab to New Window" launch: hash = #move-tab=<encoded-url>
        if (_hash.startsWith('move-tab=')) {
            const _movedUrl = decodeURIComponent(_hash.slice('move-tab='.length));
            createTab(_movedUrl || '');
            renderQuickLinks();
            history.replaceState(null, '', window.location.pathname);
            consoleLog('info', '🪟 Tab moved to new window' + (_movedUrl ? ': ' + _movedUrl : ''));
            consoleLog('success', '⬡ Web3 provider: window.ethereum injected');
            return;
        }

        const cfg = DB.getSettings();
        const normalizeMode = (value, kind) => {
            const v = String(value || '').trim().toLowerCase();
            if (!v) return '';
            if (kind === 'opensWith') {
                if (v === 'last-session' || v === 'all windows from last session' || v === 'svi prozori iz zadnje sesije' || v === 'svim prozorima iz zadnje sesije') return 'last-session';
                if (v === 'new-window' || v === 'a new window' || v === 'novi prozor' || v === 'novim prozorom') return 'new-window';
                if (v === 'new-private-window' || v === 'a new private window' || v === 'novi privatni prozor' || v === 'novim privatnim prozorom') return 'new-private-window';
            }
            if (kind === 'newWindowWith' || kind === 'newTabWith') {
                if (v === 'start-page' || v === 'start page' || v === 'početna stranica (etherx)' || v === 'početnom stranicom') return 'start-page';
                if (v === 'homepage' || v === 'početnom stranicom (adresa)' || v === 'početna stranica') return 'homepage';
                if (v === 'empty-page' || v === 'empty page' || v === 'praznom stranicom' || v === 'prazna stranica') return 'empty-page';
                if (v === 'same-page' || v === 'same page' || v === 'istom stranicom') return 'same-page';
            }
            return v;
        };

        // Determine initial URL based on "New Window" settings
        const getInitialUrl = () => {
            const winMode = normalizeMode(cfg.newWindowWith, 'newWindowWith');
            if (winMode === 'homepage' && cfg.homepage) return cfg.homepage;
            if (winMode === 'empty-page') return 'about:blank';
            return ''; // Default to Start Page (NTP)
        };

        // If user set "opensWith" to something other than "All windows from last session", skip restore
        const opensWithMode = normalizeMode(cfg.opensWith, 'opensWith');
        if (cfg.opensWith && opensWithMode !== 'last-session') {
            const url = getInitialUrl();
            createTab(url); renderQuickLinks();
            consoleLog('info', '🚀 EtherX Browser initialized'); consoleLog('success', '⬡ Web3 provider: window.ethereum injected');
            return;
        }
        // Use window-specific keys to avoid overwriting state between windows
        let windowId = 'main';
        try {
            if (window.electronAPI && typeof window.electronAPI.windowId === 'function') {
                windowId = window.electronAPI.windowId() || 'main';
            }
        } catch (e) { }

        const saved = localStorage.getItem('ex_session_tabs_' + windowId) || localStorage.getItem('ex_session_tabs');
        const savedActiveIdx = parseInt(localStorage.getItem('ex_session_active_' + windowId) || localStorage.getItem('ex_session_active') || '0', 10);
        if (saved) {
            try {
                const tabs = JSON.parse(saved);
                if (Array.isArray(tabs) && tabs.length) {
                    const idMap = {};
                    tabs.forEach((t, i) => {
                        const tab = createTab('', t.title || 'New Tab', false);
                        tab.url = t.url || '';
                        if (t.pinned) tab.pinned = true;
                        if (t.faviconUrl) tab.faviconUrl = t.faviconUrl;
                        updateTabEl(tab);
                        idMap[i] = tab.id;
                    });
                    let activateId = idMap[0];
                    Object.keys(idMap).forEach(k => { if (parseInt(k) === savedActiveIdx || idMap[k] === savedActiveIdx) activateId = idMap[k]; });
                    switchTab(activateId || idMap[0]);
                    renderQuickLinks();
                    consoleLog('info', '🚀 EtherX Browser initialized – restored ' + tabs.length + ' tab(s)');
                    consoleLog('success', '⬡ Web3 provider: window.ethereum injected');
                    return;
                }
            } catch (e) {
                try {
                    localStorage.removeItem('ex_session_tabs_' + windowId);
                    localStorage.removeItem('ex_session_active_' + windowId);
                } catch (_) { }
            }
        }

        // localStorage was empty (e.g. after app update clears renderer origin).
        // Fall back to the SQLite autosave that was written by saveSessionTabs().
        if (window.electronAPI) {
            // Create a blank tab immediately so the UI is interactive while we await SQLite.
            const placeholderTab = createTab('', 'New Tab', true);
            renderQuickLinks();
            window.electronAPI.invoke('db:getSessions', 50).then(function (sessions) {
                if (!Array.isArray(sessions)) {
                    const url = getInitialUrl();
                    if (url) navigateTo(url, placeholderTab.id);
                    consoleLog('info', '🚀 EtherX Browser initialized'); consoleLog('success', '⬡ Web3 provider: window.ethereum injected');
                    return;
                }
                const autosave = sessions.find(s => s && (s.name === '__autosave_' + windowId || s.name === '__autosave_main'));
                if (!autosave) {
                    const url = getInitialUrl();
                    if (url) navigateTo(url, placeholderTab.id);
                    consoleLog('info', '🚀 EtherX Browser initialized'); consoleLog('success', '⬡ Web3 provider: window.ethereum injected');
                    return;
                }
                const tabs = Array.isArray(autosave.tabs) ? autosave.tabs : [];
                if (!tabs.length) {
                    const url = getInitialUrl();
                    if (url) navigateTo(url, placeholderTab.id);
                    consoleLog('info', '🚀 EtherX Browser initialized'); consoleLog('success', '⬡ Web3 provider: window.ethereum injected');
                    return;
                }
                // Remove placeholder tab, restore saved tabs
                closeTab(placeholderTab.id);
                localStorage.setItem('ex_session_tabs_' + windowId, JSON.stringify(tabs));
                if (autosave.activeTab !== undefined) localStorage.setItem('ex_session_active_' + windowId, autosave.activeTab);
                const idMap = {};
                tabs.forEach(function (t, i) {
                    const tab = createTab('', t.title || 'New Tab', false);
                    tab.url = t.url || '';
                    if (t.pinned) tab.pinned = true;
                    if (t.faviconUrl) tab.faviconUrl = t.faviconUrl;
                    updateTabEl(tab);
                    idMap[i] = tab.id;
                });
                const savedIdx = parseInt(autosave.activeTab || '0', 10);
                let activateId = idMap[0];
                Object.keys(idMap).forEach(function (k) { if (parseInt(k) === savedIdx) activateId = idMap[k]; });
                switchTab(activateId || idMap[0]);
                renderQuickLinks();
                consoleLog('info', '🚀 EtherX Browser initialized – restored ' + tabs.length + ' tab(s) from SQLite backup');
                consoleLog('success', '⬡ Web3 provider: window.ethereum injected');
            }).catch(function () {
                const url = getInitialUrl();
                if (url) navigateTo(url, placeholderTab.id);
                consoleLog('info', '🚀 EtherX Browser initialized'); consoleLog('success', '⬡ Web3 provider: window.ethereum injected');
            });
            return;
        }

        _startFresh();
        function _startFresh() {
            const url = getInitialUrl();
            createTab(url); renderQuickLinks();
            consoleLog('info', '🚀 EtherX Browser initialized'); consoleLog('success', '⬡ Web3 provider: window.ethereum injected');
        }
    })();

