    document.getElementById('wswNewTab').addEventListener('click', () => { createTab(); closeWindowSwitcher(); });

    // ── Logo Customization (Settings → General) ──────────────────────────────
    (function initLogoCustomization() {
        const LOGO_KEY = 'ex_custom_logo';
        const DEFAULT_LOGO_VALUE = 'logo_novi.png';
        const IMAGE_VALUE_REGEX = /^(data:image\/|file:\/\/|https?:\/\/|\.?\.?\/|\/|[a-zA-Z]:\\).+|.+\.(png|jpe?g|gif|webp|svg|ico)$/i;
        function applyLogo(val) {
            // val: emoji/text string or image path/data-url
            const titleLogo = document.getElementById('titleLogoBtn');
            const ntpLogo = document.getElementById('ntpLogo');
            const preview = document.getElementById('logoPreview');
            const isImageValue = !!val && IMAGE_VALUE_REGEX.test(val);
            [titleLogo, ntpLogo, preview].forEach(el => {
                if (!el) return;
                if (isImageValue) {
                    el.innerHTML = `<img src="${val}" style="width:100%;height:100%;object-fit:cover;border-radius:inherit">`;
                } else {
                    el.textContent = val || 'E';
                }
            });
        }
        // Load saved logo on startup
        const saved = localStorage.getItem(LOGO_KEY);
        if (saved) applyLogo(saved);
        else applyLogo(DEFAULT_LOGO_VALUE);

        // File upload
        document.getElementById('logoFileInput')?.addEventListener('change', e => {
            const file = e.target.files?.[0]; if (!file) return;
            if (!file.type.startsWith('image/')) { showToast('⚠️ Please choose an image file'); return; }
            const reader = new FileReader();
            reader.onload = ev => { const dataUrl = ev.target.result; localStorage.setItem(LOGO_KEY, dataUrl); applyLogo(dataUrl); showToast('✓ Logo updated'); };
            reader.readAsDataURL(file);
        });

        // Emoji / text input
        const emojiInput = document.getElementById('logoEmojiInput');
        document.getElementById('logoEmojiBtn')?.addEventListener('click', () => {
            emojiInput.style.display = emojiInput.style.display === 'none' ? '' : 'none';
            emojiInput.focus();
        });
        emojiInput?.addEventListener('input', () => {
            const v = emojiInput.value.trim();
            if (!v) return;
            localStorage.setItem(LOGO_KEY, v);
            applyLogo(v);
        });

        // Reset
        document.getElementById('logoResetBtn')?.addEventListener('click', () => {
            localStorage.removeItem(LOGO_KEY);
            applyLogo(DEFAULT_LOGO_VALUE);
            if (emojiInput) { emojiInput.value = ''; emojiInput.style.display = 'none'; }
            showToast('↺ Logo reset to default');
        });
    })();

    // ── Screenshot ──────────────────────────────────────────────────────────────
    async function takeScreenshot(fullPage = false) {
        const tab = getActiveTab();
        const pageTitle = (tab?.title || 'screenshot').replace(/[^a-z0-9]/gi, '-').slice(0, 24).replace(/-+$/, '');
        const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
        const filename = 'etherx-' + pageTitle + '-' + ts + '.png';
        const loc = (DB.getSettings().screenshotLocation) || 'download';

        showToast('📷 Snimam zaslon…');
        try {
            let canvas;
            const getFrame = () => document.getElementById('browseFrame');
            const frame = new Proxy({}, { get: (t, p) => typeof getFrame()[p] === "function" ? getFrame()[p].bind(getFrame()) : getFrame()[p], set: (t, p, v) => { getFrame()[p] = v; return true; } });
            if (window.html2canvas) {
                const target = fullPage ? document.documentElement : (frame || document.documentElement);
                canvas = await window.html2canvas(target, { useCORS: true, allowTaint: true, scale: window.devicePixelRatio || 1, logging: false });
            } else {
                // Fallback: blank canvas with URL text
                canvas = document.createElement('canvas');
                canvas.width = window.innerWidth;
                canvas.height = window.innerHeight;
                const ctx = canvas.getContext('2d');
                ctx.fillStyle = '#1a1a2e';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
                ctx.fillStyle = '#aaa';
                ctx.font = '14px sans-serif';
                ctx.fillText('📷 ' + (tab?.url || 'EtherX Browser'), 20, canvas.height / 2);
            }

            if (loc === 'clipboard') {
                canvas.toBlob(blob => {
                    navigator.clipboard.write([new ClipboardItem({ 'image/png': blob })])
                        .then(() => showToast('📋 Screenshot kopiran u međuspremnik!'))
                        .catch(() => {
                            // fallback — download instead
                            const url = URL.createObjectURL(blob);
                            const a = document.createElement('a'); a.href = url; a.download = filename; a.click();
                            URL.revokeObjectURL(url);
                            showToast('📷 Screenshot preuzet: ' + filename);
                        });
                });
            } else {
                canvas.toBlob(blob => {
                    const url = URL.createObjectURL(blob);
                    const a = document.createElement('a'); a.href = url; a.download = filename; a.click();
                    URL.revokeObjectURL(url);
                    showToast('📷 Screenshot preuzet: ' + filename);
                });
            }
        } catch (err) {
            showToast('⚠️ Screenshot neuspješan: ' + err.message);
        }
    }

    // Screenshot menu handlers
    document.getElementById('mi-screenshot')?.addEventListener('click', () => startRegionScreenshot()); // default: rectangle selection
    document.getElementById('mi-screenshot-full')?.addEventListener('click', () => takeScreenshot(true));
    document.getElementById('mi-screenshot-region')?.addEventListener('click', () => startRegionScreenshot());

    function startRegionScreenshot() {
        // Create overlay for region selection
        const overlay = document.createElement('div');
        overlay.id = 'screenshotRegionOverlay';
        Object.assign(overlay.style, { position: 'fixed', top: 0, left: 0, width: '100vw', height: '100vh', zIndex: 999999, cursor: 'crosshair', background: 'rgba(0,0,0,0.25)' });
        const box = document.createElement('div');
        Object.assign(box.style, { position: 'absolute', border: '2px dashed #00d4ff', background: 'rgba(0,212,255,0.1)', display: 'none' });
        overlay.appendChild(box);
        document.body.appendChild(overlay);
        let sx, sy, drawing = false;
        overlay.addEventListener('mousedown', e => { sx = e.clientX; sy = e.clientY; drawing = true; box.style.left = sx + 'px'; box.style.top = sy + 'px'; box.style.width = '0'; box.style.height = '0'; box.style.display = 'block'; });
        overlay.addEventListener('mousemove', e => { if (!drawing) return; const x = Math.min(e.clientX, sx), y = Math.min(e.clientY, sy); box.style.left = x + 'px'; box.style.top = y + 'px'; box.style.width = Math.abs(e.clientX - sx) + 'px'; box.style.height = Math.abs(e.clientY - sy) + 'px'; });
        overlay.addEventListener('mouseup', e => {
            drawing = false;
            overlay.remove();
            const rect = { x: Math.min(e.clientX, sx), y: Math.min(e.clientY, sy), width: Math.abs(e.clientX - sx), height: Math.abs(e.clientY - sy) };
            if (rect.width < 10 || rect.height < 10) { showToast('⚠️ Selection too small'); return; }
            // Electron path: use native capturePage
            if (window.electronAPI) {
                window.electronAPI.invoke('app:captureRegion', rect).then(dataUrl => {
                    if (!dataUrl) { showToast('⚠️ Capture failed'); return; }
                    const a = document.createElement('a'); a.href = dataUrl; a.download = 'etherx-region-' + Date.now() + '.png'; a.click();
                    showToast('📷 Region screenshot saved!');
                }).catch(() => showToast('⚠️ Capture failed'));
            } else {
                // Web fallback: use html2canvas on a clipped region
                takeRegionFallback(rect);
            }
        });
        const esc = e => { if (e.key === 'Escape') { overlay.remove(); document.removeEventListener('keydown', esc); } };
        document.addEventListener('keydown', esc);
    }
    async function takeRegionFallback(rect) {
        try {
            const canvas = await (window.html2canvas ? window.html2canvas(document.documentElement, { useCORS: true, allowTaint: true, scale: window.devicePixelRatio || 1, logging: false }) : Promise.reject('no html2canvas'));
            const dpr = window.devicePixelRatio || 1;
            const cropped = document.createElement('canvas');
            cropped.width = rect.width * dpr; cropped.height = rect.height * dpr;
            cropped.getContext('2d').drawImage(canvas, rect.x * dpr, rect.y * dpr, rect.width * dpr, rect.height * dpr, 0, 0, rect.width * dpr, rect.height * dpr);
            cropped.toBlob(blob => {
                const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = 'etherx-region-' + Date.now() + '.png'; a.click(); URL.revokeObjectURL(url);
                showToast('📷 Region screenshot saved!');
            });
        } catch (e) { showToast('⚠️ Region screenshot failed'); }
    }

    // Screenshot shortcut recorder (Settings → Advanced)
    (function initScreenshotSettings() {
        const input = document.getElementById('screenshotShortcutInput');
        const resetBtn = document.getElementById('screenshotShortcutReset');
        const DEFAULT_SC = 'Ctrl+Shift+S';

        function loadShortcut() {
            const saved = DB.getSettings().screenshotShortcut || DEFAULT_SC;
            if (input) input.value = saved;
            const scEl = document.getElementById('mi-screenshot-sc');
            if (scEl) scEl.textContent = saved;
            const helpEl = document.getElementById('help-sc-screenshot');
            if (helpEl) helpEl.textContent = saved;
        }
        loadShortcut();

        if (input) {
            input.addEventListener('focus', () => { input.value = '⌨ Press keys…'; input.style.borderColor = 'var(--accent)'; });
            input.addEventListener('blur', () => { input.style.borderColor = ''; loadShortcut(); });
            input.addEventListener('keydown', e => {
                e.preventDefault();
                e.stopPropagation();
                const parts = [];
                if (e.ctrlKey) parts.push('Ctrl');
                if (e.altKey) parts.push('Alt');
                if (e.shiftKey) parts.push('Shift');
                const key = e.key;
                if (!['Control', 'Alt', 'Shift', 'Meta'].includes(key)) {
                    parts.push(key.length === 1 ? key.toUpperCase() : key);
                }
                if (parts.length >= 2) {
                    const combo = parts.join('+');
                    DB.saveSetting('screenshotShortcut', combo);
                    input.value = combo;
                    input.style.borderColor = 'var(--green,#4caf50)';
                    const scEl = document.getElementById('mi-screenshot-sc');
                    if (scEl) scEl.textContent = combo;
                    const helpEl = document.getElementById('help-sc-screenshot');
                    if (helpEl) helpEl.textContent = combo;
                    showToast('⌨ Screenshot prečac: ' + combo);
                    input.blur();
                }
            });
        }

        if (resetBtn) {
            resetBtn.addEventListener('click', () => {
                DB.saveSetting('screenshotShortcut', DEFAULT_SC);
                loadShortcut();
                showToast('↺ Screenshot prečac resetiran na ' + DEFAULT_SC);
            });
        }

        // Screenshot location select
        const locSel = document.getElementById('screenshotLocation');
        if (locSel) {
            const saved = DB.getSettings().screenshotLocation || 'download';
            Array.from(locSel.options).forEach(opt => { opt.selected = opt.value === saved; });
            locSel.addEventListener('change', () => {
                DB.saveSetting('screenshotLocation', locSel.value);
                showToast('📷 Lokacija screenshota: ' + locSel.options[locSel.selectedIndex].text);
            });
        }
    })();

    // ── Settings: icon tab switching + s-tab-pane ──────────────────────────────

    // ── Storage Management ────────────────────────────────────────────────────
    const STORE_DEFS = [
        { id: 'hist', label: '🕒 History', defaultKey: 'ex_hist' },
        { id: 'bm', label: '⭐ Bookmarks', defaultKey: 'ex_bm' },
        { id: 'cfg', label: '⚙️ Settings', defaultKey: 'ex_cfg' },
        { id: 'user', label: '👤 User Profile', defaultKey: 'ex_user' },
        { id: 'notes', label: '📝 Notes', defaultKey: 'ex_notes' },
        { id: 'dl', label: '⬇️ Downloads', defaultKey: 'ex_dl' },
        { id: 'passwords', label: '🔑 Passwords', defaultKey: 'ex_passwords' },
        { id: 'sessions', label: '🗄️ Sessions', defaultKey: 'ex_sessions' },
        { id: 'ai_chat', label: '🤖 AI Cache / Chat', defaultKey: 'ex_ai_chat' },
        { id: 'storage_cfg', label: '🗺️ Storage Config', defaultKey: 'ex_storage_cfg' },
    ];

    function refreshStorageUsage() {
        const t = document.getElementById('storageUsageTable'); if (!t) return;
        // Visual feedback so the user knows the refresh ran
        const btn = document.getElementById('btnRefreshStorage');
        if (btn) { btn.textContent = '↺ ...'; btn.disabled = true; }

        let totalBytes = 0;
        const knownKeys = new Set(STORE_DEFS.map(s => DB.getStorageKey(s.id)));
        const rows = STORE_DEFS.map(s => {
            const key = DB.getStorageKey(s.id);
            const raw = localStorage.getItem(key) || '';
            const bytes = new Blob([raw]).size;
            totalBytes += bytes;
            return { label: s.label, key, bytes };
        });
        // Include any extra keys not in STORE_DEFS
        Object.keys(localStorage).filter(k => !knownKeys.has(k)).forEach(k => {
            const raw = localStorage.getItem(k) || '';
            const bytes = new Blob([raw]).size;
            totalBytes += bytes;
            rows.push({ label: '📎 ' + k, key: k, bytes });
        });
        const fmt = b => b < 1024 ? b + ' B' : b < 1048576 ? (b / 1024).toFixed(1) + ' KB' : (b / 1048576).toFixed(2) + ' MB';
        const now = new Date().toLocaleTimeString();
        t.innerHTML = `<table style="width:100%;border-collapse:collapse;font-size:11px;color:var(--text2)">
        <thead><tr style="border-bottom:1px solid var(--border2);color:var(--text3)"><th style="text-align:left;padding:4px 8px">Store</th><th style="text-align:left;padding:4px 8px">Key</th><th style="text-align:right;padding:4px 8px">Veličina</th><th style="text-align:right;padding:4px 8px">%</th></tr></thead>
        <tbody>` +
            rows.map(r => `<tr style="border-bottom:1px solid rgba(255,255,255,.04)">
          <td style="padding:3px 8px">${r.label}</td>
          <td style="padding:3px 8px;color:var(--accent);font-family:monospace">${escHtml(r.key)}</td>
          <td style="padding:3px 8px;text-align:right;color:var(--text3)">${fmt(r.bytes)}</td>
          <td style="padding:3px 8px;text-align:right;color:var(--text3)">${totalBytes ? ((r.bytes / totalBytes * 100).toFixed(1)) : '0'}%</td>
        </tr>`).join('') +
            `<tr style="border-top:1px solid var(--border2);font-weight:600"><td colspan="2" style="padding:4px 8px;color:var(--text)">Ukupno localStorage</td><td colspan="2" style="padding:4px 8px;text-align:right;color:var(--text)">${fmt(totalBytes)}</td></tr>
        </tbody></table>
        <div style="font-size:10px;color:var(--text3);margin-top:4px;text-align:right">Ažurirano: ${now}</div>`;

        // Also query full origin storage estimate (includes IndexedDB, SQLite, Cache API)
        if (navigator.storage && navigator.storage.estimate) {
            navigator.storage.estimate().then(est => {
                const used = fmt(est.usage || 0);
                const quota = fmt(est.quota || 0);
                const bar = document.getElementById('storageEstimateBar');
                if (bar) bar.innerHTML = `<div style="font-size:11px;color:var(--text2);margin-top:6px;padding:6px 8px;background:rgba(255,255,255,.04);border-radius:6px;border:1px solid var(--border2)">
            📦 <b>Ukupna pohrana (sve):</b> ${used} / ${quota}
            &nbsp;<span style="color:var(--text3)">— uključuje SQLite, IndexedDB, Cache API</span></div>`;
            }).catch(() => { });
        }

        if (btn) {
            setTimeout(() => { btn.textContent = '↺ Refresh'; btn.disabled = false; }, 400);
        }
    }

    function initStorageTab() {
        // Key mapping table
        const kt = document.getElementById('storageKeyTable'); if (!kt) return;
        kt.innerHTML = STORE_DEFS.map(s => {
            const key = DB.getStorageKey(s.id);
            return `<div style="display:flex;align-items:center;gap:8px;padding:4px 0;border-bottom:1px solid rgba(255,255,255,.04)">
          <span style="flex:1;font-size:12px;color:var(--text2)">${s.label}</span>
          <input id="storekey_${s.id}" value="${escHtml(key)}" style="width:140px;background:var(--bg3);border:1px solid var(--border2);border-radius:6px;color:var(--text);padding:4px 8px;font-size:11px;font-family:monospace">
          <button onclick="_saveStoreKey('${s.id}')" style="font-size:11px;padding:4px 8px;background:var(--accent);border:none;border-radius:6px;color:#fff;cursor:pointer">Save</button>
          <button onclick="_migrateStore('${s.id}')" style="font-size:11px;padding:4px 8px;background:rgba(255,255,255,.06);border:1px solid var(--border2);border-radius:6px;color:var(--text2);cursor:pointer">Migrate</button>
        </div>`;
        }).join('');

        // Export/Import list
        const el = document.getElementById('storeExportList'); if (!el) return;
        el.innerHTML = STORE_DEFS.map(s => `
        <div style="display:flex;align-items:center;gap:8px">
          <span style="flex:1;font-size:12px;color:var(--text2)">${s.label}</span>
          <button onclick="_exportStore('${s.id}')" style="font-size:11px;padding:4px 10px;background:rgba(255,255,255,.06);border:1px solid var(--border2);border-radius:6px;color:var(--text2);cursor:pointer">📤 Export</button>
          <button onclick="_importStore('${s.id}')" style="font-size:11px;padding:4px 10px;background:rgba(255,255,255,.06);border:1px solid var(--border2);border-radius:6px;color:var(--text2);cursor:pointer">📥 Import</button>
        </div>`).join('');

        // Clear list
        const cl = document.getElementById('storeClearList'); if (!cl) return;
        cl.innerHTML = STORE_DEFS.map(s => `
        <button onclick="_clearStore('${s.id}')" style="font-size:11px;padding:4px 10px;background:rgba(192,57,43,.1);border:1px solid rgba(192,57,43,.3);border-radius:6px;color:#e74c3c;cursor:pointer">
          🗑 ${s.label}
        </button>`).join('');

        refreshStorageUsage();
    }

    function _saveStoreKey(storeId) {
        const input = document.getElementById('storekey_' + storeId);
        if (!input) return;
        const newKey = input.value.trim();
        if (!newKey) { showToast('⚠️ Key cannot be empty'); return; }
        DB.setStorageKey(storeId, newKey);
        initStorageTab();
    }

    function _migrateStore(storeId) {
        const oldKey = DB.getStorageKey(storeId);
        const input = document.getElementById('storekey_' + storeId);
        const newKey = input?.value?.trim() || oldKey;
        if (oldKey === newKey) { showToast('⚠️ Keys are identical — nothing to migrate'); return; }
        const data = localStorage.getItem(oldKey);
        if (data === null) { showToast('⚠️ No data found at key: ' + oldKey); return; }
        localStorage.setItem(newKey, data);
        localStorage.removeItem(oldKey);
        DB.setStorageKey(storeId, newKey);
        refreshStorageUsage();
        showToast('✅ Migrated "' + oldKey + '" → "' + newKey + '"');
    }

    function _exportStore(storeId) {
        const key = DB.getStorageKey(storeId);
        const data = localStorage.getItem(key);
        if (!data) { showToast('⚠️ No data to export for: ' + key); return; }
        const def = STORE_DEFS.find(s => s.id === storeId);
        const filename = 'etherx-' + storeId + '-' + new Date().toISOString().slice(0, 10) + '.json';
        const blob = new Blob([data], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a'); a.href = url; a.download = filename; a.click();
        URL.revokeObjectURL(url);
        showToast('📤 Exported: ' + filename);
    }

    function _importStore(storeId) {
        const key = DB.getStorageKey(storeId);
        const input = document.createElement('input');
        input.type = 'file'; input.accept = '.json,application/json';
        input.onchange = e => {
            const file = e.target.files[0]; if (!file) return;
            const reader = new FileReader();
            reader.onload = ev => {
                try {
                    JSON.parse(ev.target.result); // validate JSON
                    if (!confirm('Import into "' + key + '"? This will REPLACE existing data.')) return;
                    localStorage.setItem(key, ev.target.result);
                    refreshStorageUsage();
                    showToast('📥 Imported into: ' + key);
                } catch (err) { showToast('⚠️ Invalid JSON file: ' + err.message); }
            };
            reader.readAsText(file);
        };
        input.click();
    }

    function _clearStore(storeId) {
        const key = DB.getStorageKey(storeId);
        const def = STORE_DEFS.find(s => s.id === storeId);
        if (!confirm('Clear all data in ' + (def?.label || key) + ' (' + key + ')?\nThis cannot be undone.')) return;
        localStorage.removeItem(key);
        refreshStorageUsage();
        showToast('🗑 Cleared: ' + key);
    }

    // Init storage tab when it becomes active
    document.querySelectorAll('.sit-btn[data-stab="storage"]').forEach(btn => {
        btn.addEventListener('click', () => setTimeout(initStorageTab, 50));
    });
    // Wire Refresh button via JS to avoid any inline-onclick scope issues
    document.addEventListener('click', e => {
        if (e.target && e.target.id === 'btnRefreshStorage') refreshStorageUsage();
    });

    // ── Diagnostics Center ────────────────────────────────────────────────────
    const DIAG_STATE = { lastReportText: '' };

    function diagFmtBytes(bytes) {
        const n = Number(bytes || 0);
        if (n < 1024) return n + ' B';
        if (n < 1048576) return (n / 1024).toFixed(1) + ' KB';
        return (n / 1048576).toFixed(2) + ' MB';
    }

    function diagCountStorage(storage) {
        try {
            let bytes = 0;
            for (let i = 0; i < storage.length; i += 1) {
                const key = storage.key(i);
                const value = storage.getItem(key) || '';
                bytes += new Blob([String(key || '') + String(value)]).size;
            }
            return { keys: storage.length, bytes };
        } catch (error) {
            return { keys: 0, bytes: 0, error: String(error?.message || error) };
        }
    }

    function diagActiveWebview() {
        const tab = getActiveTab?.();
        const wv = getTabWebview?.(tab?.id || STATE.activeTabId)
            || document.querySelector(`webview[data-tab-id="${STATE.activeTabId}"]`)
            || document.getElementById('browseFrame');
        let webviewUrl = '';
        try { webviewUrl = typeof wv?.getURL === 'function' ? wv.getURL() : ''; } catch (_) { webviewUrl = ''; }
        return {
            tab,
            webview: wv && wv.tagName === 'WEBVIEW' ? wv : null,
            url: webviewUrl || tab?.url || '',
            title: tab?.title || '',
            partition: wv?.getAttribute?.('partition') || '',
            useragent: wv?.getAttribute?.('useragent') || '',
            isLoading: typeof wv?.isLoading === 'function' ? !!wv.isLoading() : false,
        };
    }

    async function diagCollectCookies(url) {
        try {
            if (!url || !window.etherx?.cookies?.getAll) return { ok: false, count: 0, reason: 'Cookie API nije dostupan' };
            const res = await window.etherx.cookies.getAll(url);
            const list = Array.isArray(res) ? res : (Array.isArray(res?.cookies) ? res.cookies : []);
            const byPartition = list.reduce((acc, cookie) => {
                const key = String(cookie?.partition || 'unknown');
                acc[key] = (acc[key] || 0) + 1;
                return acc;
            }, {});
            return { ok: res?.ok !== false, count: list.length, byPartition, error: res?.error || '' };
        } catch (error) {
            return { ok: false, count: 0, error: String(error?.message || error) };
        }
    }

    async function diagCollectIndexedDb() {
        try {
            if (!indexedDB?.databases) return { ok: false, count: 0, reason: 'indexedDB.databases nije podržan u ovom shellu' };
            const dbs = await indexedDB.databases();
            return { ok: true, count: Array.isArray(dbs) ? dbs.length : 0, names: (dbs || []).map((db) => db.name).filter(Boolean).slice(0, 12) };
        } catch (error) {
            return { ok: false, count: 0, error: String(error?.message || error) };
        }
    }

    async function diagCollectLiveOs() {
        try {
            if (!window.etherx?.liveos?.getSnapshot) return { ok: false, reason: 'LiveOS bridge nije dostupan' };
            const snapshot = await window.etherx.liveos.getSnapshot();
            return {
                ok: !!snapshot,
                state: snapshot?.connection?.state || 'empty',
                events: Array.isArray(snapshot?.events) ? snapshot.events.length : 0,
                users: Array.isArray(snapshot?.userDatabase) ? snapshot.userDatabase.length : (Array.isArray(snapshot?.users) ? snapshot.users.length : 0),
                gifts: Array.isArray(snapshot?.giftLedger) ? snapshot.giftLedger.length : (Array.isArray(snapshot?.gifts) ? snapshot.gifts.length : 0),
                savedSessions: Array.isArray(snapshot?.savedSessions) ? snapshot.savedSessions.length : Number(snapshot?.archive?.savedSessionCount || 0),
                lastEventAt: snapshot?.connection?.lastEventAt || snapshot?.session?.startedAt || 0,
            };
        } catch (error) {
            return { ok: false, error: String(error?.message || error) };
        }
    }

    async function diagCollectPm2() {
        try {
            if (!window.etherx?.app?.getPM2Status) return { ok: false, reason: 'PM2 API nije dostupan' };
            const res = await window.etherx.app.getPM2Status();
            const output = String(res?.output || '').trim();
            return {
                ok: !!output && res?.ok !== false,
                hasOutput: !!output,
                online: /\bonline\b/i.test(output),
                errored: /\berrored\b|\bstopped\b/i.test(output),
                output: output.slice(0, 4000),
                error: res?.error || '',
            };
        } catch (error) {
            return { ok: false, error: String(error?.message || error) };
        }
    }

    async function collectEtherxDiagnostics() {
        const active = diagActiveWebview();
        const activeReport = {
            tabId: active.tab?.id || STATE.activeTabId || null,
            url: active.url || '',
            title: active.title || '',
            partition: active.partition || '',
            useragent: active.useragent || '',
            isLoading: active.isLoading,
        };
        const local = diagCountStorage(localStorage);
        const session = diagCountStorage(sessionStorage);
        const [cookies, idb, liveos, pm2] = await Promise.all([
            diagCollectCookies(active.url),
            diagCollectIndexedDb(),
            diagCollectLiveOs(),
            diagCollectPm2(),
        ]);
        let storageEstimate = null;
        try {
            storageEstimate = navigator.storage?.estimate ? await navigator.storage.estimate() : null;
        } catch (_) { storageEstimate = null; }

        let appVersion = document.getElementById('helpVersionNum')?.textContent || document.getElementById('helpVersionNum2')?.textContent || '';
        try {
            if (window.etherx?.app?.getVersion) appVersion = await window.etherx.app.getVersion();
        } catch (_) { }
        const tiktokAi = typeof window.getTikTokAiHealthSnapshot === 'function'
            ? window.getTikTokAiHealthSnapshot()
            : { ok: false, reason: 'TikTok AI health nije registriran' };
        const update = {
            version: String(appVersion || '').trim(),
            badge: document.getElementById('updateBadge')?.textContent || '',
            status: document.getElementById('updateStatus')?.textContent || document.getElementById('updateStatusText')?.textContent || '',
            packagedApi: !!window.etherx?.update?.check,
        };
        const loginHost = (() => {
            try { return new URL(active.url).hostname.toLowerCase(); } catch (_) { return ''; }
        })();
        return {
            generatedAt: new Date().toISOString(),
            app: {
                version: update.version,
                platform: navigator.platform,
                electronWebview: !!window.electronWebview,
                userAgent: navigator.userAgent,
            },
            active: activeReport,
            storage: {
                local,
                session,
                estimate: storageEstimate ? {
                    usage: storageEstimate.usage || 0,
                    quota: storageEstimate.quota || 0,
                    usageText: diagFmtBytes(storageEstimate.usage || 0),
                    quotaText: diagFmtBytes(storageEstimate.quota || 0),
                } : null,
                indexedDb: idb,
            },
            cookies,
            liveos,
            tiktokAi,
            pm2,
            update,
            login: {
                host: loginHost,
                isAuthSite: /(^|\.)accounts\.google\.com$|(^|\.)google\.com$|(^|\.)apple\.com$|(^|\.)microsoftonline\.com$|(^|\.)login\.live\.com$|(^|\.)tiktok\.com$/.test(loginHost),
                cookieCount: cookies.count || 0,
                partition: active.partition || '',
                webviewUserAgent: active.useragent || '',
            },
        };
    }

    function diagCard(label, value, detail, tone = 'info') {
        const colors = {
            ok: 'rgba(16,185,129,.16);border-color:rgba(16,185,129,.38)',
            warn: 'rgba(245,158,11,.16);border-color:rgba(245,158,11,.38)',
            bad: 'rgba(239,68,68,.16);border-color:rgba(239,68,68,.38)',
            info: 'rgba(59,130,246,.12);border-color:rgba(59,130,246,.28)',
        };
        return `<div style="background:${colors[tone] || colors.info};border:1px solid var(--border2);border-radius:7px;padding:9px 10px">
            <div style="font-size:10px;color:var(--text3);text-transform:uppercase;letter-spacing:.4px">${escHtml(label)}</div>
            <div style="font-size:17px;font-weight:700;color:var(--text);margin-top:2px">${escHtml(value)}</div>
            <div style="font-size:11px;color:var(--text3);margin-top:3px;line-height:1.35">${escHtml(detail || '')}</div>
        </div>`;
    }

    function renderEtherxDiagnostics(report) {
        const summaryEl = document.getElementById('diagSummary');
        const gridEl = document.getElementById('diagGrid');
        const reportEl = document.getElementById('diagReport');
        if (!summaryEl || !gridEl || !reportEl) return;

        const issues = [];
        if (report.cookies.count === 0 && report.login.isAuthSite) issues.push('Auth stranica nema cookies u persistent sessionu.');
        if (!report.active.partition && window.electronWebview) issues.push('Aktivni webview nema vidljiv partition atribut.');
        if (report.pm2.errored) issues.push('PM2 status sadrži stopped/errored.');
        if (report.liveos.ok && report.liveos.events === 0 && report.tiktokAi.messageCount > 0) issues.push('TikTok AI ima poruke, ali LiveOS snapshot nema evente.');
        if (!report.tiktokAi.ok) issues.push(report.tiktokAi.reason || report.tiktokAi.error || 'TikTok AI health nije dostupan.');

        const authHint = report.login.isAuthSite
            ? `Auth host: ${report.login.host || 'n/a'} | cookies: ${report.login.cookieCount} | partition: ${report.login.partition || 'n/a'}`
            : `Aktivni host: ${report.login.host || 'n/a'}`;
        summaryEl.textContent = [
            issues.length ? 'Status: treba pogledati ' + issues.length + ' stvar(i).' : 'Status: osnovne provjere su uredne.',
            authHint,
            'Active tab: ' + (report.active.title || report.active.url || 'n/a'),
            issues.length ? ('\nProblemi:\n- ' + issues.join('\n- ')) : '',
        ].filter(Boolean).join('\n');

        gridEl.innerHTML = [
            diagCard('Cookies', String(report.cookies.count || 0), Object.entries(report.cookies.byPartition || {}).map(([k, v]) => `${k}: ${v}`).join(' | ') || report.cookies.error || 'Nema cookies', report.cookies.count ? 'ok' : 'warn'),
            diagCard('Storage', diagFmtBytes(report.storage.local.bytes), `${report.storage.local.keys} local keys | ${report.storage.session.keys} session keys`, report.storage.local.keys ? 'ok' : 'warn'),
            diagCard('IndexedDB', String(report.storage.indexedDb.count || 0), (report.storage.indexedDb.names || []).join(', ') || report.storage.indexedDb.reason || report.storage.indexedDb.error || 'Nema baza', report.storage.indexedDb.count ? 'ok' : 'info'),
            diagCard('TikTok Chat AI', String(report.tiktokAi.messageCount || 0), `${report.tiktokAi.chatCount || 0} chat | ${report.tiktokAi.giftCount || 0} gift | scan ${report.tiktokAi.scanActive ? 'ON' : 'OFF'}`, report.tiktokAi.ok ? 'ok' : 'bad'),
            diagCard('LiveOS+', String(report.liveos.events || 0), `${report.liveos.users || 0} users | ${report.liveos.gifts || 0} gifts | ${report.liveos.savedSessions || 0} sessions`, report.liveos.ok ? (report.liveos.events ? 'ok' : 'warn') : 'bad'),
            diagCard('PM2', report.pm2.online ? 'online' : (report.pm2.hasOutput ? 'check' : 'n/a'), report.pm2.error || report.pm2.reason || 'Status dohvaćen', report.pm2.errored ? 'bad' : (report.pm2.online ? 'ok' : 'warn')),
            diagCard('Update', report.update.version || 'n/a', report.update.status || report.update.badge || 'Update API: ' + (report.update.packagedApi ? 'yes' : 'no'), report.update.packagedApi ? 'ok' : 'warn'),
            diagCard('Login', report.login.isAuthSite ? 'auth site' : 'normal', report.login.webviewUserAgent ? report.login.webviewUserAgent.slice(0, 72) : 'UA nije vidljiv', report.login.isAuthSite && !report.cookies.count ? 'warn' : 'info'),
        ].join('');

        DIAG_STATE.lastReportText = JSON.stringify(report, null, 2);
        reportEl.textContent = DIAG_STATE.lastReportText;
    }

    async function runEtherxDiagnostics() {
        const btn = document.getElementById('diagRunAllBtn');
        const summaryEl = document.getElementById('diagSummary');
        if (btn) {
            btn.disabled = true;
            btn.style.opacity = '.7';
            btn.textContent = '⏳ Provjeravam...';
        }
        if (summaryEl) summaryEl.textContent = 'Pokrećem provjere...';
        try {
            const report = await collectEtherxDiagnostics();
            renderEtherxDiagnostics(report);
            return report;
        } catch (error) {
            const msg = 'Diagnostics greška: ' + String(error?.message || error);
            if (summaryEl) summaryEl.textContent = msg;
            const reportEl = document.getElementById('diagReport');
            if (reportEl) reportEl.textContent = msg;
            showToast('⚠️ Diagnostics nije uspio');
            return null;
        } finally {
            if (btn) {
                btn.disabled = false;
                btn.style.opacity = '';
                btn.textContent = '▶ Pokreni provjere';
            }
        }
    }

    window.runEtherxDiagnostics = runEtherxDiagnostics;

    document.getElementById('diagRunAllBtn')?.addEventListener('click', () => runEtherxDiagnostics());
    document.getElementById('diagCopyBtn')?.addEventListener('click', async () => {
        const text = DIAG_STATE.lastReportText || document.getElementById('diagReport')?.textContent || '';
        if (!text || text.includes('Report još nije')) {
            await runEtherxDiagnostics();
        }
        const finalText = DIAG_STATE.lastReportText || document.getElementById('diagReport')?.textContent || '';
        try {
            await navigator.clipboard.writeText(finalText);
            showToast('📋 Diagnostics report kopiran');
        } catch (_) {
            showToast('⚠️ Clipboard nije dostupan');
        }
    });
    document.getElementById('diagOpenWebviewDevtoolsBtn')?.addEventListener('click', () => {
        if (typeof window.openActiveWebviewDevTools === 'function') window.openActiveWebviewDevTools();
    });
    document.getElementById('diagLoginModeBtn')?.addEventListener('click', () => {
        const active = diagActiveWebview();
        if (!active.webview || !active.url) {
            showToast('⚠️ Nema aktivnog webview taba za login compatibility');
            return;
        }
        try {
            applyUserAgentForURL(active.webview, active.url);
            if (typeof navigateWebviewToURL === 'function') navigateWebviewToURL(active.webview, active.url);
            else active.webview.reload?.();
            showToast('🔐 Login compatibility primijenjen na aktivni tab');
            setTimeout(runEtherxDiagnostics, 1200);
        } catch (error) {
            showToast('⚠️ Login compatibility greška: ' + String(error?.message || error));
        }
    });
    document.querySelectorAll('.sit-btn[data-stab="diagnostics"]').forEach((btn) => {
        btn.addEventListener('click', () => setTimeout(runEtherxDiagnostics, 80));
    });

    // ── Master Password Change ────────────────────────────────────────────────
    document.getElementById('sChangeMasterPwd')?.addEventListener('click', async () => {
        const oldPwd = await showPrompt('🔐 Enter your CURRENT master password:\n\n⚠️ Master password is NEVER saved. It\'s only used to encrypt/decrypt your data.', '', { password: true });
        if (!oldPwd) return;

        // Verify current password by trying to decrypt something
        const s = DB.getSettings();
        const testData = s.test_pwd_verify;
        if (testData) {
            try {
                // If there's encrypted data, verify old password works
                const decrypted = decryptAES(testData, oldPwd);
                if (!decrypted || decrypted !== 'verified') {
                    showToast('❌ Incorrect current password');
                    return;
                }
            } catch (e) {
                showToast('❌ Incorrect current password');
                return;
            }
        }

        const newPwd = await showPrompt('🔐 Enter your NEW master password:\n\n⚠️ You will need this password to unlock your data. DO NOT FORGET IT!', '', { password: true });
        if (!newPwd || newPwd.length < 4) { showToast('⚠️ New password must be at least 4 characters'); return; }

        const confirmPwd = await showPrompt('🔐 Confirm NEW master password:', '', { password: true });
        if (confirmPwd !== newPwd) { showToast('❌ Passwords do not match'); return; }

        // Store encrypted verification token
        const encrypted = encryptAES('verified', newPwd);
        DB.saveSetting('test_pwd_verify', encrypted);

        showToast('✅ Master password changed successfully!\n\n⚠️ Remember: Master password is NEVER saved anywhere. Keep it safe!');
    });    // ── Download Links Management ─────────────────────────────────────────────




